def _normalize_doc_route_bindings(raw: Any) -> list[str]:
    values: list[str] = []
    if not isinstance(raw, list):
        return values
    seen: set[str] = set()
    for entry in raw:
        route_id = str(entry or "").strip()
        if not route_id:
            continue
        if route_id in seen:
            continue
        seen.add(route_id)
        values.append(route_id)
    return values


def _normalize_doc_tags(raw: Any) -> list[str]:
    values: list[str] = []
    if not isinstance(raw, list):
        return values
    seen: set[str] = set()
    for entry in raw:
        tag = str(entry or "").strip().lower()
        if not tag:
            continue
        if tag in seen:
            continue
        seen.add(tag)
        values.append(tag)
    return values


def _normalize_role_slugs(raw: Any) -> list[str]:
    values: list[str] = []
    if not isinstance(raw, list):
        return values
    seen: set[str] = set()
    for entry in raw:
        role = str(entry or "").strip().lower()
        if not role:
            continue
        if role in seen:
            continue
        seen.add(role)
        values.append(role)
    return values


def _normalize_article_category(raw: Any, *, fallback: str = "web") -> str:
    value = str(raw or "").strip().lower()
    if value in ARTICLE_CATEGORIES or ARTICLE_CATEGORY_SLUG_PATTERN.match(value):
        return value
    return fallback


