@csrf_exempt
@require_any_role("platform_owner", "platform_admin")
def seed_apply(request: HttpRequest) -> JsonResponse:
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    try:
        payload = json.loads(request.body.decode("utf-8")) if request.body else {}
    except json.JSONDecodeError:
        return JsonResponse({"error": "invalid json body"}, status=400)
    raw_slugs = payload.get("pack_slugs")
    pack_slugs = [str(value).strip() for value in raw_slugs] if isinstance(raw_slugs, list) else None
    apply_core = bool(payload.get("apply_core"))
    dry_run = bool(payload.get("dry_run"))
    identity = getattr(request, "user_identity", None)
    result = apply_seed_packs(
        pack_slugs=pack_slugs or None,
        apply_core=apply_core,
        dry_run=dry_run,
        applied_by=identity,
    )
    return JsonResponse(result)


def auth_mode(request: HttpRequest) -> JsonResponse:
    return JsonResponse(
        {
            "auth_mode": _auth_mode(),
            "public_base_url": str(os.environ.get("XYN_PUBLIC_BASE_URL", "")).strip() or _effective_public_base_url(request),
            "oidc_enabled": _auth_mode() == "oidc",
            "token_enabled": _auth_mode() == "token",
            "dev_enabled": _auth_mode() == "dev",
        }
    )


def _platform_initialization_state(identity: UserIdentity) -> Dict[str, Any]:
    workspace_count = _user_visible_workspace_qs().count()
    initialized = workspace_count > 0
    requires_setup = bool(_auth_mode() != "dev" and _is_platform_admin(identity) and not initialized)
    return {
        "initialized": bool(initialized),
        "requires_setup": bool(requires_setup),
        "workspace_count": int(workspace_count),
        "auth_mode": _auth_mode(),
    }


def _is_system_workspace(workspace: Workspace) -> bool:
    slug = str(getattr(workspace, "slug", "") or "").strip().lower()
    if slug in {"platform-builder", "civic-lab"}:
        return True
    metadata = getattr(workspace, "metadata_json", None)
    if isinstance(metadata, dict) and metadata.get("xyn_system_workspace") is True:
        return True
    return False


def _user_visible_workspace_qs():
    return Workspace.objects.exclude(slug__in=["platform-builder", "civic-lab"])


def _workspace_is_visible(workspace: Workspace, *, include_system: bool = False) -> bool:
    if include_system:
        return True
    return not _is_system_workspace(workspace)


DEFAULT_WORKSPACE_RUNTIME_ARTIFACTS: tuple[tuple[str, str, str, str], ...] = (
    (
        "core.workbench",
        "Workbench",
        "registry/modules/workbench.artifact.manifest.json",
        "Console-first, panel-based runtime landing experience.",
    ),
    (
        "xyn-api",
        "xyn-api",
        "registry/modules/xyn-api.artifact.manifest.json",
        "Deployable Xyn API runtime artifact.",
    ),
    (
        "xyn-ui",
        "xyn-ui",
        "registry/modules/xyn-ui.artifact.manifest.json",
        "Deployable Xyn UI runtime artifact.",
    ),
)

DEFAULT_XYN_SOLUTION_NAME = "Xyn"
DEFAULT_XYN_SOLUTION_KEY = "xyn-platform-default"
DEFAULT_XYN_SOLUTION_ARTIFACT_ROLES: tuple[tuple[str, str, str, int], ...] = (
    ("core.workbench", "primary_ui", "Default shell/workbench surface.", 10),
    ("xyn-ui", "runtime_service", "Default UI runtime artifact.", 20),
    ("xyn-api", "runtime_service", "Default API runtime artifact.", 30),
)

DEFAULT_RUNTIME_ARTIFACT_OWNERSHIP: Dict[str, Dict[str, Any]] = {
    "core.workbench": {
        "repo_slug": "xyn-platform",
        "allowed_paths": [],
        "edit_mode": "repo_backed",
    },
    "xyn-ui": {
        "repo_slug": "xyn-platform",
        "allowed_paths": ["apps/xyn-ui/"],
        "edit_mode": "repo_backed",
    },
    "xyn-api": {
        "repo_slug": "xyn-platform",
        "allowed_paths": ["services/xyn-api/backend/"],
        "edit_mode": "repo_backed",
    },
    "core.xyn-runtime": {
        "repo_slug": "xyn",
        "allowed_paths": [],
        "edit_mode": "repo_backed",
    },
}


def _runtime_artifact_ownership_for_slug(slug: str) -> Dict[str, Any]:
    token = str(slug or "").strip().lower()
    ownership = DEFAULT_RUNTIME_ARTIFACT_OWNERSHIP.get(token)
    if ownership:
        return {
            "repo_slug": str(ownership.get("repo_slug") or "").strip(),
            "allowed_paths": [str(item).strip() for item in (ownership.get("allowed_paths") or []) if str(item).strip()],
            "edit_mode": str(ownership.get("edit_mode") or "generated").strip().lower() or "generated",
        }
    if token.startswith("core.xyn-"):
        return {"repo_slug": "xyn", "allowed_paths": [], "edit_mode": "repo_backed"}
    return {"repo_slug": "", "allowed_paths": [], "edit_mode": "generated"}


def resolve_artifact_ownership(artifact: Artifact) -> Dict[str, Any]:
    allowed_paths = (
        artifact.owner_path_prefixes_json
        if isinstance(getattr(artifact, "owner_path_prefixes_json", None), list)
        else []
    )
    normalized_paths = [str(item).strip() for item in allowed_paths if str(item).strip()]
    edit_mode = str(getattr(artifact, "edit_mode", "") or "").strip().lower() or "generated"
    if edit_mode not in {"repo_backed", "generated", "read_only"}:
        edit_mode = "generated"
    return {
        "repo_slug": str(getattr(artifact, "owner_repo_slug", "") or "").strip() or None,
        "allowed_paths": normalized_paths,
        "edit_mode": edit_mode,
    }


def _bootstrap_runtime_db_ready() -> bool:
    readiness = schema_bootstrap_readiness(required_tables=DEFAULT_BOOTSTRAP_REQUIRED_TABLES)
    if not readiness.ready:
        logger.info("Runtime bootstrap readiness check deferred: %s", readiness.reason)
    return readiness.ready


def _run_runtime_bootstrap(*, reason: str) -> None:
    if str(os.environ.get("XYENCE_BOOTSTRAP_DISABLE") or "").strip() == "1":
        return
    if not _bootstrap_runtime_db_ready():
        logger.info("Skipping runtime bootstrap (%s): DB/schema not ready.", reason)
        return
    try:
        ensure_default_ai_seeds()
    except Exception as exc:
        logger.warning("Runtime bootstrap (%s) AI seed step failed: %s", reason, exc)
    try:
        bootstrap_instance_registration()
    except Exception as exc:
        logger.warning("Runtime bootstrap (%s) instance registration step failed: %s", reason, exc)
    try:
        auto_apply_core_seed_packs()
    except Exception as exc:
        logger.warning("Runtime bootstrap (%s) core seed-pack step failed: %s", reason, exc)


def _default_dev_workspace_slug() -> str:
    raw = str(os.getenv("XYN_WORKSPACE_SLUG", "development") or "").strip().lower()
    slug = slugify(raw)
    return slug or "development"


def _workspace_title_from_slug(slug: str) -> str:
    value = str(slug or "").strip().replace("-", " ")
    return value.title() if value else "Development"


def _default_xyn_solution_workspace_slug() -> str:
    configured = slugify(str(os.getenv("XYN_DEFAULT_XYN_SOLUTION_WORKSPACE_SLUG", "") or "").strip().lower())
    if configured:
        return configured
    if _auth_mode() == "dev":
        return _default_dev_workspace_slug()
    return ""


def _workspace_matches_default_xyn_solution_target(workspace: Workspace) -> bool:
    target_slug = _default_xyn_solution_workspace_slug()
    if not target_slug:
        return False
    return str(getattr(workspace, "slug", "") or "").strip().lower() == target_slug


def _ensure_default_xyn_solution_for_workspace(*, workspace: Workspace) -> Optional[Application]:
    if workspace is None or not _workspace_is_visible(workspace, include_system=False):
        return None
    if not _workspace_matches_default_xyn_solution_target(workspace):
        return None
    with transaction.atomic():
        locked_workspace = Workspace.objects.select_for_update().get(id=workspace.id)
        application = (
            Application.objects.filter(workspace=locked_workspace, metadata_json__system_solution_key=DEFAULT_XYN_SOLUTION_KEY)
            .order_by("-updated_at", "-created_at")
            .first()
        )
        if application is None:
            application = (
                Application.objects.filter(workspace=locked_workspace, source_factory_key="xyn_platform_default")
                .order_by("-updated_at", "-created_at")
                .first()
            )
        if application is None:
            application = Application.objects.create(
                workspace=locked_workspace,
                name=DEFAULT_XYN_SOLUTION_NAME,
                summary="Default Xyn platform solution workspace.",
                source_factory_key="xyn_platform_default",
                source_conversation_id="",
                status="active",
                request_objective="",
                metadata_json={"system_solution_key": DEFAULT_XYN_SOLUTION_KEY, "origin": "bootstrap_default"},
            )
        else:
            metadata = application.metadata_json if isinstance(application.metadata_json, dict) else {}
            metadata_changed = False
            if metadata.get("system_solution_key") != DEFAULT_XYN_SOLUTION_KEY:
                metadata = dict(metadata)
                metadata["system_solution_key"] = DEFAULT_XYN_SOLUTION_KEY
                metadata_changed = True
            if metadata.get("origin") != "bootstrap_default":
                metadata = dict(metadata)
                metadata["origin"] = "bootstrap_default"
                metadata_changed = True
            update_fields: List[str] = []
            if application.source_factory_key != "xyn_platform_default":
                application.source_factory_key = "xyn_platform_default"
                update_fields.append("source_factory_key")
            if application.name != DEFAULT_XYN_SOLUTION_NAME:
                application.name = DEFAULT_XYN_SOLUTION_NAME
                update_fields.append("name")
            if metadata_changed:
                application.metadata_json = metadata
                update_fields.append("metadata_json")
            if update_fields:
                update_fields.append("updated_at")
                application.save(update_fields=update_fields)

    runtime_artifacts_by_slug: Dict[str, tuple[str, str, str]] = {
        slug: (title, manifest_ref, summary)
        for slug, title, manifest_ref, summary in DEFAULT_WORKSPACE_RUNTIME_ARTIFACTS
    }

    def _materialize_solution_artifact(slug: str) -> Optional[Artifact]:
        token = str(slug or "").strip().lower()
        if not token:
            return None
        local = (
            Artifact.objects.filter(workspace=workspace, slug=token)
            .select_related("type")
            .order_by("-updated_at", "-created_at")
            .first()
        )
        if local is not None:
            return local
        runtime_entry = runtime_artifacts_by_slug.get(token)
        if runtime_entry is not None:
            title, manifest_ref, summary = runtime_entry
            return _ensure_runtime_artifact(
                workspace=workspace,
                slug=token,
                title=title,
                manifest_ref=manifest_ref,
                summary=summary,
            )
        source = (
            Artifact.objects.filter(slug=token)
            .exclude(workspace=workspace)
            .select_related("type")
            .order_by("-updated_at", "-created_at")
            .first()
        )
        if source is None:
            return None
        return Artifact.objects.create(
            workspace=workspace,
            type=source.type,
            title=source.title,
            slug=source.slug,
            status=source.status,
            visibility=source.visibility,
            summary=source.summary,
            scope_json=dict(source.scope_json or {}),
            owner_repo_slug=str(source.owner_repo_slug or "").strip(),
            owner_path_prefixes_json=list(source.owner_path_prefixes_json or []),
            edit_mode=str(source.edit_mode or "generated").strip().lower() or "generated",
            provenance_json={
                **(source.provenance_json if isinstance(source.provenance_json, dict) else {}),
                "materialized_for_workspace": str(workspace.id),
                "materialized_from_artifact_id": str(source.id),
                "materialized_from_workspace_id": str(source.workspace_id),
                "materialized_by": "default_xyn_solution_bootstrap",
            },
        )

    artifact_by_slug: Dict[str, Artifact] = {}
    bindings = (
        WorkspaceArtifactBinding.objects.filter(
            workspace=workspace,
            artifact__slug__in=[slug for slug, _role, _summary, _order in DEFAULT_XYN_SOLUTION_ARTIFACT_ROLES],
        )
        .select_related("artifact", "artifact__type")
        .order_by("artifact__slug", "-updated_at", "-created_at")
    )
    for binding in bindings:
        slug = str(getattr(binding.artifact, "slug", "") or "").strip().lower()
        if slug and slug not in artifact_by_slug:
            artifact_by_slug[slug] = _materialize_solution_artifact(slug) or binding.artifact

    for slug, role, responsibility_summary, sort_order in DEFAULT_XYN_SOLUTION_ARTIFACT_ROLES:
        artifact = artifact_by_slug.get(slug) or _materialize_solution_artifact(slug)
        if artifact is None:
            continue
        ApplicationArtifactMembership.objects.update_or_create(
            application=application,
            artifact=artifact,
            defaults={
                "workspace": workspace,
                "role": role,
                "responsibility_summary": responsibility_summary,
                "metadata_json": {"origin": "bootstrap_default_xyn_solution"},
                "sort_order": sort_order,
            },
        )
    solution_count = Application.objects.filter(workspace=workspace, metadata_json__system_solution_key=DEFAULT_XYN_SOLUTION_KEY).count()
    if solution_count != 1:
        logger.warning(
            "Default Xyn solution bootstrap expected exactly one system solution for workspace=%s but found=%s",
            workspace.slug,
            solution_count,
        )
    return application


def _ensure_default_xyn_solution() -> Optional[Application]:
    target_slug = _default_xyn_solution_workspace_slug()
    if not target_slug:
        return None
    workspace = Workspace.objects.filter(slug=target_slug).first()
    if workspace is None:
        return None
    return _ensure_default_xyn_solution_for_workspace(workspace=workspace)


def _runtime_artifact_host_workspace(fallback_workspace: Workspace) -> Workspace:
    host_workspace = Workspace.objects.filter(slug="platform-builder").first()
    if host_workspace is not None:
        return host_workspace
    return fallback_workspace


def _ensure_default_workspace_artifact_bindings(workspace: Workspace) -> None:
    host_workspace = _runtime_artifact_host_workspace(workspace)
    for slug, title, manifest_ref, summary in DEFAULT_WORKSPACE_RUNTIME_ARTIFACTS:
        artifact = _ensure_runtime_artifact(
            workspace=host_workspace,
            slug=slug,
            title=title,
            manifest_ref=manifest_ref,
            summary=summary,
        )
        binding, _ = WorkspaceArtifactBinding.objects.get_or_create(
            workspace=workspace,
            artifact=artifact,
            defaults={"enabled": True, "installed_state": "installed", "config_ref": None},
        )
        update_fields: List[str] = []
        if not binding.enabled:
            binding.enabled = True
            update_fields.append("enabled")
        if str(binding.installed_state or "").strip().lower() != "installed":
            binding.installed_state = "installed"
            update_fields.append("installed_state")
        if update_fields:
            update_fields.append("updated_at")
            binding.save(update_fields=update_fields)
    _ensure_default_xyn_solution_for_workspace(workspace=workspace)


def _ensure_dev_bootstrap_workspace(identity: UserIdentity) -> Optional[Workspace]:
    if _auth_mode() != "dev":
        return None
    if not _is_platform_admin(identity):
        return None
    workspace_slug = _default_dev_workspace_slug()
    with transaction.atomic():
        workspace, _ = Workspace.objects.get_or_create(
            slug=workspace_slug,
            defaults={
                "name": _workspace_title_from_slug(workspace_slug),
                "org_name": _workspace_title_from_slug(workspace_slug),
                "description": f"Default {workspace_slug} workspace for local bootstrap.",
                "status": "active",
                "kind": "internal",
                "lifecycle_stage": "internal",
                "auth_mode": "local",
                "metadata_json": {"bootstrap": "dev_default"},
            },
        )
        workspace = Workspace.objects.select_for_update().get(id=workspace.id)
        metadata = workspace.metadata_json if isinstance(workspace.metadata_json, dict) else {}
        if metadata.get("xyn_system_workspace") is True:
            metadata = dict(metadata)
            metadata.pop("xyn_system_workspace", None)
            workspace.metadata_json = metadata
            workspace.save(update_fields=["metadata_json", "updated_at"])
        WorkspaceMembership.objects.update_or_create(
            workspace=workspace,
            user_identity=identity,
            defaults={"role": "admin", "termination_authority": True},
        )
        _ensure_default_workspace_artifact_bindings(workspace)
        _ensure_default_xyn_solution_for_workspace(workspace=workspace)
    workspace_rows = Workspace.objects.filter(slug=workspace_slug).count()
    if workspace_rows != 1:
        logger.warning("Dev bootstrap expected exactly one workspace for slug=%s but found=%s", workspace_slug, workspace_rows)
    return workspace


@csrf_exempt
def platform_initialization_status(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    return JsonResponse({"platform_initialization": _platform_initialization_state(identity)})


@csrf_exempt
def platform_initialization_complete(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if not _is_platform_admin(identity):
        return JsonResponse({"error": "forbidden"}, status=403)
    if _auth_mode() == "dev":
        return JsonResponse({"error": "platform initialization wizard is not used in dev mode"}, status=409)
    if _user_visible_workspace_qs().exists():
        return JsonResponse(
            {"error": "platform already initialized", "platform_initialization": _platform_initialization_state(identity)},
            status=409,
        )

    payload = _parse_json(request)
    requested_name = str(payload.get("workspace_name") or payload.get("company_name") or "").strip()
    workspace_name = requested_name or "Company"
    requested_slug = str(payload.get("workspace_slug") or "").strip().lower()
    slug_base = requested_slug or slugify(workspace_name) or "company"
    slug_value = slug_base
    suffix = 2
    while Workspace.objects.filter(slug=slug_value).exists():
        slug_value = f"{slug_base}-{suffix}"
        suffix += 1

    with transaction.atomic():
        workspace = Workspace.objects.create(
            slug=slug_value,
            name=workspace_name,
            org_name=str(payload.get("org_name") or workspace_name).strip() or workspace_name,
            description=str(payload.get("description") or "").strip(),
            status="active",
            kind="customer",
            lifecycle_stage="customer",
            auth_mode="oidc" if _auth_mode() == "oidc" else "local",
            metadata_json={"bootstrap": "initial_setup"},
        )
        WorkspaceMembership.objects.update_or_create(
            workspace=workspace,
            user_identity=identity,
            defaults={"role": "admin", "termination_authority": True},
        )
        latest_doc = PlatformConfigDocument.objects.order_by("-version").first()
        next_version = int(getattr(latest_doc, "version", 0) or 0) + 1
        PlatformConfigDocument.objects.create(
            version=next_version,
            config_json={
                "initialized": True,
                "initialized_at": timezone.now().isoformat(),
                "initial_workspace_id": str(workspace.id),
                "initial_workspace_slug": workspace.slug,
            },
            created_by=getattr(request, "user", None),
        )

    return JsonResponse(
        {
            "workspace": _serialize_workspace_summary(workspace, role="admin", termination_authority=True),
            "platform_initialization": _platform_initialization_state(identity),
        }
    )


def api_me(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    include_system = str(request.GET.get("include_system") or "").strip().lower() in {"1", "true", "yes"}
    _run_runtime_bootstrap(reason="api_me")
    roles = _get_roles(identity)
    bootstrap_workspace = _ensure_dev_bootstrap_workspace(identity)
    _ensure_default_xyn_solution()
    if _is_platform_admin(identity):
        rows = Workspace.objects.all().order_by("name")
        if not include_system:
            rows = [row for row in rows if _workspace_is_visible(row, include_system=False)]
        workspace_payload = [
            _serialize_workspace_summary(
                row,
                role="admin",
                termination_authority=True,
            )
            for row in rows
        ]
    else:
        memberships = WorkspaceMembership.objects.filter(user_identity=identity).select_related("workspace").order_by("workspace__name")
        workspace_payload = [
            _serialize_workspace_summary(
                membership.workspace,
                role=membership.role,
                termination_authority=bool(membership.termination_authority),
            )
            for membership in memberships
            if _workspace_is_visible(membership.workspace, include_system=include_system)
        ]

    preferred_workspace_id = ""
    if bootstrap_workspace is not None:
        preferred_workspace_id = str(bootstrap_workspace.id)
    elif workspace_payload:
        default_slug = _default_dev_workspace_slug()
        dev_entry = next((entry for entry in workspace_payload if str(entry.get("slug") or "").strip().lower() == default_slug), None)
        preferred_workspace_id = str((dev_entry or workspace_payload[0]).get("id") or "")

    return JsonResponse(
        {
            "user": {
                "issuer": identity.issuer,
                "subject": identity.subject,
                "email": identity.email,
                "display_name": identity.display_name,
            },
            "roles": roles,
            "actor_roles": list(getattr(request, "actor_roles", []) or roles),
            "preview": _serialize_preview_status(identity, request),
            "auth_mode": _auth_mode(),
            "workspaces": workspace_payload,
            "preferred_workspace_id": preferred_workspace_id,
            "platform_initialization": _platform_initialization_state(identity),
        }
    )


@csrf_exempt
@login_required
def notifications_collection(request: HttpRequest) -> JsonResponse:
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    limit_raw = request.GET.get("limit")
    offset_raw = request.GET.get("offset")
    unread_only = _parse_bool_param(request.GET.get("unread_only"), default=False)
    source_app_key = str(request.GET.get("source_app_key") or "").strip()
    category = str(request.GET.get("category") or "").strip()
    try:
        limit = int(limit_raw) if limit_raw is not None else 50
    except (TypeError, ValueError):
        return JsonResponse({"error": "invalid limit"}, status=400)
    try:
        offset = int(offset_raw) if offset_raw is not None else 0
    except (TypeError, ValueError):
        return JsonResponse({"error": "invalid offset"}, status=400)
    payload = list_notifications_for_recipient(
        recipient=identity,
        limit=limit,
        offset=offset,
        unread_only=unread_only,
        source_app_key=source_app_key,
        category=category,
    )
    payload["unread_count"] = get_unread_count_for_recipient(recipient=identity)
    return JsonResponse(payload)


@csrf_exempt
@login_required
def notifications_unread_count(request: HttpRequest) -> JsonResponse:
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    return JsonResponse({"unread_count": get_unread_count_for_recipient(recipient=identity)})


@csrf_exempt
@login_required
def notification_mark_read(request: HttpRequest, notification_id: str) -> JsonResponse:
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    changed = mark_notification_as_read(
        recipient=identity,
        notification_id=str(notification_id),
    )
    if not changed:
        return JsonResponse({"error": "notification not found"}, status=404)
    return JsonResponse(
        {
            "notification_id": str(notification_id),
            "unread": False,
            "unread_count": get_unread_count_for_recipient(recipient=identity),
        }
    )


@csrf_exempt
@login_required
def notifications_mark_all_read(request: HttpRequest) -> JsonResponse:
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    updated = mark_all_notifications_as_read(recipient=identity)
    return JsonResponse(
        {
            "updated": int(updated),
            "unread_count": get_unread_count_for_recipient(recipient=identity),
        }
    )


def _coerce_bool(value: Any, *, field: str) -> bool:
    if isinstance(value, bool):
        return value
    token = str(value or "").strip().lower()
    if token in {"true", "1", "yes"}:
        return True
    if token in {"false", "0", "no"}:
        return False
    raise ValueError(f"{field} must be a boolean")


@csrf_exempt
@login_required
def notification_targets_collection(request: HttpRequest) -> JsonResponse:
    def _resolve_workspace_for_notifications(payload_workspace_id: str) -> Optional[Workspace]:
        workspace_id = str(payload_workspace_id or "").strip()
        if not workspace_id:
            return None
        return _resolve_workspace_for_identity(identity, workspace_id)

    if request.method == "GET":
        identity = _require_authenticated(request)
        if not identity:
            return JsonResponse({"error": "not authenticated"}, status=401)
        workspace_id = str(request.GET.get("workspace_id") or "").strip()
        if not workspace_id:
            return JsonResponse({"error": "workspace_id is required"}, status=400)
        workspace = _resolve_workspace_for_notifications(workspace_id)
        if workspace is None:
            return JsonResponse({"error": "forbidden"}, status=403)
        if not _require_workspace_capabilities(identity, str(workspace.id), [CAP_NOTIFICATION_TARGETS_MANAGE]):
            return JsonResponse({"error": "forbidden"}, status=403)
        return JsonResponse({"targets": list_delivery_targets(owner=identity)})
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    payload = _parse_json(request)
    workspace_id = str(payload.get("workspace_id") or "").strip()
    if not workspace_id:
        return JsonResponse({"error": "workspace_id is required"}, status=400)
    workspace = _resolve_workspace_for_notifications(workspace_id)
    if workspace is None:
        return JsonResponse({"error": "forbidden"}, status=403)
    if not _require_workspace_capabilities(identity, str(workspace.id), [CAP_NOTIFICATION_TARGETS_MANAGE]):
        return JsonResponse({"error": "forbidden"}, status=403)
    address = str(payload.get("address") or "").strip().lower()
    if not address:
        return JsonResponse({"error": "address is required"}, status=400)
    try:
        validate_email(address)
    except ValidationError:
        return JsonResponse({"error": "invalid email address"}, status=400)
    try:
        enabled = _coerce_bool(payload.get("enabled", True), field="enabled")
        is_primary = _coerce_bool(payload.get("is_primary", False), field="is_primary")
    except ValueError as exc:
        return JsonResponse({"error": str(exc)}, status=400)
    try:
        row = create_delivery_target(
            owner=identity,
            address=address,
            channel="email",
            enabled=enabled,
            is_primary=is_primary,
        )
    except ValueError as exc:
        return JsonResponse({"error": str(exc)}, status=400)
    targets = list_delivery_targets(owner=identity)
    target_payload = next((item for item in targets if str(item.get("id") or "") == str(row.id)), None)
    return JsonResponse({"target": target_payload}, status=201)


@csrf_exempt
@login_required
def notification_target_detail(request: HttpRequest, target_id: str) -> JsonResponse:
    if request.method == "PATCH":
        identity = _require_authenticated(request)
        if not identity:
            return JsonResponse({"error": "not authenticated"}, status=401)
        payload = _parse_json(request)
        workspace_id = str(payload.get("workspace_id") or "").strip()
        if not workspace_id:
            return JsonResponse({"error": "workspace_id is required"}, status=400)
        workspace = _resolve_workspace_for_identity(identity, workspace_id)
        if workspace is None:
            return JsonResponse({"error": "forbidden"}, status=403)
        if not _require_workspace_capabilities(identity, str(workspace.id), [CAP_NOTIFICATION_TARGETS_MANAGE]):
            return JsonResponse({"error": "forbidden"}, status=403)
        if "enabled" not in payload:
            return JsonResponse({"error": "enabled is required"}, status=400)
        try:
            enabled = _coerce_bool(payload.get("enabled"), field="enabled")
        except ValueError as exc:
            return JsonResponse({"error": str(exc)}, status=400)
        row = set_delivery_target_enabled(
            owner=identity,
            target_id=str(target_id),
            enabled=enabled,
        )
        if row is None:
            return JsonResponse({"error": "delivery target not found"}, status=404)
        targets = list_delivery_targets(owner=identity)
        target_payload = next((item for item in targets if str(item.get("id") or "") == str(row.id)), None)
        return JsonResponse({"target": target_payload})
    if request.method == "DELETE":
        identity = _require_authenticated(request)
        if not identity:
            return JsonResponse({"error": "not authenticated"}, status=401)
        workspace_id = str(request.GET.get("workspace_id") or "").strip()
        if not workspace_id:
            return JsonResponse({"error": "workspace_id is required"}, status=400)
        workspace = _resolve_workspace_for_identity(identity, workspace_id)
        if workspace is None:
            return JsonResponse({"error": "forbidden"}, status=403)
        if not _require_workspace_capabilities(identity, str(workspace.id), [CAP_NOTIFICATION_TARGETS_MANAGE]):
            return JsonResponse({"error": "forbidden"}, status=403)
        removed = remove_delivery_target(owner=identity, target_id=str(target_id))
        if not removed:
            return JsonResponse({"error": "delivery target not found"}, status=404)
        return JsonResponse({"status": "deleted"})
    return JsonResponse({"error": "method not allowed"}, status=405)


@csrf_exempt
@login_required
def notification_preferences_detail(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method == "GET":
        workspace_id = str(request.GET.get("workspace_id") or "").strip()
        if not workspace_id:
            return JsonResponse({"error": "workspace_id is required"}, status=400)
        workspace = _resolve_workspace_for_identity(identity, workspace_id)
        if workspace is None:
            return JsonResponse({"error": "forbidden"}, status=403)
        if not _require_workspace_capabilities(identity, str(workspace.id), [CAP_NOTIFICATIONS_READ]):
            return JsonResponse({"error": "forbidden"}, status=403)
        source_app_key = str(request.GET.get("source_app_key") or "").strip()
        return JsonResponse(
            {"preference": get_delivery_preference(owner=identity, source_app_key=source_app_key, workspace=workspace)}
        )
    if request.method not in {"PUT", "POST"}:
        return JsonResponse({"error": "method not allowed"}, status=405)
    payload = _parse_json(request)
    workspace_id = str(payload.get("workspace_id") or "").strip()
    if not workspace_id:
        return JsonResponse({"error": "workspace_id is required"}, status=400)
    workspace = _resolve_workspace_for_identity(identity, workspace_id)
    if workspace is None:
        return JsonResponse({"error": "forbidden"}, status=403)
    if not _require_workspace_capabilities(identity, str(workspace.id), [CAP_NOTIFICATION_TARGETS_MANAGE]):
        return JsonResponse({"error": "forbidden"}, status=403)
    source_app_key = str(payload.get("source_app_key") or "").strip()
    if "in_app_enabled" not in payload or "email_enabled" not in payload:
        return JsonResponse({"error": "in_app_enabled and email_enabled are required"}, status=400)
    try:
        in_app_enabled = _coerce_bool(payload.get("in_app_enabled"), field="in_app_enabled")
        email_enabled = _coerce_bool(payload.get("email_enabled"), field="email_enabled")
    except ValueError as exc:
        return JsonResponse({"error": str(exc)}, status=400)
    set_delivery_preference(
        owner=identity,
        source_app_key=source_app_key,
        in_app_enabled=in_app_enabled,
        email_enabled=email_enabled,
        workspace=workspace,
    )
    return JsonResponse({"preference": get_delivery_preference(owner=identity, source_app_key=source_app_key, workspace=workspace)})


