@csrf_exempt
@login_required
def artifacts_import_collection(request: HttpRequest) -> JsonResponse:
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if staff_error := _require_staff(request):
        return staff_error
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if not request.FILES or "file" not in request.FILES:
        return JsonResponse({"error": "file upload required (multipart field: file)"}, status=400)
    upload = request.FILES["file"]
    try:
        package, created = import_package_blob_idempotent(
            blob=upload.read(),
            created_by=request.user if request.user.is_authenticated else None,
        )
    except ArtifactPackageValidationError as exc:
        return JsonResponse({"error": "invalid package", "details": exc.errors}, status=400)

    manifest = package.manifest if isinstance(package.manifest, dict) else {}
    artifacts = manifest.get("artifacts") if isinstance(manifest.get("artifacts"), list) else []
    invalid = []
    for item in artifacts:
        if not isinstance(item, dict):
            continue
        artifact_type = str(item.get("type") or "").strip()
        slug = str(item.get("slug") or "").strip()
        allowed = (
            artifact_type == "application" and slug.startswith("app.")
        ) or (
            artifact_type == "policy_bundle" and slug.startswith("policy.")
        )
        if allowed:
            continue
        invalid.append(f"{artifact_type}:{slug}@{item.get('version')}")
    if invalid:
        return JsonResponse(
            {
                "error": "generated artifact import only accepts application app.* and policy_bundle policy.* slugs",
                "details": invalid,
            },
            status=400,
        )

    workspace = _resolve_solution_import_workspace(identity, request)
    if workspace is None:
        return JsonResponse(
            {"error": "workspace context is required for generated artifact import"},
            status=400,
        )

    receipt = install_package(
        package,
        binding_overrides={},
        installed_by=request.user if request.user.is_authenticated else None,
        target_workspace=workspace,
    )
    status = 200 if receipt.status == "success" else 400
    artifact_ids_from_receipt = [
        str(change.get("artifact_id") or "").strip()
        for change in (receipt.artifact_changes if isinstance(receipt.artifact_changes, list) else [])
        if isinstance(change, dict) and str(change.get("artifact_id") or "").strip()
    ]
    receipt_artifacts = list(
        Artifact.objects.filter(id__in=artifact_ids_from_receipt).select_related("type")
    ) if artifact_ids_from_receipt else []
    artifact_by_id = {str(item.id): item for item in receipt_artifacts}
    imported_rows: List[Dict[str, Any]] = []
    for artifact_id in artifact_ids_from_receipt:
        artifact = artifact_by_id.get(artifact_id)
        if artifact is None:
            continue
        imported_rows.append(
            {
                "id": str(artifact.id),
                "slug": _artifact_slug(artifact),
                "type": artifact.type.slug if artifact.type_id else "",
                "package_version": str(artifact.package_version or ""),
                "title": artifact.title,
            }
        )
    if not imported_rows:
        for item in artifacts:
            if not isinstance(item, dict):
                continue
            artifact = Artifact.objects.filter(
                type__slug=str(item.get("type") or "").strip(),
                slug=str(item.get("slug") or "").strip(),
            ).order_by("-updated_at", "-created_at").first()
            if not artifact:
                continue
            imported_rows.append(
                {
                    "id": str(artifact.id),
                    "slug": _artifact_slug(artifact),
                    "type": artifact.type.slug if artifact.type_id else "",
                    "package_version": str(artifact.package_version or ""),
                    "title": artifact.title,
                }
            )
    solution_links = _link_generated_artifacts_to_solution(artifacts=receipt_artifacts or [
        Artifact.objects.filter(id=row.get("id")).select_related("type").first()
        for row in imported_rows
        if isinstance(row, dict)
    ])
    return JsonResponse(
        {
            "package": _serialize_artifact_package(package),
            "created": created,
            "receipt": _serialize_artifact_install_receipt(receipt),
            "artifacts": imported_rows,
            "solution_links": solution_links,
        },
        status=status,
    )


@csrf_exempt
@login_required
def solution_bundle_install(request: HttpRequest) -> JsonResponse:
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if staff_error := _require_staff(request):
        return staff_error
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)

    workspace = _resolve_solution_import_workspace(identity, request)
    if workspace is None:
        return JsonResponse(
            {"error": "workspace context is required for solution bundle install"},
            status=400,
        )

    payload = _parse_json(request)
    bundle_payload = payload.get("bundle") if isinstance(payload.get("bundle"), dict) else {}
    source = str(payload.get("source") or "").strip()
    try:
        if bundle_payload:
            bundle = normalize_solution_bundle(bundle_payload)
        elif source:
            bundle = load_solution_bundle_from_source(source)
        else:
            return JsonResponse({"error": "bundle or source is required"}, status=400)
        result = install_solution_bundle(
            workspace=workspace,
            bundle=bundle,
            install_source=(source or "inline_bundle"),
            installed_by=request.user if request.user.is_authenticated else None,
        )
    except SolutionBundleError as exc:
        return JsonResponse({"error": str(exc)}, status=400)

    application = result.get("application")
    memberships = result.get("memberships") if isinstance(result.get("memberships"), list) else []
    bindings = result.get("workspace_bindings") if isinstance(result.get("workspace_bindings"), list) else []
    receipts = result.get("receipts") if isinstance(result.get("receipts"), list) else []
    return JsonResponse(
        {
            "workspace_id": str(workspace.id),
            "source": source or None,
            "bundle": result.get("bundle") if isinstance(result.get("bundle"), dict) else {},
            "application": _serialize_application_detail(application) if isinstance(application, Application) else None,
            "application_created": bool(result.get("application_created")),
            "memberships": [
                _serialize_application_artifact_membership(member)
                for member in memberships
                if isinstance(member, ApplicationArtifactMembership)
            ],
            "workspace_bindings": [
                _serialize_workspace_artifact_binding(binding)
                for binding in bindings
                if isinstance(binding, WorkspaceArtifactBinding)
            ],
            "receipts": [
                _serialize_artifact_install_receipt(receipt)
                for receipt in receipts
                if isinstance(receipt, ArtifactInstallReceipt)
            ],
            "policy_source": str(result.get("policy_source") or "reconstructed"),
            "install_source": str(result.get("install_source") or source or "inline_bundle"),
            "warnings": [str(item) for item in (result.get("warnings") or []) if str(item).strip()],
        }
    )


