def _solution_change_session_selected_artifact_ids(session: SolutionChangeSession) -> List[str]:
    raw = session.selected_artifact_ids_json if isinstance(session.selected_artifact_ids_json, list) else []
    normalized: List[str] = []
    seen: set[str] = set()
    for item in raw:
        token = str(item or "").strip()
        if not token or token in seen:
            continue
        seen.add(token)
        normalized.append(token)
    return normalized


def _solution_scope_lock_state(session: SolutionChangeSession) -> Dict[str, Any]:
    metadata = session.metadata_json if isinstance(session.metadata_json, dict) else {}
    scope_lock = metadata.get("scope_lock") if isinstance(metadata.get("scope_lock"), dict) else {}
    locked = bool(scope_lock.get("decomposition_scope_locked"))
    locked_artifact_ids = [
        str(item or "").strip()
        for item in (scope_lock.get("locked_artifact_ids") if isinstance(scope_lock.get("locked_artifact_ids"), list) else [])
        if str(item or "").strip()
    ]
    if locked and not locked_artifact_ids:
        locked_artifact_ids = _solution_change_session_selected_artifact_ids(session)
    return {
        "decomposition_scope_locked": locked,
        "locked_artifact_ids": _dedupe(locked_artifact_ids),
        "scope_lock_reason": str(scope_lock.get("scope_lock_reason") or "").strip(),
        "scope_source": str(scope_lock.get("scope_source") or "").strip(),
        "widen_events": scope_lock.get("widen_events") if isinstance(scope_lock.get("widen_events"), list) else [],
    }


def _persist_solution_scope_lock(
    *,
    session: SolutionChangeSession,
    locked_artifact_ids: List[str],
    scope_lock_reason: str,
    scope_source: str,
    widen_event: Optional[Dict[str, Any]] = None,
) -> None:
    metadata = session.metadata_json if isinstance(session.metadata_json, dict) else {}
    current = _solution_scope_lock_state(session)
    widen_events = list(current.get("widen_events") or [])
    if isinstance(widen_event, dict) and widen_event:
        widen_events.append(widen_event)
    metadata["scope_lock"] = {
        "decomposition_scope_locked": True,
        "locked_artifact_ids": _dedupe([str(item or "").strip() for item in (locked_artifact_ids or []) if str(item or "").strip()]),
        "scope_lock_reason": str(scope_lock_reason or "").strip(),
        "scope_source": str(scope_source or "").strip(),
        "widen_events": widen_events,
    }
    session.metadata_json = metadata


def _apply_scope_lock_to_selection(
    *,
    session: SolutionChangeSession,
    selected_artifact_ids: List[str],
    scope_source: str,
    widen_reason: str = "",
    permit_planner_discovery: bool = False,
) -> Tuple[List[str], bool, str]:
    scope_lock = _solution_scope_lock_state(session)
    normalized_selected = _dedupe([str(item or "").strip() for item in selected_artifact_ids if str(item or "").strip()])
    if not bool(scope_lock.get("decomposition_scope_locked")):
        return normalized_selected, False, ""
    locked_ids = [str(item or "").strip() for item in (scope_lock.get("locked_artifact_ids") or []) if str(item or "").strip()]
    if not locked_ids:
        return normalized_selected, False, ""
    widened_ids = [item for item in normalized_selected if item not in set(locked_ids)]
    if not widened_ids:
        return normalized_selected, False, ""
    reason = str(widen_reason or "").strip()
    if permit_planner_discovery and not reason:
        reason = "planner_discovered_cross_artifact_dependency"
    if not reason:
        return locked_ids, False, "scope_widen_reason_required"
    widened = _dedupe([*locked_ids, *widened_ids])
    _persist_solution_scope_lock(
        session=session,
        locked_artifact_ids=widened,
        scope_lock_reason=str(scope_lock.get("scope_lock_reason") or "decomposition_single_artifact_resolved"),
        scope_source=str(scope_source or "manual_override"),
        widen_event={
            "source": str(scope_source or "manual_override"),
            "reason": reason,
            "added_artifact_ids": widened_ids,
            "updated_at": timezone.now().isoformat(),
        },
    )
    return widened, True, ""


_SOLUTION_WORKSTREAM_KEYS: set[str] = {
    "ui",
    "api",
    "data",
    "workflow",
    "validation",
    "behavior",
}


def _solution_change_session_confirmed_workstreams(session: SolutionChangeSession) -> List[str]:
    metadata = session.metadata_json if isinstance(session.metadata_json, dict) else {}
    raw = metadata.get("confirmed_workstreams")
    if not isinstance(raw, list):
        return []
    normalized: List[str] = []
    seen: set[str] = set()
    for item in raw:
        token = str(item or "").strip().lower()
        if not token or token in seen or token not in _SOLUTION_WORKSTREAM_KEYS:
            continue
        seen.add(token)
        normalized.append(token)
    return normalized


def _artifact_role_matches_workstreams(role: str, workstreams: List[str]) -> bool:
    normalized_role = str(role or "").strip()
    normalized_workstreams = [str(item or "").strip().lower() for item in workstreams if str(item or "").strip()]
    if (
        ("ui" in normalized_workstreams and normalized_role == "primary_ui")
        or ("api" in normalized_workstreams and normalized_role in {"primary_api", "integration_adapter"})
        or ("data" in normalized_workstreams and normalized_role in {"primary_api", "shared_library", "runtime_service"})
        or ("workflow" in normalized_workstreams and normalized_role in {"worker", "runtime_service", "integration_adapter"})
        or ("behavior" in normalized_workstreams and normalized_role in {"primary_ui", "primary_api"})
        or ("validation" in normalized_workstreams and normalized_role in {"worker", "runtime_service", "integration_adapter", "primary_api"})
    ):
        return True
    return False


def _next_solution_planning_turn_sequence(session: SolutionChangeSession) -> int:
    current = (
        SolutionPlanningTurn.objects.filter(session=session)
        .order_by("-sequence")
        .values_list("sequence", flat=True)
        .first()
    )
    return int(current or 0) + 1


def _serialize_solution_planning_turn(turn: SolutionPlanningTurn) -> Dict[str, Any]:
    return {
        "id": str(turn.id),
        "workspace_id": str(turn.workspace_id),
        "session_id": str(turn.session_id),
        "actor": turn.actor,
        "kind": turn.kind,
        "sequence": int(turn.sequence or 0),
        "payload": turn.payload_json if isinstance(turn.payload_json, dict) else {},
        "created_by": str(turn.created_by_id) if turn.created_by_id else None,
        "created_at": turn.created_at,
        "updated_at": turn.updated_at,
    }


def _serialize_solution_planning_checkpoint(checkpoint: SolutionPlanningCheckpoint) -> Dict[str, Any]:
    return {
        "id": str(checkpoint.id),
        "workspace_id": str(checkpoint.workspace_id),
        "session_id": str(checkpoint.session_id),
        "checkpoint_key": checkpoint.checkpoint_key,
        "label": checkpoint.label,
        "status": checkpoint.status,
        "required_before": checkpoint.required_before,
        "payload": checkpoint.payload_json if isinstance(checkpoint.payload_json, dict) else {},
        "decided_by": str(checkpoint.decided_by_id) if checkpoint.decided_by_id else None,
        "decided_at": checkpoint.decided_at,
        "created_at": checkpoint.created_at,
        "updated_at": checkpoint.updated_at,
    }


def _append_solution_planning_turn(
    *,
    session: SolutionChangeSession,
    actor: str,
    kind: str,
    payload: Optional[Dict[str, Any]] = None,
    created_by: Optional[UserIdentity] = None,
) -> SolutionPlanningTurn:
    normalized_payload = dict(payload) if isinstance(payload, dict) else {}
    if str(actor or "") == "planner":
        if str(kind or "") == "option_set":
            options = normalized_payload.get("options") if isinstance(normalized_payload.get("options"), list) else []
            canonical_option_ids = [
                str((item or {}).get("id") or "").strip()
                for item in options
                if isinstance(item, dict) and str((item or {}).get("id") or "").strip()
            ]
            normalized_payload = {
                **normalized_payload,
                "expected_response_kind": "option_selection",
                "allows_multiple": False,
                "canonical_option_identifiers": canonical_option_ids,
                "response_schema": {
                    "type": "object",
                    "required_any_of": ["selected_option_id", "selected_option_ids", "option_id", "response", "prompt_response"],
                    "canonical_required": ["selected_option_id"],
                    "properties": {
                        "selected_option_id": {"type": "string", "enum": canonical_option_ids},
                        "selected_option_ids": {"type": "array", "items": {"type": "string", "enum": canonical_option_ids}, "minItems": 1, "maxItems": 1},
                        "option_id": {"type": "string", "deprecated": True, "enum": canonical_option_ids},
                        "response": {"type": "string"},
                        "prompt_response": {"type": "string", "deprecated": True},
                        "source_turn_id": {"type": "string"},
                        "metadata": {"type": "object"},
                    },
                },
                "response_examples": (
                    ([{"selected_option_id": canonical_option_ids[0]}, {"selected_option_ids": [canonical_option_ids[0]]}]
                     if canonical_option_ids
                     else [{"selected_option_id": "<option_id>"}])
                ),
            }
        elif str(kind or "") == "question":
            normalized_payload = {
                **normalized_payload,
                "expected_response_kind": "text_response",
                "allows_multiple": False,
                "response_schema": {
                    "type": "object",
                    "required_any_of": ["response", "prompt_response", "reply_text", "text"],
                    "canonical_required": ["response"],
                    "properties": {
                        "response": {"type": "string"},
                        "prompt_response": {"type": "string", "deprecated": True},
                        "reply_text": {"type": "string", "deprecated": True},
                        "text": {"type": "string", "deprecated": True},
                        "source_turn_id": {"type": "string"},
                        "metadata": {"type": "object"},
                    },
                },
                "response_examples": [{"response": "Keep this backend-only and preserve behavior."}],
            }
    turn = SolutionPlanningTurn.objects.create(
        workspace_id=session.workspace_id,
        session=session,
        actor=actor,
        kind=kind,
        sequence=_next_solution_planning_turn_sequence(session),
        payload_json=normalized_payload,
        created_by=created_by,
    )
    return turn


_HYBRID_REFINEMENT_RESULT_TYPES = {
    "answer_resolution",
    "plan_revision",
    "clarification_request",
    "cannot_interpret",
}
_HYBRID_REFINEMENT_THEME_VALUES = {"light", "dark"}
_HYBRID_REFINEMENT_ALLOWED_TOP_LEVEL = {
    "mode",
    "result_type",
    "confidence",
    "normalized_updates",
    "planner_message",
    "warnings",
}
_HYBRID_REFINEMENT_ALLOWED_UPDATE_KEYS = {
    "name",
    "ui_preferences",
    "features_add",
    "constraints_add",
    "resolved_answers",
    "open_questions_remaining",
    "additional_considerations_add",
}
_HYBRID_REFINEMENT_ALLOWED_QUESTION_KEYS = {
    "integration_v1",
    "collaboration_model",
    "rich_text_required",
    "app_name",
    "ui_theme",
}


def _refinement_default_result(
    *,
    mode: str,
    result_type: str,
    confidence: float = 0.0,
    planner_message: str = "",
    warnings: Optional[List[str]] = None,
    normalized_updates: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    return {
        "mode": mode,
        "result_type": result_type,
        "confidence": float(max(0.0, min(1.0, confidence))),
        "normalized_updates": normalized_updates if isinstance(normalized_updates, dict) else {},
        "planner_message": str(planner_message or "").strip(),
        "warnings": [str(item).strip() for item in (warnings or []) if str(item).strip()],
    }


def _clean_refinement_value(value: str) -> str:
    cleaned = str(value or "").strip().strip("\"'").strip()
    cleaned = re.sub(r"\s+", " ", cleaned).strip()
    return cleaned.rstrip(".,;:").strip()


def _append_unique_lowered(target: List[str], value: str) -> None:
    text = str(value or "").strip()
    if not text:
        return
    lowered = text.lower()
    if any(str(existing or "").strip().lower() == lowered for existing in target):
        return
    target.append(text)


_PLAN_REWRITE_INSTRUCTION_PATTERNS: Tuple[re.Pattern[str], ...] = (
    re.compile(r"\brewrite\b.*\bproposed\s+work\b", re.IGNORECASE),
    re.compile(r"\breplace\b.*\bnext\s+action\b", re.IGNORECASE),
    re.compile(r"\bkeep\b.*\bprimary\b", re.IGNORECASE),
    re.compile(r"\binclude\b.*\bonly\s+if\b", re.IGNORECASE),
    re.compile(r"\bremove\b.*\b(provider|framework)\b", re.IGNORECASE),
    re.compile(r"\bnarrow\b.*\bscope\b", re.IGNORECASE),
    re.compile(r"\btighten\b.*\bplan\b", re.IGNORECASE),
)


def _looks_like_plan_rewrite_instruction(text: str) -> bool:
    value = str(text or "").strip()
    if not value:
        return False
    lowered = value.lower()
    if any(token in lowered for token in {"proposed work", "next action", "keep", "include", "primary", "only if evidence", "provider", "framework"}):
        return True
    return any(pattern.search(value) for pattern in _PLAN_REWRITE_INSTRUCTION_PATTERNS)


def _extract_filename_tokens(text: str) -> List[str]:
    tokens: List[str] = []
    if not text:
        return tokens
    for match in re.findall(r"\b([A-Za-z0-9_./-]+\.(?:tsx|ts|jsx|js|css|scss|py))\b", text):
        candidate = str(match or "").strip()
        if candidate and candidate not in tokens:
            tokens.append(candidate)
    return tokens


def _normalize_file_hint(value: str) -> str:
    return str(value or "").strip().replace("\\", "/").lower()


def _match_file_hint_to_candidates(hint: str, candidates: List[str]) -> str:
    normalized_hint = _normalize_file_hint(hint)
    if not normalized_hint:
        return ""
    hint_name = normalized_hint.rsplit("/", 1)[-1]
    for candidate in candidates:
        normalized_candidate = _normalize_file_hint(candidate)
        if normalized_candidate.endswith(normalized_hint):
            return candidate
    for candidate in candidates:
        normalized_candidate = _normalize_file_hint(candidate)
        candidate_name = normalized_candidate.rsplit("/", 1)[-1]
        if hint_name and candidate_name == hint_name:
            return candidate
    return ""


def _extract_plan_rewrite_directives(records: List[Dict[str, Any]], refinements: List[str]) -> Dict[str, Any]:
    reply_texts: List[str] = []
    for record in records:
        reply = str((record or {}).get("reply_text") or "").strip()
        if reply:
            reply_texts.append(reply)
    for reply in refinements:
        candidate = str(reply or "").strip()
        if candidate and candidate not in reply_texts:
            reply_texts.append(candidate)

    directives: Dict[str, Any] = {
        "rewrite_requested": False,
        "rewrite_proposed_work": False,
        "replace_next_action": False,
        "remove_provider_framework_noise": False,
        "narrow_scope": False,
        "primary_file_hints": [],
        "conditional_file_hints": [],
    }
    for text in reply_texts:
        lowered = text.lower()
        has_instruction = _looks_like_plan_rewrite_instruction(text)
        if has_instruction:
            directives["rewrite_requested"] = True
        if re.search(r"\brewrite\b.*\bproposed\s+work\b", lowered):
            directives["rewrite_proposed_work"] = True
        if re.search(r"\breplace\b.*\bnext\s+action\b", lowered) or (
            "next action" in lowered and any(token in lowered for token in {"replace", "actual implementation", "implementation action"})
        ):
            directives["replace_next_action"] = True
        if re.search(r"\bremove\b.*\b(provider|framework)\b", lowered) or ("provider/framework" in lowered):
            directives["remove_provider_framework_noise"] = True
        if any(token in lowered for token in {"tighten", "narrow scope", "narrow the scope", "focus scope", "keep scope tight"}):
            directives["narrow_scope"] = True
        file_tokens = _extract_filename_tokens(text)
        if "primary" in lowered:
            for token in file_tokens:
                if token not in directives["primary_file_hints"]:
                    directives["primary_file_hints"].append(token)
        if "only if" in lowered or "only when" in lowered:
            for token in file_tokens:
                if token not in directives["conditional_file_hints"]:
                    directives["conditional_file_hints"].append(token)
    return directives


def _sanitize_shared_contracts_for_refinement(
    contracts: List[str],
    *,
    directives: Dict[str, Any],
) -> List[str]:
    cleaned: List[str] = []
    remove_noise = bool(directives.get("remove_provider_framework_noise"))
    for item in contracts:
        token = str(item or "").strip()
        if not token:
            continue
        lowered = token.lower()
        if _looks_like_plan_rewrite_instruction(token):
            continue
        if remove_noise and any(noise in lowered for noise in {"provider", "framework"}):
            continue
        if token not in cleaned:
            cleaned.append(token)
    return cleaned


def _apply_refinement_rewrite_to_plan_payload(
    *,
    plan: Dict[str, Any],
    directives: Dict[str, Any],
    request_text: str,
) -> Dict[str, Any]:
    if not isinstance(plan, dict):
        return plan
    if not bool(directives.get("rewrite_requested")):
        return plan
    updated = copy.deepcopy(plan)
    candidate_files = [str(item).strip() for item in (updated.get("candidate_files") or []) if str(item).strip()]

    primary_candidate = ""
    for hint in directives.get("primary_file_hints") or []:
        matched = _match_file_hint_to_candidates(str(hint or ""), candidate_files)
        if matched:
            primary_candidate = matched
            break
    if not primary_candidate and candidate_files:
        primary_candidate = candidate_files[0]

    conditional_candidates: List[str] = []
    for hint in directives.get("conditional_file_hints") or []:
        matched = _match_file_hint_to_candidates(str(hint or ""), candidate_files)
        if matched and matched != primary_candidate and matched not in conditional_candidates:
            conditional_candidates.append(matched)

    if bool(directives.get("rewrite_proposed_work")):
        forbids_ui_changes = _request_forbids_ui_changes(request_text)
        structural_backend_refactor = _request_signals_structural_backend_refactor(request_text)
        if primary_candidate:
            if forbids_ui_changes or structural_backend_refactor:
                rewritten_steps = [
                    f"Inspect `{primary_candidate}` and identify solution-change-session workflow code to extract into modules.",
                    f"Move extracted workflow logic from `{primary_candidate}` into focused backend modules with delegation wrappers.",
                ]
            else:
                rewritten_steps = [
                    f"Inspect `{primary_candidate}` and confirm ownership of the affected header/dropdown styling behavior.",
                    f"Apply a minimal UI/layout fix in `{primary_candidate}` to address: {str(request_text or '').strip()[:140]}.",
                ]
            if conditional_candidates:
                if forbids_ui_changes or structural_backend_refactor:
                    rewritten_steps.append(
                        f"Include `{conditional_candidates[0]}` only if shared backend workflow coupling requires coordinated extraction."
                    )
                else:
                    rewritten_steps.append(
                        f"Include `{conditional_candidates[0]}` only if evidence shows shared styling/component coupling requires it."
                    )
            if forbids_ui_changes or structural_backend_refactor:
                rewritten_steps.extend(
                    [
                        "Verify request/response behavior remains identical after extraction.",
                        "Add or update focused regression tests for extracted backend workflow paths.",
                    ]
                )
            else:
                rewritten_steps.extend(
                    [
                        "Validate the dropdown styling/width behavior in the live header shell and check adjacent control parity.",
                        "Add or update a focused regression test for this UI behavior.",
                    ]
                )
            updated["implementation_steps"] = rewritten_steps[:5]
            updated["proposed_work"] = rewritten_steps[:5]
        else:
            message = (
                "Could not confidently identify owning component files for the requested rewrite. "
                "Please confirm the primary component path before revising implementation steps."
            )
            open_questions = [
                str(item).strip()
                for item in (updated.get("open_questions") if isinstance(updated.get("open_questions"), list) else [])
                if str(item).strip()
            ]
            if message not in open_questions:
                open_questions.append(message)
            updated["open_questions"] = open_questions
            updated["next_action"] = "Confirm the primary target component path, then regenerate the plan rewrite."

    if bool(directives.get("replace_next_action")) and primary_candidate:
        next_action = f"Apply the first implementation change in `{primary_candidate}` and capture a focused diff."
        updated["next_action"] = next_action
        validation_plan = [
            str(item).strip()
            for item in (updated.get("validation_plan") if isinstance(updated.get("validation_plan"), list) else [])
            if str(item).strip()
        ]
        tail = [item for item in validation_plan if item != next_action]
        updated["validation_plan"] = [next_action, *tail]

    contracts = [
        str(item).strip()
        for item in (updated.get("shared_contracts") if isinstance(updated.get("shared_contracts"), list) else [])
        if str(item).strip()
    ]
    updated["shared_contracts"] = _sanitize_shared_contracts_for_refinement(contracts, directives=directives)
    return updated


def _normalize_question_key(value: Any) -> str:
    token = str(value or "").strip().lower().replace("-", "_").replace(" ", "_")
    aliases = {
        "external_integrations_v1": "integration_v1",
        "integrations_v1": "integration_v1",
        "integration": "integration_v1",
        "collaboration": "collaboration_model",
        "collaboration_mode": "collaboration_model",
        "name": "app_name",
        "application_name": "app_name",
        "theme": "ui_theme",
        "ui_preferences_theme": "ui_theme",
        "rich_text": "rich_text_required",
    }
    token = aliases.get(token, token)
    return token if token in _HYBRID_REFINEMENT_ALLOWED_QUESTION_KEYS else ""


def _deterministic_refinement_interpretation(reply_text: str) -> Dict[str, Any]:
    text = str(reply_text or "").strip()
    lowered = text.lower()
    normalized_updates: Dict[str, Any] = {
        "features_add": [],
        "constraints_add": [],
        "resolved_answers": [],
        "open_questions_remaining": [],
        "additional_considerations_add": [],
    }
    warnings: List[str] = []
    recognized = 0

    name_match = re.search(r"\bname\s+the\s+application\s+(.+)$", text, re.IGNORECASE)
    if not name_match:
        name_match = re.search(r"\bcall\s+it\s+(.+)$", text, re.IGNORECASE)
    if name_match:
        candidate_name = _clean_refinement_value(name_match.group(1))[:120]
        if candidate_name:
            normalized_updates["name"] = candidate_name
            recognized += 1

    wants_light = any(token in lowered for token in {"default theme to light", "use light theme", "use light mode"})
    wants_dark = any(token in lowered for token in {"default theme to dark", "use dark theme", "use dark mode"})
    if wants_light and wants_dark:
        warnings.append("Conflicting theme preferences were provided.")
    elif wants_light:
        normalized_updates["ui_preferences"] = {"theme": "light"}
        normalized_updates["resolved_answers"].append({"question_key": "ui_theme", "value": "light"})
        recognized += 1
    elif wants_dark:
        normalized_updates["ui_preferences"] = {"theme": "dark"}
        normalized_updates["resolved_answers"].append({"question_key": "ui_theme", "value": "dark"})
        recognized += 1

    no_integrations = any(
        token in lowered
        for token in {
            "no external integration",
            "no external integrations",
            "without external integration",
            "without external integrations",
        }
    )
    yes_integrations = (not no_integrations) and (
        ("external integration" in lowered) or ("external integrations" in lowered)
    )
    if no_integrations and yes_integrations:
        warnings.append("Conflicting integration requirements were provided.")
    elif no_integrations:
        normalized_updates["resolved_answers"].append({"question_key": "integration_v1", "value": False})
        recognized += 1
    elif yes_integrations:
        normalized_updates["resolved_answers"].append({"question_key": "integration_v1", "value": True})
        recognized += 1

    single_collab = ("single-user" in lowered) or ("single user" in lowered)
    multi_collab = any(
        token in lowered
        for token in {
            "multi-user",
            "multi user",
            "editor/reader",
            "editor and reader",
            "editor role",
            "reader role",
            "collaboration",
        }
    )
    if single_collab and multi_collab:
        warnings.append("Conflicting collaboration preferences were provided.")
    elif single_collab:
        normalized_updates["resolved_answers"].append({"question_key": "collaboration_model", "value": "single"})
        recognized += 1
    elif multi_collab:
        normalized_updates["resolved_answers"].append({"question_key": "collaboration_model", "value": "multi"})
        recognized += 1

    if ("rich text" in lowered) or ("wysiwyg" in lowered) or ("editor support" in lowered):
        normalized_updates["resolved_answers"].append({"question_key": "rich_text_required", "value": True})
        recognized += 1

    feature_match = re.search(r"\b(?:add|include|support)\s+(.+)$", text, re.IGNORECASE)
    if feature_match:
        feature_candidate = _clean_refinement_value(feature_match.group(1))
        feature_lower = feature_candidate.lower()
        if feature_candidate:
            if ("rich text" in feature_lower) or ("wysiwyg" in feature_lower):
                normalized_updates["resolved_answers"].append({"question_key": "rich_text_required", "value": True})
            else:
                _append_unique_lowered(normalized_updates["features_add"], feature_candidate)
            recognized += 1

    if warnings:
        return _refinement_default_result(
            mode="deterministic",
            result_type="clarification_request",
            confidence=0.25,
            planner_message="I found conflicting constraints in your refinement. Please clarify the intended direction.",
            warnings=warnings,
            normalized_updates=normalized_updates,
        )
    if recognized == 0:
        normalized_updates["additional_considerations_add"] = [_clean_refinement_value(text)] if _clean_refinement_value(text) else []
        return _refinement_default_result(
            mode="deterministic",
            result_type="cannot_interpret",
            confidence=0.2,
            planner_message="I could not confidently interpret that refinement. Please clarify or use planner interpretation.",
            normalized_updates=normalized_updates,
        )
    return _refinement_default_result(
        mode="deterministic",
        result_type="answer_resolution" if recognized <= 2 else "plan_revision",
        confidence=0.9,
        normalized_updates=normalized_updates,
    )


def _extract_json_object_text(text: str) -> str:
    payload = str(text or "").strip()
    if not payload:
        return ""
    fence_match = re.search(r"```(?:json)?\s*([\s\S]*?)\s*```", payload, re.IGNORECASE)
    if fence_match:
        fenced = str(fence_match.group(1) or "").strip()
        if fenced:
            payload = fenced
    if payload.startswith("{") and payload.endswith("}"):
        return payload

    in_string = False
    escape = False
    depth = 0
    start_index: Optional[int] = None
    for idx, ch in enumerate(payload):
        if escape:
            escape = False
            continue
        if ch == "\\" and in_string:
            escape = True
            continue
        if ch == '"':
            in_string = not in_string
            continue
        if in_string:
            continue
        if ch == "{":
            if depth == 0:
                start_index = idx
            depth += 1
        elif ch == "}":
            if depth == 0:
                continue
            depth -= 1
            if depth == 0 and start_index is not None:
                candidate = payload[start_index : idx + 1].strip()
                try:
                    parsed = json.loads(candidate)
                except json.JSONDecodeError:
                    start_index = None
                    continue
                if isinstance(parsed, dict):
                    return candidate
                start_index = None
    return ""


def _validate_hybrid_refinement_envelope(candidate: Any) -> Tuple[Optional[Dict[str, Any]], List[str]]:
    errors: List[str] = []
    if not isinstance(candidate, dict):
        return None, ["envelope must be an object"]
    unknown_top = [key for key in candidate.keys() if key not in _HYBRID_REFINEMENT_ALLOWED_TOP_LEVEL]
    if unknown_top:
        errors.append(f"unknown top-level keys: {', '.join(sorted(unknown_top))}")
    result_type = str(candidate.get("result_type") or "").strip()
    if result_type not in _HYBRID_REFINEMENT_RESULT_TYPES:
        errors.append("invalid result_type")
    confidence_raw = candidate.get("confidence")
    try:
        confidence = float(confidence_raw if confidence_raw is not None else 0.0)
    except (TypeError, ValueError):
        confidence = 0.0
        errors.append("invalid confidence")
    confidence = max(0.0, min(1.0, confidence))
    mode = str(candidate.get("mode") or "agent_fallback").strip().lower()
    if mode not in {"deterministic", "agent_fallback"}:
        errors.append("invalid mode")
        mode = "agent_fallback"

    normalized_raw = candidate.get("normalized_updates")
    normalized = normalized_raw if isinstance(normalized_raw, dict) else {}
    unknown_updates = [key for key in normalized.keys() if key not in _HYBRID_REFINEMENT_ALLOWED_UPDATE_KEYS]
    if unknown_updates:
        errors.append(f"unknown normalized_updates keys: {', '.join(sorted(unknown_updates))}")

    safe_updates: Dict[str, Any] = {}
    if "name" in normalized:
        value = _clean_refinement_value(str(normalized.get("name") or ""))[:120]
        if value:
            safe_updates["name"] = value
    if "ui_preferences" in normalized:
        prefs = normalized.get("ui_preferences")
        if isinstance(prefs, dict):
            theme = str(prefs.get("theme") or "").strip().lower()
            if theme in _HYBRID_REFINEMENT_THEME_VALUES:
                safe_updates["ui_preferences"] = {"theme": theme}
            elif theme:
                errors.append("invalid ui_preferences.theme")
        elif prefs is not None:
            errors.append("ui_preferences must be an object")

    def _clean_string_list(value: Any, *, limit: int = 6, item_limit: int = 140) -> List[str]:
        if not isinstance(value, list):
            return []
        cleaned: List[str] = []
        for item in value[:limit]:
            token = _clean_refinement_value(str(item or ""))[:item_limit]
            if token:
                _append_unique_lowered(cleaned, token)
        return cleaned

    features_add = _clean_string_list(normalized.get("features_add"))
    if features_add:
        safe_updates["features_add"] = features_add
    constraints_add = _clean_string_list(normalized.get("constraints_add"), item_limit=180)
    if constraints_add:
        safe_updates["constraints_add"] = constraints_add
    open_questions = []
    if "open_questions_remaining" in normalized:
        if isinstance(normalized.get("open_questions_remaining"), list):
            for item in normalized.get("open_questions_remaining")[:8]:
                key = _normalize_question_key(item)
                if key:
                    _append_unique_lowered(open_questions, key)
                elif str(item or "").strip():
                    errors.append(f"invalid open question key: {item}")
            safe_updates["open_questions_remaining"] = open_questions
        else:
            errors.append("open_questions_remaining must be a list")

    resolved_answers: List[Dict[str, Any]] = []
    raw_answers = normalized.get("resolved_answers")
    if raw_answers is not None:
        if not isinstance(raw_answers, list):
            errors.append("resolved_answers must be a list")
        else:
            for row in raw_answers[:10]:
                if not isinstance(row, dict):
                    errors.append("resolved_answers rows must be objects")
                    continue
                key = _normalize_question_key(row.get("question_key"))
                if not key:
                    errors.append("invalid resolved_answers.question_key")
                    continue
                value = row.get("value")
                if key == "integration_v1":
                    if isinstance(value, bool):
                        normalized_value: Any = value
                    elif str(value).strip().lower() in {"yes", "true", "required", "include"}:
                        normalized_value = True
                    elif str(value).strip().lower() in {"no", "false", "none", "exclude"}:
                        normalized_value = False
                    else:
                        errors.append("invalid integration_v1 value")
                        continue
                elif key == "collaboration_model":
                    token = str(value or "").strip().lower()
                    if token in {"single", "single_user", "single-user"}:
                        normalized_value = "single"
                    elif token in {"multi", "multi_user", "multi-user"}:
                        normalized_value = "multi"
                    else:
                        errors.append("invalid collaboration_model value")
                        continue
                elif key == "rich_text_required":
                    if isinstance(value, bool):
                        normalized_value = value
                    elif str(value).strip().lower() in {"yes", "true", "required"}:
                        normalized_value = True
                    elif str(value).strip().lower() in {"no", "false", "not_required"}:
                        normalized_value = False
                    else:
                        errors.append("invalid rich_text_required value")
                        continue
                elif key == "ui_theme":
                    token = str(value or "").strip().lower()
                    if token in _HYBRID_REFINEMENT_THEME_VALUES:
                        normalized_value = token
                    else:
                        errors.append("invalid ui_theme value")
                        continue
                else:
                    normalized_value = _clean_refinement_value(str(value or ""))[:120]
                    if not normalized_value:
                        errors.append("invalid app_name value")
                        continue
                resolved_answers.append({"question_key": key, "value": normalized_value})
    if resolved_answers:
        safe_updates["resolved_answers"] = resolved_answers

    additional = _clean_string_list(normalized.get("additional_considerations_add"), limit=4, item_limit=180)
    if additional:
        safe_updates["additional_considerations_add"] = additional

    warnings = _clean_string_list(candidate.get("warnings"), limit=6, item_limit=160)
    planner_message = _clean_refinement_value(str(candidate.get("planner_message") or ""))[:320]

    if errors:
        return None, errors
    return {
        "mode": mode,
        "result_type": result_type,
        "confidence": confidence,
        "normalized_updates": safe_updates,
        "planner_message": planner_message,
        "warnings": warnings,
    }, []


def _invoke_planner_refinement_fallback(
    *,
    session: SolutionChangeSession,
    reply_text: str,
    deterministic: Dict[str, Any],
    force_planner_fallback: bool = False,
) -> Dict[str, Any]:
    resolved = resolve_ai_config(purpose_slug="planning")
    fallback_diagnostics: Dict[str, Any] = {
        "forced": bool(force_planner_fallback),
        "context_pack_applied": False,
        "context_pack_ref_count": 0,
        "context_pack_hash": "",
        "raw_response_present": False,
        "raw_response_length": 0,
        "json_extracted": False,
        "validation_errors": [],
    }
    raw_context_refs: List[Any] = []
    for key in ("purpose_default_context_pack_refs_json", "agent_context_pack_refs_json"):
        refs = resolved.get(key)
        if isinstance(refs, list):
            raw_context_refs.extend(refs)
    resolved_packs: List[ContextPack] = []
    seen_pack_ids: Set[str] = set()
    for ref in raw_context_refs:
        pack = _resolve_context_pack_ref(ref)
        if not pack:
            continue
        pack_id = str(pack.id)
        if pack_id in seen_pack_ids:
            continue
        seen_pack_ids.add(pack_id)
        resolved_packs.append(pack)
    fallback_diagnostics["context_pack_ref_count"] = len(resolved_packs)
    if resolved_packs:
        resolved_context = _resolve_context_pack_list(resolved_packs)
        context_text = str(resolved_context.get("effective_context") or "").strip()
        fallback_diagnostics["context_pack_hash"] = str(resolved_context.get("hash") or "")
        if context_text:
            base_system_prompt = str(resolved.get("system_prompt") or "").strip()
            resolved["system_prompt"] = (
                f"{base_system_prompt}\n\n{context_text}".strip() if base_system_prompt else context_text
            )
            fallback_diagnostics["context_pack_applied"] = True
    deterministic_updates = deterministic.get("normalized_updates") if isinstance(deterministic.get("normalized_updates"), dict) else {}
    schema_example = {
        "mode": "agent_fallback",
        "result_type": "plan_revision",
        "confidence": 0.78,
        "normalized_updates": {
            "name": "My Knowledge",
            "ui_preferences": {"theme": "light"},
            "features_add": ["offline sync"],
            "constraints_add": ["no external integrations in v1"],
            "resolved_answers": [{"question_key": "integration_v1", "value": False}],
            "open_questions_remaining": ["collaboration_model"],
            "additional_considerations_add": ["prioritize fast capture flow"],
        },
        "planner_message": "Applied the refinement with one remaining clarification.",
        "warnings": [],
    }
    prompt = (
        "You are a refinement interpreter.\n"
        "Return ONLY one strict JSON object that matches the required envelope.\n"
        "Do not output markdown.\n"
        "Do not output backticks.\n"
        "Do not output prose.\n"
        "Do not output any text before or after the JSON object.\n"
        "Do not include markdown fences, explanations, or any prose before/after JSON.\n"
        "Unknown keys are forbidden at every level.\n"
        "Top-level keys allowed exactly: mode,result_type,confidence,normalized_updates,planner_message,warnings.\n"
        "Set mode to agent_fallback.\n"
        "Allowed result_type values: answer_resolution,plan_revision,clarification_request,cannot_interpret.\n"
        "Allowed normalized_updates keys: name,ui_preferences,features_add,constraints_add,resolved_answers,"
        "open_questions_remaining,additional_considerations_add.\n"
        "Allowed question_key values: integration_v1,collaboration_model,rich_text_required,app_name,ui_theme.\n"
        "If you cannot safely interpret, return result_type cannot_interpret with minimal safe updates.\n"
        f"Schema example (JSON object shape): {json.dumps(schema_example, ensure_ascii=True)}\n\n"
        f"Session request: {str(session.request_text or '').strip()}\n"
        f"User refinement: {str(reply_text or '').strip()}\n"
        f"Deterministic baseline: {json.dumps(deterministic_updates, ensure_ascii=True)}\n"
    )
    result = invoke_model(
        resolved_config=resolved,
        messages=[{"role": "user", "content": prompt}],
    )
    raw_text = str(result.get("content") or "")
    fallback_diagnostics["raw_response_present"] = bool(raw_text.strip())
    fallback_diagnostics["raw_response_length"] = len(raw_text)
    json_text = _extract_json_object_text(raw_text)
    fallback_diagnostics["json_extracted"] = bool(json_text)
    logger.info(
        "planning_refinement_fallback diagnostics=%s",
        json.dumps(fallback_diagnostics, sort_keys=True),
    )
    if not json_text:
        return _refinement_default_result(
            mode="agent_fallback",
            result_type="cannot_interpret",
            confidence=0.0,
            planner_message=(
                "I could not safely interpret that refinement. Please restate it in a more specific way, "
                "or retry with planner interpretation."
            ),
            warnings=["fallback returned no parseable JSON"],
        )
    try:
        parsed = json.loads(json_text)
    except json.JSONDecodeError:
        return _refinement_default_result(
            mode="agent_fallback",
            result_type="cannot_interpret",
            confidence=0.0,
            planner_message=(
                "I could not safely interpret that refinement. Please restate it in a more specific way, "
                "or retry with planner interpretation."
            ),
            warnings=["fallback JSON decode failure"],
        )
    safe, errors = _validate_hybrid_refinement_envelope(parsed)
    if safe is None:
        fallback_diagnostics["validation_errors"] = list(errors)
        logger.warning(
            "planning_refinement_fallback validation_failed diagnostics=%s",
            json.dumps(fallback_diagnostics, sort_keys=True),
        )
        return _refinement_default_result(
            mode="agent_fallback",
            result_type="cannot_interpret",
            confidence=0.0,
            planner_message=(
                "I could not safely interpret that refinement. Please restate it in a more specific way, "
                "or retry with planner interpretation."
            ),
            warnings=[f"validation error: {err}" for err in errors],
        )
    safe["mode"] = "agent_fallback"
    return safe


def _interpret_solution_refinement(
    *,
    session: SolutionChangeSession,
    reply_text: str,
    force_planner_fallback: bool = False,
) -> Dict[str, Any]:
    deterministic = _deterministic_refinement_interpretation(reply_text)
    deterministic_type = str(deterministic.get("result_type") or "")
    should_fallback = bool(force_planner_fallback) or deterministic_type in {"cannot_interpret", "clarification_request"}
    if not should_fallback:
        return deterministic
    try:
        fallback = _invoke_planner_refinement_fallback(
            session=session,
            reply_text=reply_text,
            deterministic=deterministic,
            force_planner_fallback=force_planner_fallback,
        )
    except Exception as exc:
        if deterministic_type in {"answer_resolution", "plan_revision"} and not force_planner_fallback:
            deterministic_warnings = list(deterministic.get("warnings") or [])
            deterministic_warnings.append(f"planner fallback unavailable: {exc}")
            deterministic["warnings"] = deterministic_warnings
            return deterministic
        return _refinement_default_result(
            mode="agent_fallback",
            result_type="cannot_interpret",
            confidence=0.0,
            planner_message="Planner fallback is unavailable right now. Please refine your response with clearer constraints.",
            warnings=[f"fallback error: {exc}"],
        )
    return fallback


def _ensure_solution_stage_checkpoint(
    *,
    session: SolutionChangeSession,
) -> SolutionPlanningCheckpoint:
    checkpoint, _created = SolutionPlanningCheckpoint.objects.get_or_create(
        session=session,
        workspace_id=session.workspace_id,
        checkpoint_key="plan_scope_confirmed",
        required_before="stage",
        defaults={
            "label": "Approve planning scope before stage apply",
            "status": "pending",
            "payload_json": {
                "description": "Confirm the selected artifacts and draft plan before staging.",
                "checkpoint_state": "pending",
                "plan_revision": 0,
                "scope_hash": "",
                "scope_signature": {},
                "reopen_reason": "",
            },
        },
    )
    return checkpoint


def _solution_option_rows(
    memberships: List[ApplicationArtifactMembership],
    *,
    limit: int = 3,
    ordered_artifact_ids: Optional[List[str]] = None,
    request_text: str = "",
) -> List[Dict[str, Any]]:
    normalized_ordered_ids: List[str] = []
    seen_ordered_ids: Set[str] = set()
    if isinstance(ordered_artifact_ids, list):
        for item in ordered_artifact_ids:
            token = str(item or "").strip()
            if not token or token in seen_ordered_ids:
                continue
            seen_ordered_ids.add(token)
            normalized_ordered_ids.append(token)

    membership_by_artifact_id: Dict[str, ApplicationArtifactMembership] = {
        str(member.artifact_id): member for member in memberships
    }
    ordered_members: List[ApplicationArtifactMembership] = []
    seen_membership_artifact_ids: Set[str] = set()
    for artifact_id in normalized_ordered_ids:
        member = membership_by_artifact_id.get(artifact_id)
        if member is None:
            continue
        seen_membership_artifact_ids.add(str(member.artifact_id))
        ordered_members.append(member)
    for member in memberships:
        artifact_id = str(member.artifact_id)
        if artifact_id in seen_membership_artifact_ids:
            continue
        seen_membership_artifact_ids.add(artifact_id)
        ordered_members.append(member)

    lowered_request = str(request_text or "").strip().lower()
    forbids_ui_changes = _request_forbids_ui_changes(lowered_request)
    ui_context_tokens = {"ui", "ux", "frontend", "view", "screen", "page", "panel", "layout", "input", "component"}
    ui_code_change_tokens = {"resize", "width", "height", "css", "style", "component", "input", "textarea", "field", "layout"}
    is_ui_code_change_request = (
        bool(lowered_request)
        and not forbids_ui_changes
        and any(token in lowered_request for token in ui_context_tokens)
        and any(token in lowered_request for token in ui_code_change_tokens)
    )
    if is_ui_code_change_request:
        editable_members: List[ApplicationArtifactMembership] = []
        non_editable_members: List[ApplicationArtifactMembership] = []
        for member in ordered_members:
            artifact = member.artifact
            has_editable_paths = bool(
                isinstance(getattr(artifact, "owner_path_prefixes_json", None), list)
                and any(str(item or "").strip() for item in (artifact.owner_path_prefixes_json or []))
            )
            if has_editable_paths:
                editable_members.append(member)
            else:
                non_editable_members.append(member)
        if editable_members:
            ordered_members = editable_members + non_editable_members

    candidate_members = ordered_members[: min(max(limit, 1), len(ordered_members))]
    options: List[Dict[str, Any]] = []
    for member in candidate_members:
        options.append(
            {
                "id": str(member.artifact_id),
                "label": member.artifact.title,
                "role": member.role,
                "description": member.responsibility_summary or "",
            }
        )
    return options


def _has_meaningful_solution_memberships(memberships: List[ApplicationArtifactMembership]) -> bool:
    meaningful_roles = {
        "primary_ui",
        "primary_api",
        "integration_adapter",
        "worker",
        "runtime_service",
        "shared_library",
    }
    return any(str(member.role or "") in meaningful_roles for member in memberships)


def _request_requires_initial_clarification(request_text: str) -> bool:
    tokens = [token for token in re.findall(r"[a-z0-9_]+", str(request_text or "").lower()) if len(token) >= 2]
    return len(tokens) <= 4


def _maybe_emit_solution_checkpoint_turn(
    *,
    session: SolutionChangeSession,
    checkpoint: SolutionPlanningCheckpoint,
    force_emit: bool = False,
) -> None:
    latest_checkpoint_turn = (
        SolutionPlanningTurn.objects.filter(session=session, actor="planner", kind="checkpoint")
        .order_by("-sequence", "-created_at")
        .first()
    )
    latest_payload = latest_checkpoint_turn.payload_json if isinstance(getattr(latest_checkpoint_turn, "payload_json", None), dict) else {}
    if (
        not force_emit
        and latest_checkpoint_turn is not None
        and str(latest_payload.get("checkpoint_id") or "") == str(checkpoint.id)
        and str(latest_payload.get("status") or "") == str(checkpoint.status or "")
    ):
        return
    _append_solution_planning_turn(
        session=session,
        actor="planner",
        kind="checkpoint",
        payload={
            "checkpoint_id": str(checkpoint.id),
            "checkpoint_key": checkpoint.checkpoint_key,
            "label": checkpoint.label,
            "required_before": checkpoint.required_before,
            "status": checkpoint.status,
        },
    )


def _record_solution_draft_plan(
    *,
    session: SolutionChangeSession,
    memberships: List[ApplicationArtifactMembership],
    summary: str,
    force_code_aware_planning: bool = False,
) -> Dict[str, Any]:
    plan = _generate_solution_change_plan(
        session=session,
        memberships=memberships,
        force_code_aware_planning=force_code_aware_planning,
    )
    if isinstance(plan, dict):
        scope_lock = _solution_scope_lock_state(session)
        if bool(scope_lock.get("decomposition_scope_locked")):
            plan_selected = plan.get("selected_artifact_ids") if isinstance(plan.get("selected_artifact_ids"), list) else []
            current_selected = _solution_change_session_selected_artifact_ids(session)
            if not plan_selected and current_selected:
                plan["selected_artifact_ids"] = list(current_selected)
            elif plan_selected:
                planner_discovery_reason = ""
                if bool(plan.get("cross_artifact_required")):
                    planner_discovery_reason = "planner_reported_cross_artifact_required"
                elif str(plan.get("planning_mode") or "").strip() == "cross_artifact_change":
                    planner_discovery_reason = "planner_mode_cross_artifact_change"
                constrained, widened, error_code = _apply_scope_lock_to_selection(
                    session=session,
                    selected_artifact_ids=[str(item).strip() for item in plan_selected if str(item).strip()],
                    scope_source="planner_discovery",
                    widen_reason=planner_discovery_reason,
                    permit_planner_discovery=bool(planner_discovery_reason),
                )
                if error_code == "scope_widen_reason_required":
                    plan["selected_artifact_ids"] = list(scope_lock.get("locked_artifact_ids") or current_selected)
                    risk_annotations = [
                        str(item).strip()
                        for item in (plan.get("risk_annotations") if isinstance(plan.get("risk_annotations"), list) else [])
                        if str(item).strip()
                    ]
                    annotation = (
                        "Decomposition scope lock retained: additional artifacts were not auto-selected because no widening reason was recorded."
                    )
                    if annotation not in risk_annotations:
                        risk_annotations.append(annotation)
                    plan["risk_annotations"] = risk_annotations
                elif widened:
                    plan["selected_artifact_ids"] = constrained
    validate_decomposition_plan_quality(plan if isinstance(plan, dict) else {})
    objective_summary = str(
        plan.get("planner_objective_text")
        or plan.get("request_text")
        or session.request_text
        or ""
    )
    user_refinements = (
        [str(item).strip() for item in plan.get("user_refinements", []) if str(item).strip()]
        if isinstance(plan.get("user_refinements"), list)
        else []
    )
    session.plan_json = plan
    session.status = "planned"
    session.save(update_fields=["plan_json", "status", "metadata_json", "updated_at"])
    _append_solution_planning_turn(
        session=session,
        actor="planner",
        kind="draft_plan",
        payload={
            "summary": summary,
            "objective": objective_summary,
            "request_text": str(session.request_text or ""),
            "user_refinements": user_refinements,
            "selected_artifact_ids": list(plan.get("selected_artifact_ids") or []),
            "confirmed_workstreams": list(plan.get("confirmed_workstreams") or []),
            "suggested_workstreams": list(plan.get("suggested_workstreams") or []),
            "implementation_steps": list(plan.get("implementation_steps") or []),
            "shared_contracts": list(plan.get("shared_contracts") or []),
            "open_questions": list(plan.get("open_questions") or []),
            "validation_plan": list(plan.get("validation_plan") or []),
            "planning_mode": str(plan.get("planning_mode") or "deterministic"),
            "planner_mode": str(plan.get("planner_mode") or ""),
            "plan_kind": str(plan.get("plan_kind") or ""),
            "confidence": float(plan.get("confidence") or 0.0),
            "code_context_summary": str(plan.get("code_context_summary") or ""),
            "candidate_files": list(plan.get("candidate_files") or []),
            "candidate_components": list(plan.get("candidate_components") or []),
            "proposed_work": list(plan.get("proposed_work") or []),
            "file_operations": list(plan.get("file_operations") or []),
            "test_operations": list(plan.get("test_operations") or []),
            "validation_sequence": list(plan.get("validation_sequence") or []),
            "preview_requirements": list(plan.get("preview_requirements") or []),
            "risk_annotations": list(plan.get("risk_annotations") or []),
            "source_files": list(plan.get("source_files") or []),
            "destination_modules": list(plan.get("destination_modules") or []),
            "extraction_seams": list(plan.get("extraction_seams") or []),
            "proposed_moves": list(plan.get("proposed_moves") or []),
            "compatibility_shims": list(plan.get("compatibility_shims") or []),
            "route_update_implications": list(plan.get("route_update_implications") or []),
            "ordered_migration_steps": list(plan.get("ordered_migration_steps") or []),
        },
    )
    return plan


def _reset_solution_stage_checkpoint(*, session: SolutionChangeSession) -> SolutionPlanningCheckpoint:
    checkpoint = _ensure_solution_stage_checkpoint(session=session)
    payload = checkpoint.payload_json if isinstance(checkpoint.payload_json, dict) else {}
    payload = {
        **payload,
        "checkpoint_state": "pending",
        "reopen_reason": "",
    }
    if str(checkpoint.status or "") != "pending":
        checkpoint.status = "pending"
        checkpoint.decided_by = None
        checkpoint.decided_at = None
        checkpoint.payload_json = payload
        checkpoint.save(update_fields=["status", "decided_by", "decided_at", "payload_json", "updated_at"])
    else:
        checkpoint.payload_json = payload
        checkpoint.save(update_fields=["payload_json", "updated_at"])
    return checkpoint


def _solution_plan_scope_signature(plan: Dict[str, Any]) -> Dict[str, Any]:
    payload = plan if isinstance(plan, dict) else {}
    file_operations_scope: List[Dict[str, str]] = []
    test_operations_scope: List[Dict[str, str]] = []
    proposed_moves_scope: List[Dict[str, str]] = []
    file_operations = payload.get("file_operations") if isinstance(payload.get("file_operations"), list) else []
    for row in file_operations:
        if not isinstance(row, dict):
            continue
        operation = str(row.get("operation") or "").strip().lower()
        source = str(row.get("source") or row.get("path") or row.get("target") or "").strip()
        destination = str(row.get("destination") or row.get("to_module") or "").strip()
        if not operation and not source and not destination:
            continue
        file_operations_scope.append(
            {
                "operation": operation,
                "source": source,
                "destination": destination,
            }
        )
    file_operations_scope = sorted(
        file_operations_scope,
        key=lambda item: (
            str(item.get("operation") or ""),
            str(item.get("source") or ""),
            str(item.get("destination") or ""),
        ),
    )
    test_operations = payload.get("test_operations") if isinstance(payload.get("test_operations"), list) else []
    for row in test_operations:
        if not isinstance(row, dict):
            continue
        operation = str(row.get("operation") or "").strip().lower()
        target = str(row.get("target") or "").strip()
        scope = str(row.get("scope") or "").strip()
        if not operation and not target and not scope:
            continue
        test_operations_scope.append(
            {
                "operation": operation,
                "target": target,
                "scope": scope,
            }
        )
    test_operations_scope = sorted(
        test_operations_scope,
        key=lambda item: (
            str(item.get("operation") or ""),
            str(item.get("target") or ""),
            str(item.get("scope") or ""),
        ),
    )
    proposed_moves = payload.get("proposed_moves") if isinstance(payload.get("proposed_moves"), list) else []
    for row in proposed_moves:
        if not isinstance(row, dict):
            continue
        seam = str(row.get("seam") or "").strip()
        source = str(row.get("from") or row.get("source") or "").strip()
        destination = str(row.get("to_module") or row.get("destination") or "").strip()
        import_rewrite_target = str(row.get("import_rewrite_target") or "").strip()
        if not seam and not source and not destination and not import_rewrite_target:
            continue
        proposed_moves_scope.append(
            {
                "seam": seam,
                "source": source,
                "destination": destination,
                "import_rewrite_target": import_rewrite_target,
            }
        )
    proposed_moves_scope = sorted(
        proposed_moves_scope,
        key=lambda item: (
            str(item.get("seam") or ""),
            str(item.get("source") or ""),
            str(item.get("destination") or ""),
            str(item.get("import_rewrite_target") or ""),
        ),
    )
    return {
        "planning_mode": str(payload.get("planning_mode") or ""),
        "plan_kind": str(payload.get("plan_kind") or ""),
        "selected_artifact_ids": sorted(
            {
                str(item).strip()
                for item in (
                    payload.get("selected_artifact_ids")
                    if isinstance(payload.get("selected_artifact_ids"), list)
                    else []
                )
                if str(item).strip()
            }
        ),
        "candidate_files": sorted(
            {
                str(item).strip()
                for item in (payload.get("candidate_files") if isinstance(payload.get("candidate_files"), list) else [])
                if str(item).strip()
            }
        )[:20],
        "source_files": sorted(
            {
                str(item).strip()
                for item in (payload.get("source_files") if isinstance(payload.get("source_files"), list) else [])
                if str(item).strip()
            }
        )[:20],
        "destination_modules": sorted(
            {
                str(item).strip()
                for item in (
                    payload.get("destination_modules")
                    if isinstance(payload.get("destination_modules"), list)
                    else []
                )
                if str(item).strip()
            }
        )[:30],
        "extraction_seams": sorted(
            {
                str(item).strip()
                for item in (payload.get("extraction_seams") if isinstance(payload.get("extraction_seams"), list) else [])
                if str(item).strip()
            }
        )[:20],
        "proposed_moves_scope": proposed_moves_scope[:50],
        "file_operations_scope": file_operations_scope[:50],
        "test_operations_scope": test_operations_scope[:30],
    }


def _solution_plan_scope_hash(plan: Dict[str, Any]) -> str:
    signature = _solution_plan_scope_signature(plan)
    encoded = json.dumps(signature, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(encoded.encode("utf-8")).hexdigest()


def _solution_plan_scope_changed(*, previous_plan: Dict[str, Any], next_plan: Dict[str, Any]) -> bool:
    return _solution_plan_scope_hash(previous_plan) != _solution_plan_scope_hash(next_plan)


def _refresh_solution_stage_checkpoint_for_plan_update(
    *,
    session: SolutionChangeSession,
    previous_plan: Dict[str, Any],
    next_plan: Dict[str, Any],
) -> Tuple[SolutionPlanningCheckpoint, bool, str]:
    checkpoint = _ensure_solution_stage_checkpoint(session=session)
    status = str(checkpoint.status or "").strip()
    payload = checkpoint.payload_json if isinstance(checkpoint.payload_json, dict) else {}
    plan_revision = int(payload.get("plan_revision") or 0)
    next_scope_signature = _solution_plan_scope_signature(next_plan)
    next_scope_hash = _solution_plan_scope_hash(next_plan)
    previous_scope_hash = str(payload.get("scope_hash") or "").strip()

    if status != "approved":
        refreshed = _reset_solution_stage_checkpoint(session=session)
        refreshed_payload = refreshed.payload_json if isinstance(refreshed.payload_json, dict) else {}
        refreshed.payload_json = {
            **refreshed_payload,
            "checkpoint_state": "pending",
            "plan_revision": max(plan_revision, 0),
            "scope_hash": next_scope_hash,
            "scope_signature": next_scope_signature,
            "reopen_reason": "checkpoint_not_approved",
        }
        refreshed.save(update_fields=["payload_json", "updated_at"])
        return refreshed, False, "checkpoint_not_approved"
    material_scope_changed = _solution_plan_scope_changed(previous_plan=previous_plan, next_plan=next_plan)
    if previous_scope_hash and previous_scope_hash != next_scope_hash:
        material_scope_changed = True
    if material_scope_changed:
        refreshed = _reset_solution_stage_checkpoint(session=session)
        refreshed_payload = refreshed.payload_json if isinstance(refreshed.payload_json, dict) else {}
        refreshed.payload_json = {
            **refreshed_payload,
            "checkpoint_state": "reopened",
            "plan_revision": max(plan_revision, 0) + 1,
            "scope_hash": next_scope_hash,
            "scope_signature": next_scope_signature,
            "reopen_reason": "material_scope_changed",
            "reopen_at": timezone.now().isoformat(),
        }
        refreshed.save(update_fields=["payload_json", "updated_at"])
        return refreshed, True, "material_scope_changed"
    checkpoint.payload_json = {
        **payload,
        "checkpoint_state": "approved",
        "scope_hash": next_scope_hash,
        "scope_signature": next_scope_signature,
        "reopen_reason": "",
    }
    checkpoint.save(update_fields=["payload_json", "updated_at"])
    return checkpoint, False, "scope_unchanged"


def _advance_solution_planning_after_user_response(
    *,
    session: SolutionChangeSession,
    memberships: List[ApplicationArtifactMembership],
) -> None:
    planning_state = _solution_planning_state(session)
    if planning_state.get("pending_question") or planning_state.get("pending_option_set"):
        return
    has_existing_plan = isinstance(session.plan_json, dict) and bool(session.plan_json)
    previous_plan = session.plan_json if isinstance(session.plan_json, dict) else {}
    next_plan = _record_solution_draft_plan(
        session=session,
        memberships=memberships,
        summary=(
            "Generated structured cross-artifact draft plan."
            if not has_existing_plan
            else "Revised draft plan using your latest planning response."
        ),
    )
    checkpoint, reopened, reopen_reason = _refresh_solution_stage_checkpoint_for_plan_update(
        session=session,
        previous_plan=previous_plan,
        next_plan=next_plan,
    )
    if reopened and reopen_reason == "material_scope_changed":
        metadata = session.metadata_json if isinstance(session.metadata_json, dict) else {}
        metadata["checkpoint_reopen_reason"] = "material_scope_changed"
        metadata["checkpoint_reopen_at"] = timezone.now().isoformat()
        session.metadata_json = metadata
        session.save(update_fields=["metadata_json", "updated_at"])
    _maybe_emit_solution_checkpoint_turn(
        session=session,
        checkpoint=checkpoint,
        force_emit=has_existing_plan or reopened,
    )


def _solution_planning_state(session: SolutionChangeSession) -> Dict[str, Any]:
    turns = list(
        SolutionPlanningTurn.objects.filter(session=session)
        .select_related("created_by")
        .order_by("sequence", "created_at")
    )
    checkpoints = list(
        SolutionPlanningCheckpoint.objects.filter(session=session)
        .select_related("decided_by")
        .order_by("created_at")
    )
    serialized_turns = [_serialize_solution_planning_turn(turn) for turn in turns]
    serialized_checkpoints = [_serialize_solution_planning_checkpoint(checkpoint) for checkpoint in checkpoints]
    last_user_sequence = max(
        (int(turn.sequence or 0) for turn in turns if str(turn.actor or "") == "user"),
        default=0,
    )
    latest_draft_plan = next(
        (
            serialized
            for serialized in reversed(serialized_turns)
            if str(serialized.get("actor") or "") == "planner" and str(serialized.get("kind") or "") == "draft_plan"
        ),
        None,
    )
    pending_prompt_turn = next(
        (
            serialized
            for serialized in reversed(serialized_turns)
            if str(serialized.get("actor") or "") == "planner"
            and str(serialized.get("kind") or "") in {"question", "option_set"}
            and int(serialized.get("sequence") or 0) > last_user_sequence
        ),
        None,
    )
    pending_question = pending_prompt_turn if str((pending_prompt_turn or {}).get("kind") or "") == "question" else None
    pending_option_set = pending_prompt_turn if str((pending_prompt_turn or {}).get("kind") or "") == "option_set" else None
    pending_checkpoints = (
        [entry for entry in serialized_checkpoints if str(entry.get("status") or "") == "pending"]
        if latest_draft_plan and not pending_prompt_turn
        else []
    )
    scope_lock = _solution_scope_lock_state(session)
    return {
        "turns": serialized_turns,
        "checkpoints": serialized_checkpoints,
        "pending_question": pending_question,
        "pending_option_set": pending_option_set,
        "pending_checkpoints": pending_checkpoints,
        "latest_draft_plan": latest_draft_plan,
        "decomposition_scope_locked": bool(scope_lock.get("decomposition_scope_locked")),
        "locked_artifact_ids": list(scope_lock.get("locked_artifact_ids") or []),
        "scope_lock_reason": str(scope_lock.get("scope_lock_reason") or ""),
        "scope_source": str(scope_lock.get("scope_source") or ""),
    }


def _seed_solution_planning_state_on_create(
    *,
    session: SolutionChangeSession,
    memberships: List[ApplicationArtifactMembership],
) -> None:
    request_text = str(session.request_text or "").strip()
    if request_text:
        _append_solution_planning_turn(
            session=session,
            actor="user",
            kind="request",
            payload={"request_text": request_text},
            created_by=session.created_by,
        )

    token_count = len([token for token in re.findall(r"[a-z0-9_]+", request_text.lower()) if len(token) >= 2])
    has_meaningful_memberships = _has_meaningful_solution_memberships(memberships)
    auto_locked_artifact_id = _resolve_initial_decomposition_autolock_artifact(
        session=session,
        memberships=memberships,
    )
    if auto_locked_artifact_id:
        session.selected_artifact_ids_json = [auto_locked_artifact_id]
        metadata = session.metadata_json if isinstance(session.metadata_json, dict) else {}
        planner_hints = _collect_decomposition_planner_hints(
            session_metadata=session.metadata_json if isinstance(session.metadata_json, dict) else {},
            analysis_metadata=session.analysis_json if isinstance(session.analysis_json, dict) else {},
        )
        metadata["initial_scope"] = {
            "auto_locked": True,
            "artifact_id": auto_locked_artifact_id,
            "reason": "decomposition_single_artifact_resolved",
            "target_source_files": list(
                planner_hints.get("target_source_files")
                if isinstance(planner_hints.get("target_source_files"), list)
                else []
            ),
        }
        metadata["scope_lock"] = {
            "decomposition_scope_locked": True,
            "locked_artifact_ids": [auto_locked_artifact_id],
            "scope_lock_reason": "decomposition_single_artifact_resolved",
            "scope_source": "campaign_metadata",
            "widen_events": [],
        }
        session.metadata_json = metadata
        session.save(update_fields=["selected_artifact_ids_json", "metadata_json", "updated_at"])
        _record_solution_draft_plan(
            session=session,
            memberships=memberships,
            summary="Auto-scoped decomposition plan from campaign metadata.",
        )
        checkpoint = _reset_solution_stage_checkpoint(session=session)
        _maybe_emit_solution_checkpoint_turn(session=session, checkpoint=checkpoint)
        return

    if request_text and not has_meaningful_memberships:
        if _request_requires_initial_clarification(request_text):
            _append_solution_planning_turn(
                session=session,
                actor="planner",
                kind="question",
                payload={
                    "question": (
                        "Before I draft the first plan: should this start as a single-user or multi-user app, "
                        "and should we prioritize data modeling or UI first?"
                    ),
                    "reason": "initial_scope_clarification",
                },
            )
            return
        _record_solution_draft_plan(
            session=session,
            memberships=memberships,
            summary="Generated an initial draft plan from your request.",
        )
        checkpoint = _reset_solution_stage_checkpoint(session=session)
        _maybe_emit_solution_checkpoint_turn(session=session, checkpoint=checkpoint)
        return

    if token_count <= 6:
        _append_solution_planning_turn(
            session=session,
            actor="planner",
            kind="question",
            payload={
                "question": "Which artifacts should this change target first, and what outcome should be validated?",
                "reason": "request_scope_needs_clarification",
            },
        )
    else:
        analysis = session.analysis_json if isinstance(session.analysis_json, dict) else {}
        ordered_artifact_ids = (
            analysis.get("suggested_artifact_ids")
            if isinstance(analysis.get("suggested_artifact_ids"), list)
            else []
        )
        options = _solution_option_rows(
            memberships,
            ordered_artifact_ids=ordered_artifact_ids,
            request_text=request_text,
        )
        if options:
            _append_solution_planning_turn(
                session=session,
                actor="planner",
                kind="option_set",
                payload={
                    "prompt": (
                        "Select the initial artifact to focus planning on "
                        "(you can still include multiple artifacts later)."
                    ),
                    "options": options,
                },
            )
        else:
            _append_solution_planning_turn(
                session=session,
                actor="planner",
                kind="question",
                payload={
                    "question": "No selectable artifacts are available yet. Add memberships or refine scope, then regenerate options.",
                    "reason": "missing_artifact_options",
                },
            )


def _infer_solution_workstreams_from_request(request_text: str) -> List[str]:
    lowered = str(request_text or "").strip().lower()
    if not lowered:
        return []
    forbids_ui_changes = _request_forbids_ui_changes(request_text)
    workstreams: List[str] = []

    def _append_once(token: str) -> None:
        if token not in workstreams:
            workstreams.append(token)

    ui_tokens = {"ui", "ux", "layout", "width", "header", "pane", "panel", "screen", "view", "style", "css", "input", "control", "presentation"}
    api_tokens = {"api", "endpoint", "request", "response", "service", "contract", "schema"}
    data_tokens = {"data", "model", "storage", "persist", "persistence", "database", "db", "table", "field"}
    workflow_tokens = {"flow", "workflow", "session", "planner", "stage", "apply", "preview", "validate", "orchestration", "pipeline", "job"}
    behavior_tokens = {"logic", "behavior", "rule", "validation", "condition"}

    if (not forbids_ui_changes) and any(token in lowered for token in ui_tokens):
        _append_once("ui")
    if any(token in lowered for token in api_tokens):
        _append_once("api")
    if any(token in lowered for token in data_tokens):
        _append_once("data")
    if any(token in lowered for token in workflow_tokens):
        _append_once("workflow")
    if any(token in lowered for token in behavior_tokens):
        _append_once("behavior")
    return workstreams


def _analyze_solution_impacted_artifacts(
    *, application: Application, request_text: str, memberships: List[ApplicationArtifactMembership]
) -> Dict[str, Any]:
    text = str(request_text or "").strip().lower()
    tokens = [token for token in re.findall(r"[a-z0-9_]+", text) if len(token) >= 3]
    path_hints = _request_path_hints(request_text)
    forbids_ui_changes = _request_forbids_ui_changes(request_text)
    structural_backend_refactor = _request_signals_structural_backend_refactor(request_text)
    ui_context_tokens = {
        "ui",
        "ux",
        "frontend",
        "view",
        "screen",
        "page",
        "panel",
        "pane",
        "layout",
        "form",
        "input",
        "button",
        "modal",
        "workbench",
        "console",
        "header",
        "footer",
    }
    ui_code_change_tokens = {
        "resize",
        "resized",
        "width",
        "height",
        "align",
        "spacing",
        "margin",
        "padding",
        "css",
        "style",
        "styling",
        "component",
        "textfield",
        "input",
        "textarea",
        "dropdown",
        "select",
        "placeholder",
        "label",
        "font",
        "color",
        "theme",
        "fullwidth",
    }
    api_change_tokens = {
        "api",
        "endpoint",
        "schema",
        "contract",
        "backend",
        "payload",
        "response",
        "request",
    }
    has_ui_context = (not forbids_ui_changes) and any(token in text for token in ui_context_tokens)
    has_ui_code_change_signal = (not forbids_ui_changes) and any(token in text for token in ui_code_change_tokens)
    is_ui_code_change_request = has_ui_context and has_ui_code_change_signal
    is_api_change_request = any(token in text for token in api_change_tokens) and not is_ui_code_change_request
    role_signals: Dict[str, List[str]] = {
        "primary_ui": ["ui", "ux", "frontend", "view", "screen", "page", "shell", "workbench"],
        "primary_api": ["api", "endpoint", "contract", "schema", "backend", "service", "orchestrator"],
        "integration_adapter": ["adapter", "integration", "connector", "bridge", "import"],
        "worker": ["worker", "job", "queue", "async", "batch"],
        "runtime_service": ["runtime", "deploy", "container", "service", "ops"],
        "shared_library": ["shared", "library", "sdk", "types", "common"],
    }
    matched_roles: set[str] = set()
    for role, words in role_signals.items():
        if any(word in text for word in words):
            matched_roles.add(role)
    impacted_rows: List[Dict[str, Any]] = []
    for member in memberships:
        artifact = member.artifact
        score = 0
        reasons: List[str] = []
        has_editable_paths = bool(
            isinstance(getattr(artifact, "owner_path_prefixes_json", None), list)
            and any(str(item or "").strip() for item in (artifact.owner_path_prefixes_json or []))
        )
        is_repo_backed = str(getattr(artifact, "edit_mode", "") or "").strip().lower() == "repo_backed"
        artifact_intent_text = " ".join(
            [
                str(getattr(artifact, "title", "") or ""),
                str(getattr(artifact, "slug", "") or ""),
                str(getattr(artifact, "summary", "") or ""),
                str(member.responsibility_summary or ""),
            ]
        ).lower()
        artifact_ui_signal = any(token in artifact_intent_text for token in {" ui", "frontend", "workbench", "panel", "layout"})
        artifact_api_signal = any(token in artifact_intent_text for token in {"api", "backend", "endpoint", "service"})
        owner_paths = [
            str(item or "").strip().lower()
            for item in (
                artifact.owner_path_prefixes_json
                if isinstance(getattr(artifact, "owner_path_prefixes_json", None), list)
                else []
            )
            if str(item or "").strip()
        ]
        matched_path_hint = any(
            _path_hint_matches_owner_scope(path_hint, owner_prefix)
            for path_hint in path_hints
            for owner_prefix in owner_paths
        )
        path_hint_targets_python_backend = any(
            token in path_hint for path_hint in path_hints for token in ("xyn_orchestrator", "xyn_api.py", ".py")
        )
        if matched_path_hint:
            score += 10
            reasons.append("explicit request path overlaps artifact owned source paths")
        elif path_hints and path_hint_targets_python_backend and artifact_api_signal:
            score += 5
            reasons.append("request references backend python module and artifact has API/backend intent")
        if member.role in matched_roles:
            score += 4
            reasons.append(f"request mentions {member.role.replace('_', ' ')} concerns")
            if is_ui_code_change_request and member.role == "primary_ui" and not has_editable_paths:
                score -= 3
                reasons.append("role confidence reduced: primary_ui artifact has no editable paths for UI code changes")
        haystack = " ".join(
            [
                str(member.role or ""),
                str(member.responsibility_summary or ""),
                str(artifact.title or ""),
                str(getattr(artifact.type, "slug", "") or ""),
                str(getattr(artifact, "summary", "") or ""),
            ]
        ).lower()
        token_hits = [token for token in tokens if token in haystack]
        if token_hits:
            score += min(3, len(token_hits))
            reasons.append(f"matched request terms: {', '.join(sorted(set(token_hits))[:3])}")
        if member.role in {"primary_ui", "primary_api"}:
            if is_ui_code_change_request and member.role == "primary_ui" and not has_editable_paths:
                reasons.append("primary role weighting suppressed: artifact is not editable for UI code changes")
            else:
                score += 1
                reasons.append("primary role default weighting")
        if is_ui_code_change_request:
            if has_editable_paths:
                bonus = 5 if is_repo_backed else 4
                score += bonus
                reasons.append("ui code-change request prefers artifacts with editable path ownership")
            else:
                score -= 4
                reasons.append("ui code-change request penalizes artifacts without editable path ownership")
            if artifact_ui_signal:
                score += 3
                reasons.append("ui code-change request aligns with artifact UI intent")
            elif artifact_api_signal:
                score -= 2
                reasons.append("ui code-change request de-prioritizes API-oriented artifacts")
        if is_api_change_request:
            if artifact_api_signal:
                score += 3
                reasons.append("api change request aligns with artifact API intent")
            elif artifact_ui_signal:
                score -= 2
                reasons.append("api change request de-prioritizes UI-oriented artifacts")
        if forbids_ui_changes and artifact_ui_signal:
            score -= 5
            reasons.append("request explicitly forbids UI/styling/layout changes")
        if structural_backend_refactor and artifact_api_signal:
            score += 3
            reasons.append("request indicates structural backend refactor")
        if score <= 0:
            continue
        impacted_rows.append(
            {
                "membership_id": str(member.id),
                "artifact_id": str(artifact.id),
                "artifact_title": artifact.title,
                "artifact_type": artifact.type.slug if artifact.type_id else "",
                "role": member.role,
                "score": score,
                "reasons": reasons,
            }
        )
    impacted_rows.sort(key=lambda row: (-int(row.get("score") or 0), str(row.get("artifact_title") or "")))
    if not impacted_rows:
        fallback_members = [m for m in memberships if m.role in {"primary_ui", "primary_api"}] or memberships[:2]
        for member in fallback_members:
            impacted_rows.append(
                {
                    "membership_id": str(member.id),
                    "artifact_id": str(member.artifact_id),
                    "artifact_title": member.artifact.title,
                    "artifact_type": member.artifact.type.slug if member.artifact.type_id else "",
                    "role": member.role,
                    "score": 1,
                    "reasons": ["defaulted to primary solution artifacts"],
                }
            )
    suggested_artifact_ids = [str(row.get("artifact_id") or "") for row in impacted_rows if str(row.get("artifact_id") or "").strip()]
    suggested_workstreams = _infer_solution_workstreams_from_request(request_text)
    return {
        "request_text": request_text,
        "token_count": len(tokens),
        "impacted_artifacts": impacted_rows,
        "suggested_artifact_ids": suggested_artifact_ids,
        "suggested_workstreams": suggested_workstreams,
    }


def _build_solution_impacted_analysis(
    *,
    application: Application,
    request_text: str,
    memberships: List[ApplicationArtifactMembership],
    session_metadata: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    metadata_payload = session_metadata if isinstance(session_metadata, dict) else {}
    metadata_hints = _collect_decomposition_planner_hints(
        session_metadata=metadata_payload,
        analysis_metadata={},
    )
    normalized_target_paths = _dedupe(
        [
            str(item).strip().replace("\\", "/")
            for item in (
                metadata_hints.get("target_source_files")
                if isinstance(metadata_hints.get("target_source_files"), list)
                else []
            )
            if str(item).strip()
        ]
    )
    if normalized_target_paths:
        hinted_suffixes = [str(Path(path).name).strip() for path in normalized_target_paths if str(Path(path).name).strip()]
        if hinted_suffixes:
            request_text = f"{request_text} {' '.join(hinted_suffixes)}".strip()
    analysis = _analyze_solution_impacted_artifacts(
        application=application,
        request_text=request_text,
        memberships=memberships,
    )
    if metadata_hints:
        analysis = {
            **analysis,
            "decomposition_campaign": metadata_hints,
            "planner_hints": metadata_hints,
        }
    impacted_rows = analysis.get("impacted_artifacts") if isinstance(analysis.get("impacted_artifacts"), list) else []
    suggested_workstreams = analysis.get("suggested_workstreams") if isinstance(analysis.get("suggested_workstreams"), list) else []
    if impacted_rows:
        analysis_status = "matched"
    elif suggested_workstreams:
        analysis_status = "suggested_only"
    else:
        analysis_status = "no_confident_matches"
    analysis["analysis_status"] = analysis_status
    placement_guidance = evaluate_architectural_placement(
        request_text=request_text,
        capability_domain="auto",
    )
    analysis["placement_guidance"] = placement_guidance
    analysis["architectural_placement"] = (
        placement_guidance.get("architectural_placement")
        if isinstance(placement_guidance, dict) and isinstance(placement_guidance.get("architectural_placement"), dict)
        else {}
    )
    analysis["analyzed_at"] = timezone.now().isoformat()
    return analysis


def _resolve_initial_decomposition_autolock_artifact(
    *,
    session: SolutionChangeSession,
    memberships: List[ApplicationArtifactMembership],
) -> Optional[str]:
    metadata_payload = session.metadata_json if isinstance(session.metadata_json, dict) else {}
    analysis_payload = session.analysis_json if isinstance(session.analysis_json, dict) else {}
    planner_hints = _collect_decomposition_planner_hints(
        session_metadata=metadata_payload,
        analysis_metadata=analysis_payload,
    )
    target_source_files = (
        planner_hints.get("target_source_files")
        if isinstance(planner_hints.get("target_source_files"), list)
        else []
    )
    normalized_targets = _dedupe(
        [str(item).strip().replace("\\", "/") for item in target_source_files if str(item).strip()]
    )
    if not normalized_targets:
        return None

    planning_mode, _reasons = _classify_solution_change_planning_mode(
        request_text=str(session.request_text or ""),
        session_metadata=planner_hints,
    )
    if planning_mode != "decompose_existing_system":
        return None

    lowered_request = str(session.request_text or "").strip().lower()
    if any(
        token in lowered_request
        for token in ("cross artifact", "cross-artifact", "across artifacts", "both ui and api", "frontend and backend")
    ):
        return None
    if bool(planner_hints.get("requires_multiple_artifacts")) or bool(planner_hints.get("cross_artifact_required")):
        return None

    membership_ids = {str(member.artifact_id): member for member in memberships}
    matched_artifact_ids: Set[str] = set()
    for target in normalized_targets:
        lowered_target = target.lower()
        target_matches: List[str] = []
        for member in memberships:
            artifact = member.artifact
            owner_prefixes = (
                artifact.owner_path_prefixes_json
                if isinstance(getattr(artifact, "owner_path_prefixes_json", None), list)
                else []
            )
            if not owner_prefixes:
                continue
            if any(
                _path_hint_matches_owner_scope(lowered_target, str(prefix or "").strip().lower())
                for prefix in owner_prefixes
                if str(prefix or "").strip()
            ):
                artifact_id = str(member.artifact_id)
                if artifact_id not in target_matches:
                    target_matches.append(artifact_id)
        if len(target_matches) != 1:
            return None
        matched_artifact_ids.add(target_matches[0])
    if len(matched_artifact_ids) != 1:
        return None
    resolved_artifact_id = str(next(iter(matched_artifact_ids)))
    if resolved_artifact_id not in membership_ids:
        return None

    impacted_rows = (
        analysis_payload.get("impacted_artifacts")
        if isinstance(analysis_payload.get("impacted_artifacts"), list)
        else []
    )
    scored = [row for row in impacted_rows if isinstance(row, dict) and str(row.get("artifact_id") or "").strip()]
    if scored:
        scored = sorted(scored, key=lambda row: -int(row.get("score") or 0))
        top_row = scored[0]
        top_artifact_id = str(top_row.get("artifact_id") or "").strip()
        top_score = int(top_row.get("score") or 0)
        if top_artifact_id and top_artifact_id != resolved_artifact_id:
            return None
        if len(scored) > 1:
            second_score = int(scored[1].get("score") or 0)
            if top_score - second_score < 3:
                return None

    return resolved_artifact_id


