def _request_appears_implementation_specific(request_text: str) -> bool:
    lowered = str(request_text or "").strip().lower()
    if not lowered:
        return False
    if _request_signals_structural_backend_refactor(request_text):
        return True
    tokens = set(re.findall(r"[a-z0-9_]+", lowered))
    return any(token in tokens for token in _CODE_AWARE_IMPLEMENTATION_TOKENS)


def _request_appears_ui_implementation_specific(request_text: str) -> bool:
    lowered = str(request_text or "").strip().lower()
    if not lowered:
        return False
    if _request_forbids_ui_changes(request_text):
        return False
    tokens = set(re.findall(r"[a-z0-9_]+", lowered))
    return any(token in tokens for token in _CODE_AWARE_UI_HINT_TOKENS)


def _request_forbids_ui_changes(request_text: str) -> bool:
    text = str(request_text or "").strip().lower()
    if not text:
        return False
    patterns = (
        r"\bno\s+ui\b",
        r"\bno\s+styling\b",
        r"\bno\s+layout\b",
        r"\bdo\s+not\s+modify\s+ui\b",
        r"\bdo\s+not\s+change\s+ui\b",
        r"\bdo\s+not\s+modify\s+styling\b",
        r"\bdo\s+not\s+modify\s+layout\b",
        r"\bdo\s+not\s+touch\s+ui\b",
        r"\bwithout\s+ui\s+changes\b",
        r"\bwithout\s+layout\s+changes\b",
        r"\bwithout\s+styling\s+changes\b",
    )
    return any(re.search(pattern, text) for pattern in patterns)


def _request_signals_structural_backend_refactor(request_text: str) -> bool:
    text = str(request_text or "").strip().lower()
    if not text:
        return False
    signals = (
        "strict refactor",
        "structural refactor",
        "extract into modules",
        "extract into smaller modules",
        "decompose",
        "delegation wrappers",
        "replace with delegation wrappers",
        "preserve behavior",
        "maintain identical request/response behavior",
        "no feature additions",
        "do not introduce new features",
    )
    return any(signal in text for signal in signals)


def _metadata_signals_decomposition_campaign(metadata: Dict[str, Any]) -> bool:
    payload = metadata if isinstance(metadata, dict) else {}
    for key in _DECOMPOSITION_METADATA_KEYS:
        value = payload.get(key)
        if isinstance(value, list) and any(str(item or "").strip() for item in value):
            return True
    return False


def _collect_decomposition_planner_hints(
    *,
    session_metadata: Dict[str, Any],
    analysis_metadata: Dict[str, Any],
) -> Dict[str, Any]:
    metadata_payload = session_metadata if isinstance(session_metadata, dict) else {}
    analysis_payload = analysis_metadata if isinstance(analysis_metadata, dict) else {}
    merged: Dict[str, Any] = copy.deepcopy(metadata_payload)
    for passthrough_key in ("requires_multiple_artifacts", "cross_artifact_required", "required_artifact_ids"):
        if passthrough_key not in merged and passthrough_key in analysis_payload:
            merged[passthrough_key] = analysis_payload.get(passthrough_key)
    containers: List[Dict[str, Any]] = []
    containers.extend([metadata_payload, analysis_payload])
    for key in (
        "decomposition_campaign",
        "decomposition_session",
        "planner_hints",
        "campaign_metadata",
        "campaign",
    ):
        value = metadata_payload.get(key)
        if isinstance(value, dict):
            containers.append(value)
    for key in ("decomposition_campaign", "planner_hints"):
        value = analysis_payload.get(key)
        if isinstance(value, dict):
            containers.append(value)
    for key in _DECOMPOSITION_METADATA_KEYS:
        values: List[str] = []
        for container in containers:
            raw = container.get(key)
            if isinstance(raw, list):
                for item in raw:
                    token = str(item or "").strip()
                    if token and token not in values:
                        values.append(token)
        if values:
            merged[key] = values
    return merged


def _request_targets_oversized_monolith(request_text: str, metadata: Dict[str, Any]) -> bool:
    text = str(request_text or "").strip().lower()
    target_files: List[str] = []
    payload = metadata if isinstance(metadata, dict) else {}
    target_source_files = payload.get("target_source_files")
    if isinstance(target_source_files, list):
        target_files.extend([str(item or "").strip().lower() for item in target_source_files if str(item or "").strip()])
    monolith_hints = (
        "backend/xyn_orchestrator/xyn_api.py",
        "services/xyn-api/backend/xyn_orchestrator/xyn_api.py",
        "xyn_orchestrator/xyn_api.py",
    )
    if any(hint in text for hint in monolith_hints):
        return True
    return any(any(hint in candidate for hint in monolith_hints) for candidate in target_files)


def _classify_solution_change_planning_mode(
    *,
    request_text: str,
    session_metadata: Dict[str, Any],
) -> Tuple[str, List[str]]:
    lowered = str(request_text or "").strip().lower()
    metadata = session_metadata if isinstance(session_metadata, dict) else {}
    reasons: List[str] = []
    if _request_signals_structural_backend_refactor(request_text):
        reasons.append("structural_refactor_terms")
    if any(term in lowered for term in _DECOMPOSITION_REQUEST_TERMS):
        reasons.append("decomposition_terms")
    if _metadata_signals_decomposition_campaign(metadata):
        reasons.append("decomposition_metadata")
    if _request_targets_oversized_monolith(request_text, metadata):
        reasons.append("oversized_monolith_target")
    if reasons:
        return "decompose_existing_system", reasons
    return "modify_existing_system", ["default_modify_path"]


def _derive_plan_prohibitions(request_text: str) -> Dict[str, Any]:
    text = str(request_text or "").strip().lower()
    if not text:
        return {
            "ui_changes_forbidden": False,
            "feature_additions_forbidden": False,
            "behavior_changes_forbidden": False,
            "active_categories": [],
        }
    ui_changes_forbidden = _request_forbids_ui_changes(text)
    feature_additions_forbidden = any(
        token in text
        for token in ("no new features", "do not introduce new features", "no feature additions")
    )
    behavior_changes_forbidden = any(
        token in text
        for token in ("preserve behavior", "maintain identical request/response behavior", "keep behavior identical")
    )
    active_categories: List[str] = []
    if ui_changes_forbidden:
        active_categories.append("ui_changes_forbidden")
    if feature_additions_forbidden:
        active_categories.append("feature_additions_forbidden")
    if behavior_changes_forbidden:
        active_categories.append("behavior_changes_forbidden")
    return {
        "ui_changes_forbidden": ui_changes_forbidden,
        "feature_additions_forbidden": feature_additions_forbidden,
        "behavior_changes_forbidden": behavior_changes_forbidden,
        "active_categories": active_categories,
    }


def _step_violates_plan_prohibitions(step_text: str, prohibitions: Dict[str, Any]) -> bool:
    lowered = str(step_text or "").strip().lower()
    if not lowered:
        return False
    if bool(prohibitions.get("ui_changes_forbidden")):
        for token in _PLAN_UI_FORBIDDEN_TERMS:
            if token in lowered:
                return True
    return False


def _sanitize_plan_step_list_for_prohibitions(
    *,
    values: List[str],
    prohibitions: Dict[str, Any],
) -> Tuple[List[str], int]:
    sanitized: List[str] = []
    removed = 0
    for value in values:
        token = str(value or "").strip()
        if not token:
            continue
        if _step_violates_plan_prohibitions(token, prohibitions):
            removed += 1
            continue
        if token not in sanitized:
            sanitized.append(token)
    return sanitized, removed


def _apply_plan_prohibition_guardrails(*, plan: Dict[str, Any], request_text: str) -> Dict[str, Any]:
    if not isinstance(plan, dict):
        return plan
    prohibitions = _derive_plan_prohibitions(request_text)
    active_categories = prohibitions.get("active_categories") if isinstance(prohibitions.get("active_categories"), list) else []
    if not active_categories:
        return plan
    sanitized_plan = copy.deepcopy(plan)
    total_removed = 0
    for field in ("implementation_steps", "proposed_work", "validation_plan"):
        raw_values = sanitized_plan.get(field) if isinstance(sanitized_plan.get(field), list) else []
        values = [str(item).strip() for item in raw_values if str(item).strip()]
        sanitized, removed = _sanitize_plan_step_list_for_prohibitions(values=values, prohibitions=prohibitions)
        total_removed += removed
        sanitized_plan[field] = sanitized
    next_action = str(sanitized_plan.get("next_action") or "").strip()
    if next_action and _step_violates_plan_prohibitions(next_action, prohibitions):
        total_removed += 1
        fallback_next_action = next(
            (
                str(item).strip()
                for item in (sanitized_plan.get("implementation_steps") if isinstance(sanitized_plan.get("implementation_steps"), list) else [])
                if str(item).strip()
            ),
            "",
        )
        if not fallback_next_action:
            fallback_next_action = (
                "Extract existing backend workflow logic into focused modules while preserving behavior and avoiding new feature work."
            )
        sanitized_plan["next_action"] = fallback_next_action
    if not (sanitized_plan.get("implementation_steps") if isinstance(sanitized_plan.get("implementation_steps"), list) else []):
        sanitized_plan["implementation_steps"] = [
            "Extract existing backend workflow logic into focused modules and keep delegation wrappers at existing call sites.",
            "Preserve identical request/response behavior and avoid introducing new features.",
        ]
    if not (sanitized_plan.get("proposed_work") if isinstance(sanitized_plan.get("proposed_work"), list) else []):
        sanitized_plan["proposed_work"] = [str(item).strip() for item in sanitized_plan.get("implementation_steps", []) if str(item).strip()]
    if not (sanitized_plan.get("validation_plan") if isinstance(sanitized_plan.get("validation_plan"), list) else []):
        sanitized_plan["validation_plan"] = [
            str(sanitized_plan.get("next_action") or "").strip()
            or "Confirm prohibited categories are respected before staging.",
        ]
    if total_removed > 0:
        annotations = [
            str(item).strip()
            for item in (sanitized_plan.get("guardrail_annotations") if isinstance(sanitized_plan.get("guardrail_annotations"), list) else [])
            if str(item).strip()
        ]
        annotation = (
            "Plan guardrail enforcement: removed "
            f"{total_removed} contradictory step(s) to honor explicit constraints ({', '.join(active_categories)})."
        )
        if annotation not in annotations:
            annotations.append(annotation)
        sanitized_plan["guardrail_annotations"] = annotations
        logger.info(
            "solution plan guardrail rewrite applied categories=%s removed_steps=%s",
            ",".join(active_categories),
            total_removed,
        )
    return sanitized_plan


def _request_path_hints(request_text: str) -> List[str]:
    raw_text = str(request_text or "")
    if not raw_text:
        return []
    hints: List[str] = []
    for match in re.findall(r"(?:[A-Za-z0-9_.-]+/)+[A-Za-z0-9_.-]+\.[A-Za-z0-9_]+", raw_text):
        token = str(match or "").strip().replace("\\", "/")
        if token and token not in hints:
            hints.append(token.lower())
    for token in re.findall(r"[A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+", raw_text):
        normalized = str(token or "").strip().replace("\\", "/")
        if "/" in normalized and "." not in normalized and normalized.lower() not in hints:
            hints.append(normalized.lower())
    return hints[:12]


def _path_hint_matches_owner_scope(path_hint: str, owner_prefix: str) -> bool:
    hint = str(path_hint or "").strip().replace("\\", "/").lower().strip("/")
    owner = str(owner_prefix or "").strip().replace("\\", "/").lower().strip("/")
    if not hint or not owner:
        return False
    return hint.startswith(owner) or owner.startswith(hint) or hint in owner or owner in hint


def _plan_lacks_concrete_targets(plan: Dict[str, Any]) -> bool:
    if not isinstance(plan, dict):
        return True
    if isinstance(plan.get("candidate_files"), list) and any(str(item or "").strip() for item in plan.get("candidate_files") or []):
        return False
    if isinstance(plan.get("candidate_components"), list) and any(str(item or "").strip() for item in plan.get("candidate_components") or []):
        return False
    implementation_steps = plan.get("implementation_steps") if isinstance(plan.get("implementation_steps"), list) else []
    for step in implementation_steps:
        text = str(step or "").strip()
        if "/" in text or "." in text:
            return False
    return True


def _likely_code_context_keywords(request_text: str) -> List[str]:
    tokens = [str(token).strip().lower() for token in re.findall(r"[a-z0-9_]+", str(request_text or ""))]
    keywords: List[str] = []
    for token in tokens:
        if len(token) < 3 or token in _CODE_AWARE_STOPWORDS:
            continue
        if token not in keywords:
            keywords.append(token)
    return keywords[:14]


def _request_token_set(request_text: str) -> Set[str]:
    return {str(token).strip().lower() for token in re.findall(r"[a-z0-9_]+", str(request_text or "")) if str(token).strip()}


def _request_prefers_header_navigation_scope(request_text: str) -> bool:
    tokens = _request_token_set(request_text)
    if not tokens:
        return False
    has_header_scope = bool(tokens.intersection(_CODE_AWARE_HEADER_LAYOUT_TOKENS))
    has_style_hint = bool(tokens.intersection(_CODE_AWARE_STYLE_HINT_TOKENS))
    has_navigation_target = bool(tokens.intersection({"dropdown", "menu", "nav", "navbar", "navigation", "header"}))
    return has_header_scope and (has_style_hint or has_navigation_target)


def _normalized_repo_path(path: str) -> str:
    return str(path or "").strip().replace("\\", "/").lower()


def _path_is_page_level(path: str) -> bool:
    normalized = _normalized_repo_path(path)
    if "/pages/" in normalized:
        return True
    return bool(re.search(r"[a-z0-9_-]+page\.(tsx|ts|jsx|js)$", normalized))


def _path_has_header_navigation_hint(path: str) -> bool:
    normalized = _normalized_repo_path(path)
    return any(token in normalized for token in _CODE_AWARE_HEADER_PATH_HINTS)


def _component_name_has_header_navigation_hint(name: str) -> bool:
    token = str(name or "").strip().lower()
    if not token:
        return False
    return any(
        hint in token
        for hint in (
            "header",
            "nav",
            "navbar",
            "menu",
            "dropdown",
            "shell",
            "toolbar",
            "layout",
            "topbar",
            "utility",
            "workspace",
            "profile",
        )
    )


def _extract_exported_components(content: str) -> List[str]:
    if not content:
        return []
    hits: List[str] = []
    patterns = [
        r"export\s+function\s+([A-Z][A-Za-z0-9_]*)\b",
        r"export\s+const\s+([A-Z][A-Za-z0-9_]*)\b",
        r"export\s+class\s+([A-Z][A-Za-z0-9_]*)\b",
        r"export\s+default\s+function\s+([A-Z][A-Za-z0-9_]*)\b",
        r"export\s+default\s+([A-Z][A-Za-z0-9_]*)\b",
    ]
    for pattern in patterns:
        for match in re.findall(pattern, content):
            value = str(match or "").strip()
            if value and value not in hits:
                hits.append(value)
    return hits[:24]


def _extract_imported_components(content: str) -> List[str]:
    if not content:
        return []
    hits: List[str] = []
    for block in re.findall(r"import\s+([^;]+?)\s+from\s+['\"][^'\"]+['\"]", content, flags=re.MULTILINE):
        token = str(block or "").strip()
        if not token:
            continue
        candidates: List[str] = []
        if token.startswith("{") and token.endswith("}"):
            candidates = [item.strip() for item in token[1:-1].split(",")]
        elif token.startswith("* as "):
            candidates = [token[5:].strip()]
        elif "," in token:
            left, right = token.split(",", 1)
            candidates.append(left.strip())
            right = right.strip()
            if right.startswith("{") and right.endswith("}"):
                candidates.extend([item.strip() for item in right[1:-1].split(",")])
            else:
                candidates.append(right)
        else:
            candidates = [token]
        for candidate in candidates:
            value = str(candidate or "").split(" as ", 1)[0].strip()
            if value and re.match(r"^[A-Z][A-Za-z0-9_]*$", value) and value not in hits:
                hits.append(value)
    return hits[:24]


def _extract_local_import_specs(content: str) -> List[str]:
    if not content:
        return []
    specs: List[str] = []
    for match in re.findall(r"import\s+[^;]+?\s+from\s+['\"]([^'\"]+)['\"]", content, flags=re.MULTILINE):
        spec = str(match or "").strip()
        if spec.startswith(".") and spec not in specs:
            specs.append(spec)
    return specs[:48]


def _extract_jsx_component_tags(content: str) -> List[str]:
    if not content:
        return []
    tags: List[str] = []
    for match in re.findall(r"<([A-Z][A-Za-z0-9_]*)\b", content):
        token = str(match or "").strip()
        if token and token not in tags:
            tags.append(token)
    return tags[:32]


def _humanize_request_issue(request_text: str) -> str:
    text = str(request_text or "").strip()
    if not text:
        return "the reported UI behavior issue"
    lowered = text.lower()
    if any(token in lowered for token in {"dropdown", "menu"}) and any(token in lowered for token in {"header", "nav", "toolbar"}):
        return "the reported header dropdown sizing/alignment issue"
    if any(token in lowered for token in {"width", "height", "layout", "spacing", "alignment", "css", "style"}):
        return "the reported layout/styling issue"
    if any(token in lowered for token in {"field", "input", "form"}):
        return "the reported form field behavior issue"
    return "the reported behavior issue"


def _file_rationale_map(code_context: Dict[str, Any]) -> Dict[str, str]:
    rows = code_context.get("evidence") if isinstance(code_context.get("evidence"), list) else []
    mapping: Dict[str, str] = {}
    for row in rows:
        if not isinstance(row, dict):
            continue
        path = str(row.get("path") or "").strip()
        rationale = str(row.get("rationale") or "").strip()
        if path and rationale:
            mapping[path] = rationale
    return mapping


def _candidate_file_is_strongly_supported(path: str, *, code_context: Dict[str, Any]) -> bool:
    confidence = float(code_context.get("confidence") or 0.0)
    rationale = _file_rationale_map(code_context).get(path, "").lower()
    if "page-level path penalty" in rationale:
        return False
    if confidence >= 0.75:
        return True
    return bool(
        "header/navigation path" in rationale
        or "header/navigation export" in rationale
        or "ownership bonus" in rationale
    )


def _resolve_local_import_paths(
    *,
    current_rel_path: str,
    import_specs: List[str],
    known_files: Set[str],
) -> List[str]:
    resolved: List[str] = []
    current_path = Path(current_rel_path)
    current_parent = current_path.parent
    for spec in import_specs:
        raw = str(spec or "").strip()
        if not raw:
            continue
        base = (current_parent / raw).as_posix()
        candidates = [
            f"{base}.tsx",
            f"{base}.ts",
            f"{base}.jsx",
            f"{base}.js",
            f"{base}.css",
            f"{base}.scss",
            f"{base}/index.tsx",
            f"{base}/index.ts",
            f"{base}/index.jsx",
            f"{base}/index.js",
        ]
        for candidate in candidates:
            normalized = _normalized_repo_path(candidate)
            if normalized in known_files and normalized not in resolved:
                resolved.append(normalized)
                break
    return resolved


def _resolve_local_repo_root(repo_slug: str) -> Optional[Path]:
    slug = str(repo_slug or "").strip().lower()
    candidates: List[Path] = []
    runtime_repo_map_raw = str(os.getenv("XYN_RUNTIME_REPO_MAP", "") or "").strip()
    if runtime_repo_map_raw:
        try:
            parsed_map = json.loads(runtime_repo_map_raw)
        except (TypeError, ValueError):
            parsed_map = {}
        mapped_paths = parsed_map.get(slug) if isinstance(parsed_map, dict) else []
        if isinstance(mapped_paths, list):
            for item in mapped_paths:
                token = str(item or "").strip()
                if token:
                    candidates.append(Path(token))
    if slug == "xyn-platform":
        env_root = str(os.getenv("XYN_PLATFORM_REPO_ROOT", "") or "").strip()
        if env_root:
            candidates.append(Path(env_root))
        candidates.append(Path("/workspace/xyn-platform"))
        candidates.append(Path("/home/jrestivo/src/xyn-platform"))
    elif slug == "xyn":
        env_root = str(os.getenv("XYN_REPO_ROOT", "") or "").strip()
        if env_root:
            candidates.append(Path(env_root))
        candidates.append(Path("/workspace/xyn"))
        candidates.append(Path("/home/jrestivo/src/xyn"))
    for candidate in candidates:
        try:
            resolved = candidate.expanduser().resolve()
        except Exception:
            continue
        if resolved.exists() and resolved.is_dir():
            return resolved
    return None


def gather_solution_change_code_context(
    *,
    request_text: str,
    artifact: Artifact,
    owner_repo_slug: str,
    allowed_paths: List[str],
) -> Dict[str, Any]:
    artifact_title = str(getattr(artifact, "title", "") or "").strip() or str(getattr(artifact, "slug", "") or "").strip()
    if not str(owner_repo_slug or "").strip():
        return {
            "available": False,
            "reason": "artifact has no owner_repo_slug",
            "candidate_files": [],
            "candidate_components": [],
            "summary": f"Code-aware planning unavailable: {artifact_title or 'selected artifact'} has no repository ownership metadata.",
        }
    safe_paths = [str(item).strip() for item in (allowed_paths or []) if str(item).strip()]
    if not safe_paths:
        return {
            "available": False,
            "reason": "artifact has no allowed owner paths",
            "candidate_files": [],
            "candidate_components": [],
            "summary": f"Code-aware planning unavailable: {artifact_title or 'selected artifact'} has no editable path scope.",
        }
    repo_root = _resolve_local_repo_root(owner_repo_slug)
    if repo_root is None:
        return {
            "available": False,
            "reason": "repo root not available locally",
            "candidate_files": [],
            "candidate_components": [],
            "summary": f"Code-aware planning unavailable: could not resolve local repo root for {owner_repo_slug}.",
        }
    keywords = _likely_code_context_keywords(request_text)
    prefers_header_scope = _request_prefers_header_navigation_scope(request_text)
    suffixes = {".ts", ".tsx", ".js", ".jsx", ".css", ".scss", ".py", ".json", ".md"}
    scanned_files = 0
    max_scanned_files = 260
    file_records: List[Dict[str, Any]] = []
    for prefix in safe_paths:
        scoped_root = (repo_root / prefix).resolve()
        if not scoped_root.exists() or not scoped_root.is_dir():
            continue
        for file_path in scoped_root.rglob("*"):
            if scanned_files >= max_scanned_files:
                break
            if not file_path.is_file() or file_path.suffix.lower() not in suffixes:
                continue
            scanned_files += 1
            try:
                content = file_path.read_text(encoding="utf-8", errors="ignore")
            except Exception:
                continue
            rel_path = str(file_path.relative_to(repo_root))
            normalized_path = _normalized_repo_path(rel_path)
            lowered_content = content.lower()
            file_records.append(
                {
                    "path": rel_path,
                    "normalized_path": normalized_path,
                    "lowered_name": file_path.name.lower(),
                    "lowered_content": lowered_content,
                    "exported_components": _extract_exported_components(content),
                    "imported_components": _extract_imported_components(content),
                    "jsx_components": _extract_jsx_component_tags(content),
                    "import_specs": _extract_local_import_specs(content),
                }
            )
        if scanned_files >= max_scanned_files:
            break
    known_files = {str(record.get("normalized_path") or "").strip() for record in file_records if str(record.get("normalized_path") or "").strip()}
    component_exports: Dict[str, Set[str]] = {}
    for record in file_records:
        rel_path = str(record.get("path") or "").strip()
        if not rel_path:
            continue
        record["local_import_paths"] = _resolve_local_import_paths(
            current_rel_path=rel_path,
            import_specs=[str(item) for item in (record.get("import_specs") or [])],
            known_files=known_files,
        )
        for component in record.get("exported_components") or []:
            component_name = str(component or "").strip()
            if not component_name:
                continue
            component_exports.setdefault(component_name, set()).add(rel_path)

    score_bonus_by_path: Dict[str, int] = {}
    ranked: List[Tuple[int, str, str]] = []
    for record in file_records:
        rel_path = str(record.get("path") or "").strip()
        if not rel_path:
            continue
        score = 0
        matched_terms: List[str] = []
        lowered_name = str(record.get("lowered_name") or "")
        lowered_content = str(record.get("lowered_content") or "")
        for token in keywords:
            if token in lowered_name:
                score += 3
                matched_terms.append(token)
            elif token in lowered_content:
                score += 1
                matched_terms.append(token)
        if "requested change" in lowered_content:
            score += 2
            matched_terms.append("requested change")
        if "solution" in lowered_content and "panel" in lowered_content:
            score += 1
            matched_terms.append("solution/panel")

        exported = [str(item).strip() for item in (record.get("exported_components") or []) if str(item).strip()]
        imported = [str(item).strip() for item in (record.get("imported_components") or []) if str(item).strip()]
        jsx_components = [str(item).strip() for item in (record.get("jsx_components") or []) if str(item).strip()]
        local_import_paths = [str(item).strip() for item in (record.get("local_import_paths") or []) if str(item).strip()]

        if prefers_header_scope:
            if _path_has_header_navigation_hint(rel_path):
                score += 4
                matched_terms.append("header/navigation path")
            if _path_is_page_level(rel_path):
                score -= 4
                matched_terms.append("page-level path penalty")
            if any(_component_name_has_header_navigation_hint(item) for item in exported):
                score += 4
                matched_terms.append("header/navigation export")
            if any(_component_name_has_header_navigation_hint(item) for item in imported):
                score += 2
                matched_terms.append("header/navigation import")
            if any(_component_name_has_header_navigation_hint(item) for item in jsx_components):
                score += 3
                matched_terms.append("header/navigation jsx ownership")
            if any(_path_has_header_navigation_hint(item) for item in local_import_paths):
                score += 2
                matched_terms.append("imports header/navigation module")

            # Lightweight ownership tracing: if a page references a header/nav component,
            # boost the owning component file instead of the page wrapper.
            if _path_is_page_level(rel_path):
                page_mentions_header_owner = False
                for component_name in jsx_components:
                    if not _component_name_has_header_navigation_hint(component_name):
                        continue
                    for owner_path in component_exports.get(component_name, set()):
                        if owner_path == rel_path:
                            continue
                        if _path_has_header_navigation_hint(owner_path) or _component_name_has_header_navigation_hint(component_name):
                            score_bonus_by_path[owner_path] = int(score_bonus_by_path.get(owner_path, 0)) + 5
                            page_mentions_header_owner = True
                if page_mentions_header_owner:
                    score -= 2
                    matched_terms.append("page wrapper around shared header component")

        if score <= 0:
            continue
        rationale = f"matched terms: {', '.join(sorted(set(matched_terms))[:5])}"
        ranked.append((score, rel_path, rationale))

    if score_bonus_by_path:
        boosted: List[Tuple[int, str, str]] = []
        for score, rel_path, rationale in ranked:
            bonus = int(score_bonus_by_path.get(rel_path, 0))
            if bonus > 0:
                boosted.append((score + bonus, rel_path, f"{rationale}; ownership bonus +{bonus}"))
            else:
                boosted.append((score, rel_path, rationale))
        ranked = boosted

    component_hits: List[str] = []
    for record in file_records:
        for component_name in [*record.get("exported_components", []), *record.get("jsx_components", [])]:
            candidate = str(component_name or "").strip()
            if candidate and candidate not in component_hits:
                component_hits.append(candidate)
            if len(component_hits) >= 12:
                break
        if len(component_hits) >= 12:
            break

    ranked.sort(key=lambda row: (-row[0], row[1]))
    search_strategy = "default"
    if prefers_header_scope:
        focused_rows = [row for row in ranked if _path_has_header_navigation_hint(row[1])]
        if focused_rows:
            focused_rows.sort(key=lambda row: (-row[0], row[1]))
            ranked = focused_rows + [row for row in ranked if row not in focused_rows]
            search_strategy = "focused_header_navigation"
    top_rows = ranked[:8]
    candidate_files = [row[1] for row in top_rows]
    evidence = [{"path": row[1], "rationale": row[2], "score": int(row[0])} for row in top_rows]
    top_slice = top_rows[:3]
    top_all_page_level = bool(top_slice) and all(_path_is_page_level(row[1]) for row in top_slice)
    top_has_header_hint = bool(top_slice) and any(_path_has_header_navigation_hint(row[1]) for row in top_slice)
    top_score = int(top_rows[0][0]) if top_rows else 0
    needs_clarification = False
    confidence_reason = ""
    if prefers_header_scope:
        if top_rows and top_all_page_level and not top_has_header_hint:
            needs_clarification = True
            confidence_reason = "header_request_only_page_level_matches"
        elif top_rows and top_score < 5:
            needs_clarification = True
            confidence_reason = "header_request_low_match_confidence"
        elif not top_rows:
            needs_clarification = True
            confidence_reason = "header_request_no_matches"
    confidence = 0.0
    if top_rows:
        confidence = max(0.25, min(0.95, float(top_score) / 10.0))
        if needs_clarification:
            confidence = min(confidence, 0.4)

    clarification_prompt = (
        "I may not have identified the correct component. "
        "This request refers to a header dropdown, but current matches are page-level files.\n\n"
        "Would you like me to:\n"
        "1. Search specifically for header/navigation components?\n"
        "2. Expand search scope?\n"
        "3. Proceed with current candidates?"
    )
    clarification_options = [
        "Search specifically for header/navigation components",
        "Expand search scope",
        "Proceed with current candidates",
    ]

    if needs_clarification and (not top_has_header_hint or top_all_page_level):
        candidate_files = []
        evidence = []

    if not candidate_files:
        return {
            "available": True,
            "reason": confidence_reason or "no strong matches",
            "candidate_files": [],
            "candidate_components": [],
            "evidence": [],
            "summary": f"Searched {owner_repo_slug} within {', '.join(safe_paths)} but found no strong file matches.",
            "repo_slug": owner_repo_slug,
            "scoped_paths": safe_paths,
            "confidence": confidence,
            "needs_clarification": needs_clarification,
            "clarification_prompt": clarification_prompt if needs_clarification else "",
            "clarification_options": clarification_options if needs_clarification else [],
            "search_strategy": search_strategy,
        }
    return {
        "available": True,
        "reason": "matched",
        "candidate_files": candidate_files,
        "candidate_components": component_hits[:8],
        "evidence": evidence,
        "summary": f"Used repo context from {owner_repo_slug} ({', '.join(safe_paths)}).",
        "repo_slug": owner_repo_slug,
        "scoped_paths": safe_paths,
        "confidence": confidence,
        "needs_clarification": needs_clarification,
        "clarification_prompt": clarification_prompt if needs_clarification else "",
        "clarification_options": clarification_options if needs_clarification else [],
        "search_strategy": search_strategy,
    }


def _format_code_aware_steps(base_steps: List[str], *, code_context: Dict[str, Any], request_text: str) -> List[str]:
    candidate_files = [str(item).strip() for item in (code_context.get("candidate_files") or []) if str(item).strip()]
    if not candidate_files:
        return base_steps
    steps: List[str] = []
    first_file = candidate_files[0]
    forbids_ui_changes = _request_forbids_ui_changes(request_text)
    structural_backend_refactor = _request_signals_structural_backend_refactor(request_text)
    if forbids_ui_changes or structural_backend_refactor:
        steps.append(
            f"Inspect `{first_file}` and isolate solution-change-session workflow logic for modular extraction."
        )
        steps.append(
            f"Extract workflow logic from `{first_file}` into focused backend modules and keep delegation wrappers at call sites."
        )
        steps.append("Verify request/response behavior remains identical after extraction and delegation.")
    else:
        issue_summary = _humanize_request_issue(request_text)
        steps.append(
            f"Inspect the owning UI component in `{first_file}` to confirm whether width, min-width, max-width, or anchoring is causing {issue_summary}."
        )
        steps.append(
            f"Apply the narrowest styling/positioning fix in `{first_file}` so the control remains visible and aligned within the viewport."
        )
        steps.append("Verify the updated control alignment does not regress neighboring header/navigation controls.")
    if len(candidate_files) > 1:
        secondary = candidate_files[1]
        if _candidate_file_is_strongly_supported(secondary, code_context=code_context):
            if forbids_ui_changes or structural_backend_refactor:
                steps.append(f"Review `{secondary}` only if shared backend workflow code must move with extraction.")
            else:
                steps.append(f"Review `{secondary}` if shared dropdown logic or styles are referenced during implementation.")
        else:
            if forbids_ui_changes or structural_backend_refactor:
                steps.append(f"Review `{secondary}` only if implementation evidence shows shared backend workflow coupling.")
            else:
                steps.append(f"Review `{secondary}` only if implementation evidence shows shared dropdown logic.")
    if forbids_ui_changes or structural_backend_refactor:
        steps.append("Add or update focused regression checks for extracted backend workflow paths.")
    else:
        steps.append("Add or update a focused regression check for the affected UI behavior.")
    unique_steps: List[str] = []
    for item in [*steps, *base_steps]:
        token = str(item or "").strip()
        if not token:
            continue
        if token not in unique_steps:
            unique_steps.append(token)
        if len(unique_steps) >= 5:
            break
    return unique_steps


def _plan_contains_uuid_like_work_items(plan: Dict[str, Any]) -> bool:
    proposed_work = plan.get("proposed_work")
    if not isinstance(proposed_work, list):
        return False
    uuid_like_pattern = re.compile(r"\b[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}\b", re.IGNORECASE)
    return any(uuid_like_pattern.search(str(item or "")) for item in proposed_work)


def _plan_has_meaningful_proposed_work(plan: Dict[str, Any]) -> bool:
    if not isinstance(plan, dict):
        return False
    proposed_work = plan.get("proposed_work")
    if not isinstance(proposed_work, list):
        return False
    entries = [str(item or "").strip() for item in proposed_work if str(item or "").strip()]
    if not entries:
        return False
    uuid_like_pattern = re.compile(r"\b[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}\b", re.IGNORECASE)
    meaningful_entries = [entry for entry in entries if not uuid_like_pattern.search(entry)]
    if not meaningful_entries:
        return False
    for entry in meaningful_entries:
        lowered = entry.lower()
        # File/component references and multi-word implementation steps are meaningful.
        if "/" in entry or "`" in entry or "." in entry:
            return True
        if len(re.findall(r"[a-z]{3,}", lowered)) >= 3:
            return True
        if any(
            token in lowered
            for token in {
                "inspect",
                "update",
                "adjust",
                "apply",
                "verify",
                "validate",
                "component",
                "layout",
                "style",
                "css",
                "header",
                "dropdown",
                "field",
                "input",
                "panel",
                "endpoint",
                "schema",
                "model",
                "migration",
            }
        ):
            return True
    return False


def _generate_code_aware_solution_change_plan(
    *,
    base_plan: Dict[str, Any],
    request_text: str,
    code_context: Dict[str, Any],
) -> Dict[str, Any]:
    plan = copy.deepcopy(base_plan if isinstance(base_plan, dict) else {})
    plan["planning_mode"] = "code_aware"
    plan["code_context_summary"] = str(code_context.get("summary") or "").strip()
    plan["candidate_files"] = [str(item).strip() for item in (code_context.get("candidate_files") or []) if str(item).strip()]
    plan["candidate_components"] = [str(item).strip() for item in (code_context.get("candidate_components") or []) if str(item).strip()]
    plan["code_context_confidence"] = float(code_context.get("confidence") or 0.0)
    plan["code_context_search_strategy"] = str(code_context.get("search_strategy") or "").strip()
    implementation_steps = plan.get("implementation_steps") if isinstance(plan.get("implementation_steps"), list) else []
    plan["implementation_steps"] = _format_code_aware_steps(
        [str(step).strip() for step in implementation_steps if str(step).strip()],
        code_context=code_context,
        request_text=request_text,
    )
    shared_contracts = [str(item).strip() for item in (plan.get("shared_contracts") if isinstance(plan.get("shared_contracts"), list) else []) if str(item).strip()]
    lowered_request = str(request_text or "").lower()
    ui_only_request = any(token in lowered_request for token in {"field", "input", "textarea", "width", "layout", "panel"}) and not any(
        token in lowered_request for token in {"api", "endpoint", "schema", "payload", "contract", "response"}
    )
    if _request_forbids_ui_changes(request_text):
        ui_only_request = False
    if ui_only_request:
        shared_contracts = [
            item
            for item in shared_contracts
            if "backward-compatible api contracts" not in item.lower()
            and "payload/data-shape compatibility" not in item.lower()
        ]
    plan["shared_contracts"] = shared_contracts
    needs_clarification = bool(code_context.get("needs_clarification"))
    if needs_clarification:
        clarification_prompt = str(code_context.get("clarification_prompt") or "").strip()
        clarification_options = [
            str(item).strip() for item in (code_context.get("clarification_options") or []) if str(item).strip()
        ]
        existing_open_questions = [
            str(item).strip() for item in (plan.get("open_questions") if isinstance(plan.get("open_questions"), list) else []) if str(item).strip()
        ]
        if clarification_prompt and clarification_prompt not in existing_open_questions:
            existing_open_questions.append(clarification_prompt)
        plan["open_questions"] = existing_open_questions
        plan["clarification_options"] = clarification_options
        plan["next_action"] = "Clarify the target header/navigation component before staging code changes."
    proposed_work = [str(item).strip() for item in plan.get("implementation_steps", []) if str(item).strip()]
    plan["proposed_work"] = proposed_work
    if not str(plan.get("next_action") or "").strip():
        plan["next_action"] = proposed_work[0] if proposed_work else "Confirm the first implementation step before staging."
    validation_plan = [str(item).strip() for item in (plan.get("validation_plan") if isinstance(plan.get("validation_plan"), list) else []) if str(item).strip()]
    if validation_plan:
        if validation_plan[0] != str(plan.get("next_action") or ""):
            validation_plan = [str(plan.get("next_action") or ""), *[item for item in validation_plan if item != str(plan.get("next_action") or "")]]
    else:
        validation_plan = [str(plan.get("next_action") or "Confirm the first implementation step before staging.")]
    plan["validation_plan"] = validation_plan
    return plan


def _maybe_apply_code_aware_solution_planning(
    *,
    plan: Dict[str, Any],
    session: SolutionChangeSession,
    selected_members: List[ApplicationArtifactMembership],
    force_code_aware_planning: bool = False,
) -> Dict[str, Any]:
    base_plan = copy.deepcopy(plan if isinstance(plan, dict) else {})
    base_plan.setdefault("planning_mode", "deterministic")
    base_plan.setdefault("code_context_summary", "")
    base_plan.setdefault("candidate_files", [])
    base_plan.setdefault("candidate_components", [])
    base_plan["proposed_work"] = [
        str(item).strip()
        for item in (base_plan.get("implementation_steps") if isinstance(base_plan.get("implementation_steps"), list) else [])
        if str(item).strip()
    ]
    if _plan_contains_uuid_like_work_items(base_plan):
        base_plan["proposed_work"] = []
    if not selected_members:
        return base_plan
    selected_ids = [str(item).strip() for item in _solution_change_session_selected_artifact_ids(session) if str(item).strip()]
    selected_member = None
    for artifact_id in selected_ids:
        selected_member = next((member for member in selected_members if str(member.artifact_id) == artifact_id), None)
        if selected_member is not None:
            break
    if selected_member is None:
        selected_member = selected_members[0]
    ownership = resolve_artifact_ownership(selected_member.artifact)
    owner_repo_slug = str(ownership.get("repo_slug") or "").strip()
    allowed_paths = [str(item).strip() for item in (ownership.get("allowed_paths") or []) if str(item).strip()]
    has_repo_backed_scope = bool(owner_repo_slug and allowed_paths)
    implementation_specific = _request_appears_implementation_specific(str(session.request_text or ""))
    ui_implementation_specific = _request_appears_ui_implementation_specific(str(session.request_text or ""))
    lacks_concrete_targets = _plan_lacks_concrete_targets(base_plan)
    has_meaningful_proposed_work = _plan_has_meaningful_proposed_work(base_plan)
    structural_fallback = has_repo_backed_scope and ui_implementation_specific and (lacks_concrete_targets or not has_meaningful_proposed_work)
    trigger_reason = "none"
    should_run = False
    if force_code_aware_planning:
        should_run = True
        trigger_reason = "forced"
    elif implementation_specific and lacks_concrete_targets:
        should_run = True
        trigger_reason = "token_match"
    elif structural_fallback:
        should_run = True
        trigger_reason = "structural_fallback"
    logger.info(
        "solution planning mode decision session=%s should_run_code_aware=%s reason=%s force=%s implementation_specific=%s ui_implementation_specific=%s selected_artifact=%s repo=%s lacks_targets=%s meaningful_proposed_work=%s",
        str(session.id),
        bool(should_run),
        trigger_reason,
        bool(force_code_aware_planning),
        bool(implementation_specific),
        bool(ui_implementation_specific),
        str(getattr(selected_member, "artifact_id", "") or ""),
        owner_repo_slug or "",
        bool(lacks_concrete_targets),
        bool(has_meaningful_proposed_work),
    )
    if not should_run:
        return base_plan
    context = gather_solution_change_code_context(
        request_text=str(session.request_text or ""),
        artifact=selected_member.artifact,
        owner_repo_slug=owner_repo_slug,
        allowed_paths=allowed_paths,
    )
    if not bool(context.get("available")):
        base_plan["planning_mode"] = "deterministic"
        base_plan["code_context_summary"] = str(context.get("summary") or "").strip()
        base_plan["candidate_files"] = []
        base_plan["candidate_components"] = []
        logger.info(
            "solution planning mode session=%s finalized_mode=%s reason=%s",
            str(session.id),
            "deterministic",
            str(context.get("reason") or "context_unavailable"),
        )
        return base_plan
    code_aware_plan = _generate_code_aware_solution_change_plan(
        base_plan=base_plan,
        request_text=str(session.request_text or ""),
        code_context=context,
    )
    logger.info(
        "solution planning mode session=%s finalized_mode=%s candidate_files=%s",
        str(session.id),
        str(code_aware_plan.get("planning_mode") or "deterministic"),
        len(code_aware_plan.get("candidate_files") or []),
    )
    return code_aware_plan


def _generate_solution_change_plan(
    *,
    session: SolutionChangeSession,
    memberships: List[ApplicationArtifactMembership],
    force_code_aware_planning: bool = False,
) -> Dict[str, Any]:
    planning_turns = list(
        SolutionPlanningTurn.objects.filter(session=session)
        .order_by("sequence", "created_at")
    )
    original_request = str(session.request_text or "").strip()
    response_records: List[Dict[str, Any]] = []
    user_refinements: List[str] = []
    for turn in planning_turns:
        if str(turn.actor or "") != "user" or str(turn.kind or "") != "response":
            continue
        payload = turn.payload_json if isinstance(turn.payload_json, dict) else {}
        if str(payload.get("response_kind") or "response") != "response":
            continue
        reply_text = str(payload.get("reply_text") or "").strip()
        if reply_text:
            user_refinements.append(reply_text)
        response_records.append(
            {
                "reply_text": reply_text,
                "interpretation": payload.get("interpretation") if isinstance(payload.get("interpretation"), dict) else None,
            }
        )

    def _planner_artifact_inputs() -> List[PlannerArtifactInput]:
        rows: List[PlannerArtifactInput] = []
        for membership in memberships:
            artifact = membership.artifact
            owner_paths = (
                artifact.owner_path_prefixes_json
                if isinstance(getattr(artifact, "owner_path_prefixes_json", None), list)
                else []
            )
            rows.append(
                PlannerArtifactInput(
                    artifact_id=str(artifact.id),
                    slug=str(artifact.slug or ""),
                    title=str(artifact.title or ""),
                    role=str(membership.role or ""),
                    artifact_type=str(artifact.type.slug if artifact.type_id else ""),
                    responsibility_summary=str(membership.responsibility_summary or ""),
                    owner_paths=[str(item).strip() for item in owner_paths if str(item).strip()],
                    edit_mode=str(getattr(artifact, "edit_mode", "") or ""),
                )
            )
        return rows

    def _line_count_lookup(path: str, *, candidate_members: List[ApplicationArtifactMembership]) -> Optional[int]:
        requested = str(path or "").strip().replace("\\", "/")
        if not requested:
            return None
        for member in candidate_members:
            ownership = resolve_artifact_ownership(member.artifact)
            repo_slug = str(ownership.get("repo_slug") or "").strip()
            allowed_paths = [str(item).strip() for item in (ownership.get("allowed_paths") or []) if str(item).strip()]
            repo_root = _resolve_local_repo_root(repo_slug)
            if repo_root is None:
                continue
            if allowed_paths and not any(
                _path_hint_matches_owner_scope(requested, str(prefix or "").strip().lower()) for prefix in allowed_paths
            ):
                continue
            file_path = (repo_root / requested).resolve()
            try:
                file_path.relative_to(repo_root.resolve())
            except Exception:
                continue
            if not file_path.exists() or not file_path.is_file():
                continue
            try:
                with file_path.open("r", encoding="utf-8", errors="ignore") as handle:
                    return sum(1 for _ in handle)
            except OSError:
                continue
        return None

    def _merge_execution_plan_fields(*, current_plan: Dict[str, Any], engine_plan: Dict[str, Any]) -> Dict[str, Any]:
        merged = copy.deepcopy(current_plan if isinstance(current_plan, dict) else {})
        list_fields = (
            "proposed_work",
            "candidate_files",
            "implementation_steps",
            "file_operations",
            "test_operations",
            "validation_sequence",
            "preview_requirements",
            "risk_annotations",
            "rollback_notes",
            "affected_tests",
            "compatibility_constraints",
            "planning_checkpoints",
            "source_files",
            "destination_modules",
            "extraction_seams",
            "proposed_moves",
            "compatibility_shims",
            "route_update_implications",
            "ordered_migration_steps",
            "affected_routes",
            "ordered_extraction_sequence",
        )
        scalar_fields = ("planning_mode", "plan_kind", "confidence", "assumptions", "scaffold_plan")
        object_fields = ("execution_package",)
        always_fields = ("planner_state", "artifact_relevance")
        for field in scalar_fields:
            current_value = merged.get(field)
            incoming_value = engine_plan.get(field)
            if incoming_value in (None, "", [], {}):
                continue
            if field == "planning_mode":
                existing_mode = str(current_value or "").strip()
                incoming_mode = str(incoming_value or "").strip()
                # Preserve legacy deterministic/code_aware contract for existing callers;
                # expose explicit planner-mode taxonomy in a dedicated field.
                if incoming_mode == "decompose_existing_system":
                    merged[field] = incoming_mode
                elif existing_mode in {"deterministic", "code_aware"}:
                    merged["planner_mode"] = incoming_mode
                else:
                    merged[field] = incoming_mode
            elif field in {"plan_kind", "confidence"}:
                merged[field] = incoming_value
            elif not current_value:
                merged[field] = incoming_value
        for field in list_fields:
            current_value = merged.get(field) if isinstance(merged.get(field), list) else []
            incoming_value = engine_plan.get(field) if isinstance(engine_plan.get(field), list) else []
            if current_value:
                continue
            if incoming_value:
                merged[field] = incoming_value
        for field in always_fields:
            incoming_value = engine_plan.get(field)
            if incoming_value in (None, "", [], {}):
                continue
            merged[field] = incoming_value
        for field in object_fields:
            incoming_value = engine_plan.get(field)
            if not isinstance(incoming_value, dict) or not incoming_value:
                continue
            current_value = merged.get(field)
            if isinstance(current_value, dict) and current_value:
                continue
            merged[field] = incoming_value
        candidate_selected = engine_plan.get("selected_artifact_ids")
        if isinstance(candidate_selected, list):
            normalized_selected = [str(item).strip() for item in candidate_selected if str(item).strip()]
            existing_selected = merged.get("selected_artifact_ids") if isinstance(merged.get("selected_artifact_ids"), list) else []
            incoming_mode = str(engine_plan.get("planning_mode") or "").strip()
            if incoming_mode == "decompose_existing_system" and normalized_selected:
                merged["selected_artifact_ids"] = normalized_selected
            elif not existing_selected and normalized_selected:
                merged["selected_artifact_ids"] = normalized_selected
        return merged

    def _finalize_plan_payload(
        payload: Dict[str, Any],
        selected_members_for_plan: List[ApplicationArtifactMembership],
    ) -> Dict[str, Any]:
        planner_metadata_hints = _collect_decomposition_planner_hints(
            session_metadata=session.metadata_json if isinstance(session.metadata_json, dict) else {},
            analysis_metadata=session.analysis_json if isinstance(session.analysis_json, dict) else {},
        )
        planning_mode_classification, classification_reasons = _classify_solution_change_planning_mode(
            request_text=original_request,
            session_metadata=planner_metadata_hints,
        )
        if planning_mode_classification == "decompose_existing_system":
            finalized = copy.deepcopy(payload if isinstance(payload, dict) else {})
            finalized["planning_mode"] = "decompose_existing_system"
            finalized["planner_mode"] = "decompose_existing_system"
            finalized["planning_mode_source"] = "decomposition_classifier"
            finalized["planning_mode_reasons"] = classification_reasons
        else:
            finalized = _maybe_apply_code_aware_solution_planning(
                plan=payload,
                session=session,
                selected_members=selected_members_for_plan,
                force_code_aware_planning=force_code_aware_planning,
            )
            if str(finalized.get("planning_mode") or "").strip() in {"deterministic", "code_aware"}:
                finalized["planner_mode"] = "modify_existing_system"
                finalized["planning_mode_source"] = "modify_existing_system"
                finalized["planning_mode_reasons"] = classification_reasons
        engine_enriched = build_solution_change_execution_plan(
            request_text=original_request,
            base_plan=finalized,
            artifacts=_planner_artifact_inputs(),
            selected_artifact_ids=[str(member.artifact_id) for member in selected_members_for_plan],
            analysis=session.analysis_json if isinstance(session.analysis_json, dict) else {},
            planner_hints=planner_metadata_hints,
            line_count_lookup=lambda path: _line_count_lookup(
                path,
                candidate_members=selected_members_for_plan if selected_members_for_plan else memberships,
            ),
        )
        merged = _merge_execution_plan_fields(current_plan=finalized, engine_plan=engine_enriched)
        rewritten = _apply_refinement_rewrite_to_plan_payload(
            plan=merged,
            directives=plan_rewrite_directives,
            request_text=original_request,
        )
        return _apply_plan_prohibition_guardrails(
            plan=rewritten,
            request_text=original_request,
        )

    def _compact_objective(text: str) -> str:
        value = str(text or "").strip()
        if not value:
            return "Deliver the requested solution scope with a validated first iteration."
        first_line = re.split(r"[\n\.]", value, maxsplit=1)[0].strip()
        compact = first_line or value
        return compact[:220].rstrip()

    def _refinement_state(
        records: List[Dict[str, Any]],
        refinements: List[str],
    ) -> Dict[str, Any]:
        state: Dict[str, Any] = {
            "integration_v1": None,  # True/False/None
            "collaboration": None,  # "single" | "multi" | None
            "rich_text": False,
            "name": None,  # Optional display name override
            "ui_preferences": {},
            "features": [],
            "additional_considerations": [],
            "manual_constraints": [],
            "open_questions_remaining": set(),
            "has_explicit_open_questions": False,
            "resolved_assumptions": [],
            "constraints": [],
        }
        def _apply_normalized_updates(normalized: Dict[str, Any]) -> None:
            if not isinstance(normalized, dict):
                return
            if str(normalized.get("name") or "").strip():
                state["name"] = _clean_refinement_value(str(normalized.get("name") or ""))[:120]
            ui_prefs = normalized.get("ui_preferences") if isinstance(normalized.get("ui_preferences"), dict) else {}
            theme = str(ui_prefs.get("theme") or "").strip().lower()
            if theme in _HYBRID_REFINEMENT_THEME_VALUES:
                state["ui_preferences"]["theme"] = theme
            for item in normalized.get("features_add") if isinstance(normalized.get("features_add"), list) else []:
                feature_candidate = _clean_refinement_value(str(item or ""))
                if not feature_candidate:
                    continue
                feature_lower = feature_candidate.lower()
                if ("rich text" in feature_lower) or ("wysiwyg" in feature_lower):
                    state["rich_text"] = True
                else:
                    _append_unique_lowered(state["features"], feature_candidate)
            for item in normalized.get("constraints_add") if isinstance(normalized.get("constraints_add"), list) else []:
                _append_unique_lowered(state["manual_constraints"], _clean_refinement_value(str(item or "")))
            for item in normalized.get("additional_considerations_add") if isinstance(normalized.get("additional_considerations_add"), list) else []:
                _append_unique_lowered(state["additional_considerations"], _clean_refinement_value(str(item or "")))
            for row in normalized.get("resolved_answers") if isinstance(normalized.get("resolved_answers"), list) else []:
                if not isinstance(row, dict):
                    continue
                question_key = _normalize_question_key(row.get("question_key"))
                value = row.get("value")
                if question_key == "integration_v1":
                    if isinstance(value, bool):
                        state["integration_v1"] = value
                elif question_key == "collaboration_model":
                    token = str(value or "").strip().lower()
                    if token in {"single", "single_user", "single-user"}:
                        state["collaboration"] = "single"
                    elif token in {"multi", "multi_user", "multi-user"}:
                        state["collaboration"] = "multi"
                elif question_key == "rich_text_required":
                    if isinstance(value, bool):
                        state["rich_text"] = value
                elif question_key == "app_name":
                    candidate = _clean_refinement_value(str(value or ""))
                    if candidate:
                        state["name"] = candidate[:120]
                elif question_key == "ui_theme":
                    token = str(value or "").strip().lower()
                    if token in _HYBRID_REFINEMENT_THEME_VALUES:
                        state["ui_preferences"]["theme"] = token
            if "open_questions_remaining" in normalized and isinstance(normalized.get("open_questions_remaining"), list):
                state["has_explicit_open_questions"] = True
                state["open_questions_remaining"] = {
                    _normalize_question_key(item)
                    for item in normalized.get("open_questions_remaining")
                    if _normalize_question_key(item)
                }

        parsed_from_records = False
        for record in records:
            interpretation = record.get("interpretation")
            if isinstance(interpretation, dict):
                safe_interp, _errors = _validate_hybrid_refinement_envelope(interpretation)
                if safe_interp is not None:
                    _apply_normalized_updates(safe_interp.get("normalized_updates") if isinstance(safe_interp.get("normalized_updates"), dict) else {})
                    parsed_from_records = True
                    continue
            refinement = str(record.get("reply_text") or "").strip()
            if not refinement:
                continue
            parsed_from_records = True
            text = str(refinement or "").strip()
            lowered = text.lower()
            if not lowered:
                continue
            recognized = False

            name_match = re.search(r"\bname\s+the\s+application\s+(.+)$", text, re.IGNORECASE)
            if not name_match:
                name_match = re.search(r"\bcall\s+it\s+(.+)$", text, re.IGNORECASE)
            if name_match:
                candidate_name = _clean_refinement_value(name_match.group(1))
                if candidate_name:
                    state["name"] = candidate_name[:120]
                    recognized = True

            if (
                ("default theme to light" in lowered)
                or ("use light theme" in lowered)
                or ("use light mode" in lowered)
            ):
                state["ui_preferences"]["theme"] = "light"
                recognized = True
            elif (
                ("default theme to dark" in lowered)
                or ("use dark theme" in lowered)
                or ("use dark mode" in lowered)
            ):
                state["ui_preferences"]["theme"] = "dark"
                recognized = True

            if (
                ("no external integration" in lowered)
                or ("no external integrations" in lowered)
                or ("without external integration" in lowered)
                or ("without external integrations" in lowered)
            ):
                state["integration_v1"] = False
                recognized = True
            elif ("external integration" in lowered) or ("external integrations" in lowered):
                state["integration_v1"] = True
                recognized = True

            if ("single-user" in lowered) or ("single user" in lowered):
                state["collaboration"] = "single"
                recognized = True
            if (
                ("multi-user" in lowered)
                or ("multi user" in lowered)
                or ("collaboration" in lowered)
                or ("editor/reader" in lowered)
                or ("editor and reader" in lowered)
                or ("editor role" in lowered and "reader role" in lowered)
            ):
                state["collaboration"] = "multi"
                recognized = True

            if ("rich text" in lowered) or ("wysiwyg" in lowered) or ("editor support" in lowered):
                state["rich_text"] = True
                recognized = True

            feature_match = re.search(r"\b(?:add|include|support)\s+(.+)$", text, re.IGNORECASE)
            if feature_match:
                feature_candidate = _clean_refinement_value(feature_match.group(1))
                feature_lower = feature_candidate.lower()
                if feature_candidate:
                    if ("rich text" in feature_lower) or ("wysiwyg" in feature_lower):
                        state["rich_text"] = True
                        recognized = True
                    else:
                        _append_unique_lowered(state["features"], feature_candidate)
                        recognized = True

            if not recognized:
                _append_unique_lowered(state["additional_considerations"], _clean_refinement_value(text))

        if not parsed_from_records:
            for refinement in refinements:
                deterministic = _deterministic_refinement_interpretation(refinement)
                updates = deterministic.get("normalized_updates") if isinstance(deterministic.get("normalized_updates"), dict) else {}
                _apply_normalized_updates(updates)

        resolved_assumptions: List[str] = []
        constraints: List[str] = []
        additional_considerations: List[str] = []
        if state["integration_v1"] is False:
            resolved_assumptions.append("Resolved: v1 excludes external integrations.")
            constraints.append("Scope constraint: keep v1 self-contained with no external integrations.")
        elif state["integration_v1"] is True:
            resolved_assumptions.append("Resolved: v1 requires at least one external integration seam.")
            constraints.append("Scope constraint: define integration boundaries for v1.")

        if state["collaboration"] == "single":
            resolved_assumptions.append("Resolved: v1 targets a single-user workflow.")
            constraints.append("Design around single-user editing and retrieval flows.")
        elif state["collaboration"] == "multi":
            resolved_assumptions.append("Resolved: v1 supports multi-user collaboration with role boundaries.")
            constraints.append("Include role-aware collaboration (editor/reader) in the first iteration.")

        if state["rich_text"]:
            resolved_assumptions.append("Resolved: rich text editing is required in the first iteration.")
            constraints.append("Include rich text editor capabilities in the initial build slice.")

        if str((state.get("ui_preferences") or {}).get("theme") or "") in {"light", "dark"}:
            theme = str(state["ui_preferences"]["theme"])
            resolved_assumptions.append(f"Resolved UI default: use {theme} theme.")

        for feature in state["features"]:
            constraints.append(f"Feature scope: include {feature} in the initial plan.")
        for item in state["manual_constraints"]:
            constraints.append(f"Scope constraint: {item}")
        for item in state["additional_considerations"]:
            additional_considerations.append(f"Additional consideration: {item}")

        state["resolved_assumptions"] = resolved_assumptions
        state["constraints"] = constraints
        state["additional_considerations"] = additional_considerations
        return state

    plan_rewrite_directives = _extract_plan_rewrite_directives(response_records, user_refinements)
    refinement_state = _refinement_state(response_records, user_refinements)
    refinement_state["constraints"] = _sanitize_shared_contracts_for_refinement(
        [str(item).strip() for item in (refinement_state.get("constraints") or []) if str(item).strip()],
        directives=plan_rewrite_directives,
    )
    refinement_state["additional_considerations"] = _sanitize_shared_contracts_for_refinement(
        [str(item).strip() for item in (refinement_state.get("additional_considerations") or []) if str(item).strip()],
        directives=plan_rewrite_directives,
    )
    latest_draft_summary = ""
    for turn in reversed(planning_turns):
        if str(turn.actor or "") == "planner" and str(turn.kind or "") == "draft_plan":
            payload = turn.payload_json if isinstance(turn.payload_json, dict) else {}
            latest_draft_summary = str(payload.get("summary") or "").strip()
            if not latest_draft_summary:
                latest_draft_summary = str(payload.get("objective") or "").strip()
            break
    planner_objective_text = _compact_objective(original_request)
    planner_context_text = planner_objective_text
    if user_refinements:
        planner_context_text = (
            "User is refining a solution plan.\n"
            f"Original request: {original_request or 'n/a'}\n"
            + ("Resolved assumptions:\n" + "\n".join(f"- {item}" for item in refinement_state["resolved_assumptions"]) + "\n" if refinement_state["resolved_assumptions"] else "")
            + ("Refinement constraints:\n" + "\n".join(f"- {item}" for item in refinement_state["constraints"]) + "\n" if refinement_state["constraints"] else "")
        )
        if latest_draft_summary:
            planner_context_text += f"\nPrior draft summary: {latest_draft_summary}"

    def _is_default_change_session_title(title: str) -> bool:
        token = str(title or "").strip()
        return bool(re.match(r"^Change Session \d{4}-\d{2}-\d{2} \d{2}:\d{2}$", token))

    def _is_greenfield_initial_solution_plan() -> bool:
        if memberships:
            return False
        if SolutionChangeSession.objects.filter(application_id=session.application_id).exclude(id=session.id).exists():
            return False
        if Goal.objects.filter(application_id=session.application_id).exists():
            return False
        return True

    def _existing_solution_no_membership_plan(
        *,
        objective_text: str,
        plan_title_value: str,
        planner_objective_value: str,
        planner_context_value: str,
        suggested_workstreams: List[str],
    ) -> Dict[str, Any]:
        lowered = objective_text.lower()
        focuses_ui = any(token in lowered for token in {"ui", "ux", "layout", "width", "header", "panel", "screen", "view"})
        focuses_api = any(token in lowered for token in {"api", "endpoint", "contract", "schema", "backend", "service"})
        focuses_data = any(token in lowered for token in {"data", "model", "schema", "storage", "db", "database", "persistence"})

        implementation_steps: List[str] = []
        validation_steps: List[str] = []

        if focuses_ui:
            implementation_steps.extend(
                [
                    "Identify the affected shell/workbench surface and component boundaries for the requested layout/behavior change.",
                    "Update component/container layout constraints and styling to satisfy the requested UI behavior.",
                ]
            )
            validation_steps.extend(
                [
                    "Validate the updated UI behavior in the target workbench view with representative workspace data.",
                    "Verify desktop and narrow-width responsive behavior for the affected surface.",
                ]
            )
        if focuses_api:
            implementation_steps.extend(
                [
                    "Trace the API handlers/serializers touched by the request and scope contract-safe updates.",
                    "Apply the narrow API/validation changes required by the request and preserve backward compatibility.",
                ]
            )
            validation_steps.append("Run API-level regression checks for changed contracts and affected query paths.")
        if focuses_data:
            implementation_steps.extend(
                [
                    "Identify impacted persisted fields and data-shape assumptions for the requested behavior change.",
                    "Apply minimal data-model/repository updates required for the change while preserving current invariants.",
                ]
            )
            validation_steps.append("Validate read/write flows and migration safety for impacted data paths.")

        if not implementation_steps:
            implementation_steps.extend(
                [
                    "Locate the specific code paths that implement the requested behavior in the existing solution.",
                    "Apply a focused change that addresses the request without broad scaffold or bootstrap rework.",
                ]
            )
        if not validation_steps:
            validation_steps.extend(
                [
                    "Validate the requested behavior change through the affected end-user flow in the active workspace.",
                    "Run targeted regression checks around adjacent workflows touched by this change.",
                ]
            )

        validation_steps = [
            "Stage the planned changes for the selected artifacts.",
            "Prepare a preview environment to review the applied changes.",
            "Validate the changes, including running relevant tests.",
            *validation_steps,
        ]

        shared_contracts = [
            "Plan against the current solution baseline; do not introduce greenfield/bootstrap assumptions.",
            "Preserve existing cross-artifact contracts unless the request explicitly requires contract changes.",
        ]
        shared_contracts.extend(refinement_state["resolved_assumptions"])
        shared_contracts.extend(refinement_state["constraints"])
        shared_contracts.extend(refinement_state["additional_considerations"][:2])

        return _finalize_plan_payload({
            "session_id": str(session.id),
            "application_id": str(session.application_id),
            "title": plan_title_value,
            "request_text": original_request,
            "planner_objective_text": planner_objective_value,
            "planner_context_text": planner_context_value,
            "user_refinements": user_refinements,
            "generated_at": timezone.now().isoformat(),
            "selected_artifact_ids": [],
            "confirmed_workstreams": confirmed_workstreams,
            "suggested_workstreams": suggested_workstreams,
            "per_artifact_work": [],
            "shared_contracts": shared_contracts,
            "open_questions": [],
            "validation_plan": validation_steps,
            "preview_implications": [
                "Use preview to verify the targeted behavior change against the existing solution baseline.",
            ],
            "implementation_steps": implementation_steps,
        }, [])

    analysis = session.analysis_json if isinstance(session.analysis_json, dict) else {}
    confirmed_workstreams = _solution_change_session_confirmed_workstreams(session)
    suggested_workstreams = [
        str(item or "").strip()
        for item in (analysis.get("suggested_workstreams") if isinstance(analysis.get("suggested_workstreams"), list) else [])
        if str(item or "").strip()
    ] or _infer_solution_workstreams_from_request(original_request)
    effective_workstreams = confirmed_workstreams or suggested_workstreams

    selected_ids = set(_solution_change_session_selected_artifact_ids(session))
    selected_members = [member for member in memberships if str(member.artifact_id) in selected_ids]
    if not selected_members and memberships:
        inferred_rows = analysis.get("impacted_artifacts") if isinstance(analysis.get("impacted_artifacts"), list) else []
        if not inferred_rows:
            inferred = _analyze_solution_impacted_artifacts(
                application=session.application,
                request_text=original_request,
                memberships=memberships,
            )
            inferred_rows = inferred.get("impacted_artifacts") if isinstance(inferred.get("impacted_artifacts"), list) else []
        confident_ids: List[str] = []
        for row in inferred_rows:
            if not isinstance(row, dict):
                continue
            artifact_id = str(row.get("artifact_id") or "").strip()
            score = int(row.get("score") or 0)
            if artifact_id and score >= 3 and artifact_id not in confident_ids:
                confident_ids.append(artifact_id)
        if not confident_ids and effective_workstreams:
            for member in memberships:
                role = str(member.role or "")
                if _artifact_role_matches_workstreams(role, effective_workstreams):
                    artifact_id = str(member.artifact_id)
                    if artifact_id not in confident_ids:
                        confident_ids.append(artifact_id)
        selected_members = [member for member in memberships if str(member.artifact_id) in set(confident_ids)]

    fallback_title = _compact_objective(original_request)[:120] if _is_default_change_session_title(session.title) else session.title
    plan_title = str(refinement_state.get("name") or fallback_title or "").strip() or fallback_title
    if not selected_members:
        if confirmed_workstreams or not _is_greenfield_initial_solution_plan():
            return _finalize_plan_payload(_existing_solution_no_membership_plan(
                objective_text=_compact_objective(original_request),
                plan_title_value=plan_title,
                planner_objective_value=planner_objective_text,
                planner_context_value=planner_context_text,
                suggested_workstreams=effective_workstreams,
            ), [])
        objective_text = _compact_objective(original_request)
        first_focus = "Start by shaping the primary data model and first user-facing workflow."
        objective_lower = objective_text.lower()
        if any(token in objective_lower for token in {"api", "integration", "sync", "pipeline", "import"}):
            first_focus = "Start by defining backend contracts and integration seams for the first vertical slice."
        elif any(token in objective_lower for token in {"ui", "ux", "screen", "dashboard", "workflow"}):
            first_focus = "Start by designing the first end-to-end user workflow and its supporting API contract."
        initial_workstreams = [
            "Core domain model and storage",
            "Primary user workflow surface",
            "Basic API/service contract",
        ]
        if refinement_state["rich_text"]:
            initial_workstreams[1] = "Primary user workflow surface with rich text editing"
        assumptions: List[str] = [
            "Assumption: initial release targets internal authenticated users.",
        ]
        assumptions.extend(refinement_state["resolved_assumptions"])
        open_questions: List[str] = []
        if refinement_state.get("has_explicit_open_questions"):
            remaining = refinement_state.get("open_questions_remaining", set())
            if "collaboration_model" in remaining:
                open_questions.append("Collaboration model for v1 is still unresolved.")
            if "integration_v1" in remaining:
                open_questions.append("External integration scope for v1 is still unresolved.")
            assumptions.extend([f"Open question: {question}" for question in open_questions])
        assumptions.extend(refinement_state["constraints"][:2])
        assumptions.extend(refinement_state["additional_considerations"][:2])
        return _finalize_plan_payload({
            "session_id": str(session.id),
            "application_id": str(session.application_id),
            "title": plan_title,
            "request_text": original_request,
            "planner_objective_text": planner_objective_text,
            "planner_context_text": planner_context_text,
            "user_refinements": user_refinements,
            "generated_at": timezone.now().isoformat(),
            "selected_artifact_ids": [],
            "confirmed_workstreams": confirmed_workstreams,
            "suggested_workstreams": effective_workstreams,
            "per_artifact_work": [],
            "shared_contracts": assumptions,
            "open_questions": open_questions,
            "validation_plan": [
                first_focus,
                "Validate the first vertical slice end-to-end before broadening scope.",
            ],
            "preview_implications": [
                "Use preview to validate the first vertical slice with representative data.",
            ],
        }, [])
    per_artifact: List[Dict[str, Any]] = []
    for member in selected_members:
        artifact = member.artifact
        role = member.role
        focus = "maintain compatibility with adjacent artifacts"
        if role == "primary_ui":
            focus = "update shell views and interaction flows for the requested change"
        elif role == "primary_api":
            focus = "extend API contracts and validation paths required by the change"
        elif role == "worker":
            focus = "update worker orchestration and async execution paths"
        elif role == "integration_adapter":
            focus = "adjust integration adapter contracts and transformation seams"
        per_artifact.append(
            {
                "artifact_id": str(artifact.id),
                "artifact_title": artifact.title,
                "artifact_type": artifact.type.slug if artifact.type_id else "",
                "role": role,
                "planned_work": [
                    focus,
                    "add/adjust tests for changed behavior",
                    "document any contract changes for consuming artifacts",
                ],
            }
        )
        if refinement_state["rich_text"] and role == "primary_ui":
            per_artifact[-1]["planned_work"].append("support rich text editing workflows in the first user-facing slice")
        if refinement_state["integration_v1"] is False:
            per_artifact[-1]["planned_work"].append("defer external integrations from v1 implementation scope")
        if refinement_state["collaboration"] == "multi":
            per_artifact[-1]["planned_work"].append("introduce role-aware collaboration semantics (editor/reader)")
        if refinement_state["collaboration"] == "single":
            per_artifact[-1]["planned_work"].append("optimize flows for single-user v1 operation")
        theme = str((refinement_state.get("ui_preferences") or {}).get("theme") or "").strip()
        if theme and role == "primary_ui":
            per_artifact[-1]["planned_work"].append(f"set default UI theme to {theme}")
        for feature in refinement_state.get("features") or []:
            per_artifact[-1]["planned_work"].append(f"add support for {feature}")
    shared_contracts: List[str] = []
    open_questions: List[str] = []
    validation_plan = [
        "Stage the planned changes for the selected artifacts.",
        "Prepare a preview environment to review the applied changes.",
        "Validate the changes, including running relevant tests.",
    ]
    selected_roles = {str(member.role or "").strip() for member in selected_members}
    selected_artifact_count = len(selected_members)
    lowered_request = original_request.lower()
    api_workstream_active = ("api" in effective_workstreams) or bool(selected_roles.intersection({"primary_api", "integration_adapter"}))
    mentions_contract = any(token in lowered_request for token in {"api", "endpoint", "schema", "contract", "payload", "response"})
    mentions_exchange = any(
        token in lowered_request
        for token in {"event", "payload", "message", "queue", "stream", "webhook", "integration", "adapter", "exchange"}
    )
    if selected_artifact_count > 1 and api_workstream_active and mentions_contract:
        shared_contracts.append("Maintain backward-compatible API contracts across selected artifacts.")
    if selected_artifact_count > 1 and mentions_exchange:
        shared_contracts.append("Validate payload/data-shape compatibility where selected artifacts exchange runtime data.")
    shared_contracts.extend(refinement_state["resolved_assumptions"])
    if refinement_state.get("has_explicit_open_questions"):
        remaining = refinement_state.get("open_questions_remaining", set())
        if "collaboration_model" in remaining:
            open_questions.append("Collaboration model for v1 is still unresolved.")
        if "integration_v1" in remaining:
            open_questions.append("External integration scope for v1 is still unresolved.")
    shared_contracts.extend([f"Open question: {question}" for question in open_questions])
    shared_contracts.extend(refinement_state["constraints"])
    shared_contracts.extend(refinement_state["additional_considerations"][:2])
    if refinement_state["constraints"]:
        validation_plan.insert(0, "Validate that revision constraints are reflected in scope and acceptance checks.")
    return _finalize_plan_payload({
        "session_id": str(session.id),
        "application_id": str(session.application_id),
        "title": plan_title,
        "request_text": original_request,
        "planner_objective_text": planner_objective_text,
        "planner_context_text": planner_context_text,
        "user_refinements": user_refinements,
        "generated_at": timezone.now().isoformat(),
        "selected_artifact_ids": [str(member.artifact_id) for member in selected_members],
        "confirmed_workstreams": confirmed_workstreams,
        "suggested_workstreams": effective_workstreams,
        "per_artifact_work": per_artifact,
        "shared_contracts": shared_contracts,
        "open_questions": open_questions,
        "validation_plan": validation_plan,
        "preview_implications": [
            "Preview instance should include all changed artifacts in one sibling deploy set",
            "Cross-artifact regression checks are required before promotion",
        ],
    }, selected_members)


def _serialize_solution_change_session(
    session: SolutionChangeSession,
    *,
    memberships_by_artifact_id: Optional[Dict[str, ApplicationArtifactMembership]] = None,
) -> Dict[str, Any]:
    memberships_by_artifact_id = memberships_by_artifact_id or {}
    selected_ids = _solution_change_session_selected_artifact_ids(session)
    selected_artifacts: List[Dict[str, Any]] = []
    for artifact_id in selected_ids:
        member = memberships_by_artifact_id.get(artifact_id)
        if not member:
            continue
        selected_artifacts.append(
            {
                "artifact_id": artifact_id,
                "artifact_title": member.artifact.title,
                "artifact_type": member.artifact.type.slug if member.artifact.type_id else "",
                "role": member.role,
            }
        )
    planning_state = _solution_planning_state(session)
    commit_count = SolutionChangeSessionRepoCommit.objects.filter(solution_change_session=session).count()
    requires_commit_provenance = _solution_change_session_requires_commit_provenance(session)
    promote_eligibility = _solution_change_session_promote_eligibility(session=session, application=session.application)
    evidence_ref = _latest_solution_change_session_promotion_evidence_ref(session)
    return {
        "id": str(session.id),
        "workspace_id": str(session.workspace_id),
        "application_id": str(session.application_id),
        "title": session.title,
        "request_text": session.request_text or "",
        "status": session.status,
        "created_by": str(session.created_by_id) if session.created_by_id else None,
        "analysis": session.analysis_json if isinstance(session.analysis_json, dict) else {},
        "selected_artifact_ids": selected_ids,
        "confirmed_workstreams": _solution_change_session_confirmed_workstreams(session),
        "selected_artifacts": selected_artifacts,
        "plan": session.plan_json if isinstance(session.plan_json, dict) else {},
        "execution_status": session.execution_status or "not_started",
        "staged_changes": session.staged_changes_json if isinstance(session.staged_changes_json, dict) else {},
        "preview": session.preview_json if isinstance(session.preview_json, dict) else {},
        "validation": session.validation_json if isinstance(session.validation_json, dict) else {},
        "metadata": session.metadata_json if isinstance(session.metadata_json, dict) else {},
        "repo_commit_count": int(commit_count),
        "requires_commit_provenance": bool(requires_commit_provenance),
        "promote_eligibility": promote_eligibility,
        "evidence_ref": evidence_ref,
        "planning": planning_state,
        "created_at": session.created_at,
        "updated_at": session.updated_at,
    }


def _serialize_solution_change_session_repo_commit(commit: SolutionChangeSessionRepoCommit) -> Dict[str, Any]:
    return {
        "id": str(commit.id),
        "workspace_id": str(commit.workspace_id),
        "solution_change_session_id": str(commit.solution_change_session_id),
        "repository_slug": str(commit.repository_slug or "").strip(),
        "branch": str(commit.branch or "").strip(),
        "commit_sha": str(commit.commit_sha or "").strip(),
        "changed_files": commit.changed_files_json if isinstance(commit.changed_files_json, list) else [],
        "validation_status": str(commit.validation_status or "unknown").strip() or "unknown",
        "created_at": commit.created_at,
        "updated_at": commit.updated_at,
    }


def _solution_session_iteration_linkage(session: SolutionChangeSession) -> Dict[str, Any]:
    metadata = session.metadata_json if isinstance(session.metadata_json, dict) else {}
    linkage = metadata.get("iteration_linkage")
    return linkage if isinstance(linkage, dict) else {}


def _persist_solution_session_iteration_linkage(
    *,
    session: SolutionChangeSession,
    linkage_updates: Dict[str, Any],
    source: str,
) -> None:
    metadata = session.metadata_json if isinstance(session.metadata_json, dict) else {}
    existing = metadata.get("iteration_linkage") if isinstance(metadata.get("iteration_linkage"), dict) else {}
    merged: Dict[str, Any] = {**existing, **(linkage_updates if isinstance(linkage_updates, dict) else {})}
    merged["source"] = str(source or "unknown").strip() or "unknown"
    merged["updated_at"] = timezone.now().isoformat()
    metadata["iteration_linkage"] = merged
    session.metadata_json = metadata
    session.save(update_fields=["metadata_json", "updated_at"])


def _persist_solution_session_activation_linkage(
    *,
    session: SolutionChangeSession,
    binding: Optional[SolutionRuntimeBinding],
    activation_payload: Dict[str, Any],
) -> None:
    if not isinstance(activation_payload, dict):
        return
    linkage_updates: Dict[str, Any] = {
        "workspace_id": str(session.workspace_id),
        "application_id": str(session.application_id),
        "session_id": str(session.id),
        "status": str(activation_payload.get("status") or "").strip().lower(),
        "activation_mode": str(activation_payload.get("policy_source") or "reconstructed"),
        "revision_anchor": activation_payload.get("revision_anchor") if isinstance(activation_payload.get("revision_anchor"), dict) else {},
        "activation": activation_payload.get("activation") if isinstance(activation_payload.get("activation"), dict) else {},
        "runtime_target": activation_payload.get("runtime_target") if isinstance(activation_payload.get("runtime_target"), dict) else {},
        "runtime_instance": activation_payload.get("runtime_instance") if isinstance(activation_payload.get("runtime_instance"), dict) else {},
    }
    if binding is not None:
        linkage_updates["runtime_binding_id"] = str(binding.id)
    _persist_solution_session_iteration_linkage(
        session=session,
        linkage_updates=linkage_updates,
        source="application_activate",
    )


def _process_solution_change_session_reply(
    *,
    session: SolutionChangeSession,
    application: Application,
    identity: UserIdentity,
    reply_text: str,
    force_planner_fallback: bool,
    response_kind: str = "response",
    source_turn_id: str = "",
    include_iteration_linkage: bool = False,
    prompt_response_metadata: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    interpretation = _interpret_solution_refinement(
        session=session,
        reply_text=reply_text,
        force_planner_fallback=force_planner_fallback,
    )
    interpretation_type = str(interpretation.get("result_type") or "cannot_interpret")
    payload: Dict[str, Any] = {
        "reply_text": reply_text,
        "response_kind": response_kind,
        "source_turn_id": source_turn_id or None,
        "interpretation": interpretation,
        "use_planner_interpretation": force_planner_fallback,
    }
    if isinstance(prompt_response_metadata, dict) and prompt_response_metadata:
        payload["metadata"] = prompt_response_metadata
    if include_iteration_linkage:
        payload["iteration_linkage"] = _solution_session_iteration_linkage(session)
    _append_solution_planning_turn(
        session=session,
        actor="user",
        kind="response",
        payload=payload,
        created_by=identity,
    )
    memberships = list(
        ApplicationArtifactMembership.objects.filter(application=application)
        .select_related("artifact", "artifact__type")
        .order_by("sort_order", "created_at")
    )
    if interpretation_type in {"clarification_request", "cannot_interpret"}:
        planner_question = str(interpretation.get("planner_message") or "").strip()
        if not planner_question:
            planner_question = (
                "I could not safely interpret that refinement. Please clarify the request or provide a more specific constraint."
                if interpretation_type == "cannot_interpret"
                else "I need one clarification before I can revise the draft plan."
            )
        _append_solution_planning_turn(
            session=session,
            actor="planner",
            kind="question",
            payload={
                "question": planner_question,
                "reason": "cannot_interpret" if interpretation_type == "cannot_interpret" else "clarification_request",
                "interpretation": interpretation,
            },
        )
    else:
        _advance_solution_planning_after_user_response(session=session, memberships=memberships)
    memberships_by_artifact_id = {str(member.artifact_id): member for member in memberships}
    return {
        "recorded": True,
        "session": _serialize_solution_change_session(session, memberships_by_artifact_id=memberships_by_artifact_id),
    }


