def _prepare_solution_change_preview(*, session: SolutionChangeSession) -> Dict[str, Any]:
    staged = session.staged_changes_json if isinstance(session.staged_changes_json, dict) else {}
    artifact_states = staged.get("artifact_states") if isinstance(staged.get("artifact_states"), list) else []
    workspace_id = str(session.workspace_id)
    application_id = str(session.application_id)
    now_iso = timezone.now().isoformat()
    local_public_base_url = str(os.getenv("XYN_PUBLIC_BASE_URL", "http://localhost") or "http://localhost").strip().rstrip("/")
    local_compose_project = str(os.getenv("XYN_LOCAL_COMPOSE_PROJECT", "xyn-local") or "xyn-local").strip() or "xyn-local"

    def _session_preview_candidate_artifact_ids() -> List[str]:
        selected_ids = [str(item).strip() for item in (staged.get("selected_artifact_ids") or []) if str(item).strip()]
        if selected_ids:
            return selected_ids
        inferred: List[str] = []
        for row in artifact_states:
            if not isinstance(row, dict):
                continue
            artifact_id = str(row.get("artifact_id") or "").strip()
            if artifact_id and artifact_id not in inferred:
                inferred.append(artifact_id)
        return inferred

    def _session_preview_should_provision_isolated_runtime(*, artifact_ids: List[str]) -> bool:
        if not artifact_ids:
            return False
        execution_runs = staged.get("execution_runs") if isinstance(staged.get("execution_runs"), list) else []
        has_stage_execution_evidence = bool(execution_runs) or bool(staged.get("dev_task_ids"))
        if not has_stage_execution_evidence:
            return False
        artifacts = list(Artifact.objects.filter(id__in=artifact_ids))
        if not artifacts:
            return False
        for artifact in artifacts:
            ownership = resolve_artifact_ownership(artifact)
            edit_mode = str(ownership.get("edit_mode") or "").strip().lower()
            if edit_mode == "repo_backed":
                return True
        return False

    def _provision_session_preview_environment() -> Dict[str, Any]:
        started_at = timezone.now().isoformat()
        session_token = str(session.id).replace("-", "")[:8]
        if not session_token:
            return {
                "attempted": False,
                "supported": False,
                "status": "reused",
                "reason": "session_id_unavailable",
                "started_at": started_at,
                "completed_at": timezone.now().isoformat(),
            }
        project_name = f"preview-{session_token}"
        ui_host = f"xyn-preview-{session_token}.localhost"
        api_host = f"api.xyn-preview-{session_token}.localhost"
        payload = {
            "name": project_name,
            "workspace_slug": str(getattr(session.workspace, "slug", "") or "").strip(),
            "ui_host": ui_host,
            "api_host": api_host,
        }
        env_mode = str(os.getenv("XYN_ENV", "") or "").strip().lower()
        if env_mode in {"local", "dev", ""}:
            payload["prefer_local_images"] = True
            payload["prefer_local_sources"] = True
        try:
            response = _seed_api_request(
                method="POST",
                path="/api/v1/provision/local-instance",
                payload=payload,
                timeout=180,
            )
        except requests.RequestException as exc:
            return {
                "attempted": True,
                "supported": True,
                "status": "failed",
                "reason": "session_preview_provision_unreachable",
                "details": exc.__class__.__name__,
                "session_preview_project": f"xyn-{project_name}",
                "started_at": started_at,
                "completed_at": timezone.now().isoformat(),
            }
        content_type = str(response.headers.get("content-type") or "").lower()
        if "application/json" not in content_type:
            return {
                "attempted": True,
                "supported": True,
                "status": "failed",
                "reason": "session_preview_provision_invalid_response",
                "details": response.text[:300],
                "session_preview_project": f"xyn-{project_name}",
                "started_at": started_at,
                "completed_at": timezone.now().isoformat(),
            }
        try:
            provision_payload = response.json() if response.content else {}
        except ValueError:
            provision_payload = {}
        if response.status_code >= 400:
            return {
                "attempted": True,
                "supported": True,
                "status": "failed",
                "reason": "session_preview_provision_failed",
                "details": str((provision_payload or {}).get("detail") or (provision_payload or {}).get("error") or response.text[:300]),
                "session_preview_project": f"xyn-{project_name}",
                "provision_status": str((provision_payload or {}).get("status") or "").strip().lower(),
                "started_at": started_at,
                "completed_at": timezone.now().isoformat(),
            }
        ui_url = str((provision_payload or {}).get("ui_url") or "").strip()
        api_url = str((provision_payload or {}).get("api_url") or "").strip()
        compose_project = str((provision_payload or {}).get("compose_project") or "").strip() or f"xyn-{project_name}"
        provision_status = str((provision_payload or {}).get("status") or "").strip().lower()
        if not ui_url:
            return {
                "attempted": True,
                "supported": True,
                "status": "failed",
                "reason": "session_preview_missing_ui_url",
                "details": "Provisioning response did not include a UI URL.",
                "compose_project": compose_project,
                "provision_status": provision_status,
                "started_at": started_at,
                "completed_at": timezone.now().isoformat(),
            }
        return {
            "attempted": True,
            "supported": True,
            "status": "newly_built_for_session",
            "reason": "session_preview_environment_created",
            "details": "",
            "compose_project": compose_project,
            "ui_url": ui_url,
            "api_url": api_url,
            "provision_status": provision_status,
            "session_preview_project": f"xyn-{project_name}",
            "started_at": started_at,
            "completed_at": timezone.now().isoformat(),
        }

    def _platform_preview_runtime_fallback(artifact: Artifact) -> Dict[str, Any]:
        slug = str(_artifact_slug(artifact) or "").strip()
        if slug not in {"core.workbench", "xyn-ui", "xyn-api"}:
            return {}
        if str(os.getenv("XYN_ENV", "") or "").strip().lower() not in {"local", "dev"}:
            return {}
        if not local_public_base_url:
            return {}
        return {
            "runtime_owner": "primary",
            "runtime_base_url": local_public_base_url,
            "public_app_url": local_public_base_url,
            "compose_project": local_compose_project,
            "runtime_target_id": "",
            "app_container_name": "",
            "source_build_job_id": "",
        }

    def _probe_runtime(base_url: str) -> Dict[str, Any]:
        probe_paths = ["/healthz", "/health", "/xyn/api/health"]
        last_error = ""
        for probe_path in probe_paths:
            try:
                response = _runtime_target_request(
                    base_url=base_url,
                    method="GET",
                    path=probe_path,
                    timeout=8,
                )
                return {
                    "ok": response.status_code < 400,
                    "status_code": int(response.status_code),
                    "path": probe_path,
                }
            except Exception as exc:
                last_error = str(exc)
        return {
            "ok": False,
            "status_code": 0,
            "path": probe_paths[-1],
            "error": last_error,
        }

    def _run_command(cmd: List[str], *, timeout_seconds: int = 90) -> Tuple[int, str, str]:
        try:
            proc = subprocess.run(
                cmd,
                text=True,
                capture_output=True,
                check=False,
                timeout=timeout_seconds,
            )
        except subprocess.TimeoutExpired as exc:
            stdout = str(exc.stdout or "").strip()
            stderr = str(exc.stderr or "").strip()
            return 124, stdout, stderr or f"command timed out after {timeout_seconds}s"
        except Exception as exc:  # pragma: no cover - defensive
            return 1, "", str(exc)
        return int(proc.returncode or 0), str(proc.stdout or "").strip(), str(proc.stderr or "").strip()

    def _launch_preview_for_session(
        *,
        artifact_rows: List[Dict[str, Any]],
        compose_projects: set[str],
    ) -> Dict[str, Any]:
        launched_at = timezone.now().isoformat()
        if len(compose_projects) != 1:
            return {
                "attempted": False,
                "supported": False,
                "status": "reused",
                "reason": "multiple_compose_projects",
                "started_at": launched_at,
                "completed_at": timezone.now().isoformat(),
            }
        containers: List[str] = []
        runtime_target_ids: List[str] = []
        for item in artifact_rows:
            if not isinstance(item, dict):
                continue
            container_name = str(item.get("app_container_name") or "").strip()
            if container_name and container_name not in containers:
                containers.append(container_name)
            runtime_target_id = str(item.get("runtime_target_id") or "").strip()
            if runtime_target_id and runtime_target_id not in runtime_target_ids:
                runtime_target_ids.append(runtime_target_id)
        if not containers:
            return {
                "attempted": False,
                "supported": False,
                "status": "reused",
                "reason": "missing_app_container_bindings",
                "runtime_target_ids": runtime_target_ids,
                "started_at": launched_at,
                "completed_at": timezone.now().isoformat(),
            }
        docker_probe_code, _docker_probe_out, docker_probe_err = _run_command(["docker", "version", "--format", "{{.Server.Version}}"])
        if docker_probe_code != 0:
            return {
                "attempted": False,
                "supported": False,
                "status": "reused",
                "reason": "docker_unavailable",
                "details": docker_probe_err or "docker CLI unavailable",
                "runtime_target_ids": runtime_target_ids,
                "started_at": launched_at,
                "completed_at": timezone.now().isoformat(),
            }
        commands: List[Dict[str, Any]] = []
        for container_name in containers:
            code, out, err = _run_command(["docker", "restart", container_name], timeout_seconds=120)
            commands.append(
                {
                    "container": container_name,
                    "command": ["docker", "restart", container_name],
                    "status_code": code,
                    "stdout": out,
                    "stderr": err,
                }
            )
            if code != 0:
                return {
                    "attempted": True,
                    "supported": True,
                    "status": "failed",
                    "reason": "docker_restart_failed",
                    "details": err or out or f"failed to restart {container_name}",
                    "launched_containers": containers,
                    "runtime_target_ids": runtime_target_ids,
                    "command_results": commands,
                    "started_at": launched_at,
                    "completed_at": timezone.now().isoformat(),
                }
        return {
            "attempted": True,
            "supported": True,
            "status": "succeeded",
            "launched_containers": containers,
            "runtime_target_ids": runtime_target_ids,
            "command_results": commands,
            "started_at": launched_at,
            "completed_at": timezone.now().isoformat(),
        }

    selected_artifact_ids_for_preview = _session_preview_candidate_artifact_ids()
    isolated_session_preview_requested = _session_preview_should_provision_isolated_runtime(
        artifact_ids=selected_artifact_ids_for_preview
    )
    session_preview_runtime: Dict[str, Any] = {}
    session_preview_fallback_reason = ""
    if isolated_session_preview_requested:
        session_preview_runtime = _provision_session_preview_environment()
        provision_status = str(session_preview_runtime.get("status") or "").strip().lower()
        if provision_status != "newly_built_for_session":
            if provision_status == "failed":
                # Keep failed provisioning evidence and surface an explicit preview failure
                # instead of silently reusing a stale runtime target.
                session_preview_fallback_reason = ""
            else:
                session_preview_fallback_reason = str(
                    session_preview_runtime.get("reason") or "session_preview_environment_unavailable"
                ).strip() or "session_preview_environment_unavailable"
                session_preview_runtime = {}

    artifact_rows: List[Dict[str, Any]] = []
    selected_artifact_ids: List[str] = []
    compose_projects: set[str] = set()
    all_bound = True
    for row in artifact_states:
        if not isinstance(row, dict):
            continue
        artifact_id = str(row.get("artifact_id") or "").strip()
        if not artifact_id:
            continue
        selected_artifact_ids.append(artifact_id)
        artifact = Artifact.objects.filter(id=artifact_id).first()
        if artifact is None:
            all_bound = False
            artifact_rows.append(
                {
                    "artifact_id": artifact_id,
                    "status": "failed",
                    "reason": "artifact_not_found",
                }
            )
            continue
        app_slug = _artifact_runtime_app_slug(artifact)
        if not app_slug:
            all_bound = False
            artifact_rows.append(
                {
                    "artifact_id": artifact_id,
                    "artifact_title": artifact.title,
                    "artifact_slug": artifact.slug,
                    "status": "failed",
                    "reason": "preview_app_slug_unresolved",
                }
            )
            continue
        runtime_record = _workspace_runtime_target(session.workspace, app_slug)
        runtime_target = runtime_record.get("runtime_target") if isinstance(runtime_record, dict) else {}
        runtime_instance = runtime_record.get("instance") if isinstance(runtime_record, dict) else None
        runtime_base_url = str(runtime_target.get("runtime_base_url") or "").strip()
        public_app_url = str(runtime_target.get("public_app_url") or "").strip()
        compose_project = str(runtime_target.get("compose_project") or "").strip()
        fallback_runtime = {}
        if session_preview_runtime:
            public_app_url = str(session_preview_runtime.get("ui_url") or "").strip()
            runtime_base_url = str(session_preview_runtime.get("api_url") or public_app_url).strip()
            compose_project = str(session_preview_runtime.get("compose_project") or "").strip()
        elif not runtime_base_url or not compose_project:
            fallback_runtime = _platform_preview_runtime_fallback(artifact)
            if fallback_runtime:
                runtime_base_url = str(fallback_runtime.get("runtime_base_url") or "").strip()
                public_app_url = str(fallback_runtime.get("public_app_url") or "").strip()
                compose_project = str(fallback_runtime.get("compose_project") or "").strip()
        if not runtime_base_url or not compose_project:
            all_bound = False
            artifact_rows.append(
                {
                    "artifact_id": artifact_id,
                    "artifact_title": artifact.title,
                    "artifact_slug": artifact.slug,
                    "app_slug": app_slug,
                    "status": "failed",
                    "reason": "runtime_target_missing",
                }
            )
            continue
        probe = (
            {
                "ok": True,
                "status_code": 200,
                "path": "session_preview_environment_created",
            }
            if session_preview_runtime
            else {
                "ok": True,
                "status_code": 200,
                "path": "local_platform_runtime_fallback",
            }
            if fallback_runtime
            else _probe_runtime(runtime_base_url)
        )
        if not probe.get("ok"):
            all_bound = False
        compose_projects.add(compose_project)
        artifact_rows.append(
            {
                "artifact_id": artifact_id,
                "artifact_title": artifact.title,
                "artifact_slug": artifact.slug,
                "app_slug": app_slug,
                "status": "ready" if probe.get("ok") else "failed",
                "runtime_owner": str(
                    session_preview_runtime.get("runtime_owner")
                    or runtime_target.get("runtime_owner")
                    or fallback_runtime.get("runtime_owner")
                    or "sibling"
                ),
                "runtime_base_url": runtime_base_url,
                "public_app_url": public_app_url,
                "compose_project": compose_project,
                "runtime_target_id": str(
                    getattr(runtime_instance, "id", "")
                    or fallback_runtime.get("runtime_target_id")
                    or ""
                ).strip(),
                "app_container_name": str(
                    runtime_target.get("app_container_name")
                    or fallback_runtime.get("app_container_name")
                    or ""
                ).strip(),
                "source_build_job_id": str(
                    session_preview_runtime.get("source_build_job_id")
                    or runtime_target.get("source_build_job_id")
                    or fallback_runtime.get("source_build_job_id")
                    or ""
                ).strip(),
                "probe": probe,
            }
        )

    single_preview_environment = len(compose_projects) == 1
    if not single_preview_environment:
        all_bound = False

    preview_urls: List[str] = []
    for artifact_row in artifact_rows:
        if not isinstance(artifact_row, dict):
            continue
        url = str(artifact_row.get("public_app_url") or "").strip()
        if url and url not in preview_urls:
            preview_urls.append(url)

    session_build = (
        dict(session_preview_runtime)
        if session_preview_runtime
        else _launch_preview_for_session(artifact_rows=artifact_rows, compose_projects=compose_projects)
    )
    if not session_preview_runtime and session_preview_fallback_reason:
        session_build = dict(session_build)
        session_build["fallback_reason"] = session_preview_fallback_reason
    build_status = str(session_build.get("status") or "").strip().lower()
    built_for_session = bool(session_build.get("attempted")) and build_status in {"succeeded", "newly_built_for_session"}
    reused_existing_runtime = not built_for_session
    if build_status == "failed":
        for artifact_row in artifact_rows:
            if not isinstance(artifact_row, dict):
                continue
            runtime_base_url = str(artifact_row.get("runtime_base_url") or "").strip()
            artifact_row["probe"] = _probe_runtime(runtime_base_url) if runtime_base_url else {"ok": False, "status_code": 0, "path": "/health"}
            artifact_row["status"] = "ready" if bool((artifact_row.get("probe") or {}).get("ok")) else "failed"
    status = "ready" if all_bound and bool(preview_urls) and build_status != "failed" else "failed"
    preview_payload: Dict[str, Any] = {
        "preview_id": str(uuid.uuid4()),
        "status": status,
        "mode": "coordinated_multi_artifact_preview",
        "prepared_at": now_iso,
        "newly_built_for_session": built_for_session,
        "reused_existing_runtime": reused_existing_runtime,
        "isolated_session_preview_requested": isolated_session_preview_requested,
        "selected_artifact_ids": selected_artifact_ids,
        "artifact_count": len(selected_artifact_ids),
        "artifacts": artifact_rows,
        "preview_urls": preview_urls,
        "primary_url": preview_urls[0] if preview_urls else "",
        "compose_projects": sorted(compose_projects),
        "single_preview_environment": single_preview_environment,
        "session_build": session_build,
        "build_deploy_evidence": {
            "runtime_owner": "sibling",
            "source_build_job_ids": sorted(
                {
                    str(item.get("source_build_job_id") or "").strip()
                    for item in artifact_rows
                    if isinstance(item, dict) and str(item.get("source_build_job_id") or "").strip()
                }
            ),
            "verified_at": now_iso,
            "session_build": session_build,
        },
        "handoff": {
            "workbench_path": (
                f"/w/{workspace_id}/workbench?panel=composer_detail&application_id={application_id}"
                f"&solution_change_session_id={session.id}"
            ),
            "solution_path": f"/w/{workspace_id}/solutions/{application_id}",
        },
    }
    if status != "ready":
        if build_status == "failed":
            reason = str(session_build.get("reason") or "session_preview_launch_failed").strip() or "session_preview_launch_failed"
            details = str(session_build.get("details") or "Failed to launch session preview for selected artifacts.").strip()
        else:
            reason = "preview_environment_unavailable"
            details = "Selected artifacts must resolve to healthy sibling runtime targets in one compose project."
        preview_payload["error"] = {
            "reason": reason,
            "details": details,
        }
    elif session_preview_fallback_reason:
        preview_payload["warning"] = {
            "reason": "session_preview_environment_create_failed_fallback_reused",
            "details": "Isolated session preview could not be provisioned; reused existing runtime target.",
            "fallback_reason": session_preview_fallback_reason,
        }
    else:
        primary_row = next((row for row in artifact_rows if isinstance(row, dict) and str(row.get("status") or "") == "ready"), None)
        if isinstance(primary_row, dict):
            _persist_solution_session_iteration_linkage(
                session=session,
                linkage_updates={
                    "workspace_id": workspace_id,
                    "application_id": application_id,
                    "session_id": str(session.id),
                    "status": "preview_ready",
                    "activation_mode": "preview",
                    "runtime_binding_id": "",
                    "runtime_instance": {
                        "id": str(primary_row.get("runtime_target_id") or "").strip(),
                        "app_slug": str(primary_row.get("app_slug") or "").strip(),
                        "status": "active",
                    },
                    "runtime_target": {
                        "runtime_owner": str(primary_row.get("runtime_owner") or "sibling"),
                        "runtime_base_url": str(primary_row.get("runtime_base_url") or "").strip(),
                        "public_app_url": str(primary_row.get("public_app_url") or "").strip(),
                        "compose_project": str(primary_row.get("compose_project") or "").strip(),
                    },
                    "activation": {
                        "job_id": "",
                        "draft_id": "",
                        "source_build_job_ids": (
                            ((preview_payload.get("build_deploy_evidence") or {}).get("source_build_job_ids") or [])
                            if isinstance(preview_payload.get("build_deploy_evidence"), dict)
                            else []
                        ),
                        "session_build_status": str((session_build or {}).get("status") or "").strip(),
                    },
                    "revision_anchor": {},
                },
                source="prepare_preview",
            )

    staged["overall_state"] = "preview_ready" if status == "ready" else "preview_failed"
    staged["preview_prepared_at"] = now_iso
    for row in artifact_states:
        if isinstance(row, dict):
            row["state"] = "preview_ready" if status == "ready" else "preview_failed"
            row["updated_at"] = now_iso
    session.staged_changes_json = staged
    session.preview_json = preview_payload
    session.execution_status = "preview_ready" if status == "ready" else "failed"
    session.save(update_fields=["staged_changes_json", "preview_json", "execution_status", "updated_at"])
    return preview_payload


def _validate_solution_change_session(*, session: SolutionChangeSession) -> Dict[str, Any]:
    plan = session.plan_json if isinstance(session.plan_json, dict) else {}
    staged = session.staged_changes_json if isinstance(session.staged_changes_json, dict) else {}
    preview = session.preview_json if isinstance(session.preview_json, dict) else {}
    artifact_states = staged.get("artifact_states") if isinstance(staged.get("artifact_states"), list) else []
    checks = [
        {
            "key": "plan_generated",
            "label": "Structured cross-artifact plan generated",
            "status": "passed" if bool(plan.get("per_artifact_work")) else "failed",
        },
        {
            "key": "staged_artifacts_present",
            "label": "Selected artifacts are staged",
            "status": "passed" if bool(artifact_states) else "failed",
        },
        {
            "key": "preview_prepared",
            "label": "Preview orchestration handoff prepared",
            "status": "passed" if str(preview.get("status") or "").strip().lower() == "ready" else "failed",
        },
    ]
    all_passed = all(str(item.get("status") or "") == "passed" for item in checks)
    for row in artifact_states:
        if isinstance(row, dict):
            row["validation_state"] = "passed" if all_passed else "failed"
            row["updated_at"] = timezone.now().isoformat()
    staged["artifact_states"] = artifact_states
    staged["overall_state"] = "validated" if all_passed else "validation_failed"
    validation_payload: Dict[str, Any] = {
        "validation_id": str(uuid.uuid4()),
        "validated_at": timezone.now().isoformat(),
        "status": "passed" if all_passed else "failed",
        "checks": checks,
        "artifact_count": len(artifact_states),
    }
    session.staged_changes_json = staged
    session.validation_json = validation_payload
    session.execution_status = "ready_for_promotion" if all_passed else "failed"
    session.save(update_fields=["staged_changes_json", "validation_json", "execution_status", "updated_at"])
    return validation_payload


def _serialize_application_detail(application: Application) -> Dict[str, Any]:
    goals = list(application.goals.all().order_by("-updated_at", "-created_at"))
    factory_definition = get_application_factory(application.source_factory_key)
    members = list(application.artifact_memberships.select_related("artifact", "artifact__type").order_by("sort_order", "created_at"))
    runtime_binding_payload = _application_runtime_binding_payload(application)
    return {
        **_serialize_application_summary(application),
        "factory": _serialize_application_factory_summary(factory_definition) if factory_definition else None,
        "goals": [_serialize_goal_summary(goal) for goal in goals],
        "artifact_memberships": [_serialize_application_artifact_membership(member) for member in members],
        "metadata": application.metadata_json if isinstance(application.metadata_json, dict) else {},
        "runtime_binding": runtime_binding_payload.get("runtime_binding"),
        "activation_composition": runtime_binding_payload.get("composition"),
    }


def _solution_activation_memberships(
    application: Application,
) -> tuple[Optional[ApplicationArtifactMembership], Optional[ApplicationArtifactMembership]]:
    memberships = list(
        ApplicationArtifactMembership.objects.filter(application=application)
        .select_related("artifact", "artifact__type")
        .order_by("sort_order", "created_at", "id")
    )
    app_memberships = [
        row
        for row in memberships
        if row.artifact
        and (
            str(getattr(row.artifact.type, "slug", "") or "").strip() == "application"
            or str(_artifact_slug(row.artifact) or "").strip().startswith("app.")
        )
    ]
    if not app_memberships:
        return None, None
    preferred_roles = ("primary_ui", "primary_api")
    selected_app = next((row for role in preferred_roles for row in app_memberships if row.role == role), app_memberships[0])
    policy_candidates = [
        row
        for row in memberships
        if row.artifact
        and row.artifact_id != selected_app.artifact_id
        and str(getattr(row.artifact.type, "slug", "") or "").strip() == "policy_bundle"
    ]
    policy_role_preference = {"supporting": 0, "policy": 1, "shared_library": 2}
    policy_candidates.sort(
        key=lambda row: (
            policy_role_preference.get(str(row.role or "").strip(), 99),
            int(row.sort_order or 0),
            str(getattr(row, "created_at", "") or ""),
            str(getattr(row, "id", "") or ""),
        )
    )
    policy_member = policy_candidates[0] if policy_candidates else None
    return selected_app, policy_member


def _artifact_ref_payload(artifact: Optional[Artifact]) -> Dict[str, str]:
    if artifact is None:
        return {}
    return {
        "artifact_id": str(artifact.id),
        "artifact_slug": str(_artifact_slug(artifact) or ""),
        "artifact_version": str(artifact.package_version or ""),
    }


def _application_solution_slug(application: Application) -> str:
    metadata = application.metadata_json if isinstance(application.metadata_json, dict) else {}
    return str(
        metadata.get("solution_bundle_slug")
        or metadata.get("generated_artifact_key")
        or metadata.get("system_solution_key")
        or ""
    ).strip()


def _application_install_source(application: Application) -> str:
    metadata = application.metadata_json if isinstance(application.metadata_json, dict) else {}
    return str(metadata.get("solution_bundle_install_source") or "").strip()


def _application_runtime_binding(application: Application) -> Optional[SolutionRuntimeBinding]:
    return (
        SolutionRuntimeBinding.objects.filter(application=application, workspace_id=application.workspace_id)
        .select_related("runtime_instance", "primary_app_artifact", "policy_artifact")
        .order_by("-updated_at", "-created_at")
        .first()
    )


def _solution_runtime_binding_composition(
    selected_app_member: Optional[ApplicationArtifactMembership],
    selected_policy_member: Optional[ApplicationArtifactMembership],
) -> Dict[str, Any]:
    return {
        "primary_app_artifact_ref": {
            "artifact_id": str(getattr(selected_app_member, "artifact_id", "") or ""),
            "artifact_slug": str(_artifact_slug(selected_app_member.artifact) or "") if selected_app_member and selected_app_member.artifact else "",
            "artifact_version": str(getattr(selected_app_member.artifact, "package_version", "") or "") if selected_app_member and selected_app_member.artifact else "",
        },
        "policy_artifact_ref": {
            "artifact_id": str(getattr(selected_policy_member, "artifact_id", "") or ""),
            "artifact_slug": str(_artifact_slug(selected_policy_member.artifact) or "") if selected_policy_member and selected_policy_member.artifact else "",
            "artifact_version": str(getattr(selected_policy_member.artifact, "package_version", "") or "") if selected_policy_member and selected_policy_member.artifact else "",
        },
    }


def _solution_runtime_binding_composition_fingerprint(composition: Dict[str, Any]) -> str:
    return hashlib.sha256(
        json.dumps(composition, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    ).hexdigest()


def _solution_runtime_binding_freshness(
    *,
    application: Application,
    binding: SolutionRuntimeBinding,
    composition: Dict[str, Any],
) -> tuple[str, str]:
    metadata = binding.metadata_json if isinstance(binding.metadata_json, dict) else {}
    expected_fingerprint = _solution_runtime_binding_composition_fingerprint(composition)
    recorded_fingerprint = str(metadata.get("composition_fingerprint") or "").strip()
    if not recorded_fingerprint:
        return "unknown", "missing_composition_fingerprint"
    if recorded_fingerprint != expected_fingerprint:
        return "stale_composition", "composition_fingerprint_mismatch"
    if str(binding.status or "").strip() == "active":
        runtime_instance = binding.runtime_instance
        if not runtime_instance or str(runtime_instance.status or "").strip().lower() != "active":
            return "stale_runtime", "runtime_instance_missing_or_inactive"
        expected_app_slug = str(runtime_instance.app_slug or "").strip()
        if not expected_app_slug:
            return "stale_runtime", "runtime_instance_missing_app_slug"
        runtime_record = _workspace_runtime_target(application.workspace, expected_app_slug)
        if not isinstance(runtime_record, dict):
            return "stale_runtime", "runtime_target_missing"
        active_instance = runtime_record.get("instance")
        if not active_instance or str(getattr(active_instance, "id", "") or "") != str(runtime_instance.id):
            return "stale_runtime", "runtime_instance_mismatch"
        runtime_target = runtime_record.get("runtime_target") if isinstance(runtime_record.get("runtime_target"), dict) else {}
        expected_artifact_slug = str((composition.get("primary_app_artifact_ref") or {}).get("artifact_slug") or "").strip()
        installed_artifact_slug = str(runtime_target.get("installed_artifact_slug") or "").strip()
        if expected_artifact_slug and installed_artifact_slug and expected_artifact_slug != installed_artifact_slug:
            return "stale_runtime", "runtime_target_artifact_mismatch"
        return "current", ""
    if str(binding.status or "").strip() in {"pending", "error"}:
        return "unknown", f"binding_status_{str(binding.status or '').strip().lower()}"
    return "unknown", "binding_status_unknown"


def _serialize_solution_runtime_binding(
    binding: SolutionRuntimeBinding,
    *,
    freshness: str = "unknown",
    freshness_reason: str = "",
) -> Dict[str, Any]:
    runtime_instance = binding.runtime_instance
    runtime_target = binding.runtime_target_json if isinstance(binding.runtime_target_json, dict) else {}
    runtime_target = _refresh_runtime_target_localhost_url(runtime_target)
    return {
        "id": str(binding.id),
        "workspace_id": str(binding.workspace_id),
        "application_id": str(binding.application_id),
        "status": str(binding.status or ""),
        "activation_mode": str(binding.activation_mode or ""),
        "freshness": freshness,
        "freshness_reason": freshness_reason,
        "primary_app_artifact_ref": {
            "artifact_id": str(binding.primary_app_artifact_id or ""),
            "artifact_slug": str(_artifact_slug(binding.primary_app_artifact) or "") if binding.primary_app_artifact else "",
            "artifact_version": str(getattr(binding.primary_app_artifact, "package_version", "") or "") if binding.primary_app_artifact else "",
        },
        "policy_artifact_ref": {
            "artifact_id": str(binding.policy_artifact_id or ""),
            "artifact_slug": str(_artifact_slug(binding.policy_artifact) or "") if binding.policy_artifact else "",
            "artifact_version": str(getattr(binding.policy_artifact, "package_version", "") or "") if binding.policy_artifact else "",
        },
        "runtime_instance": {
            "id": str(getattr(runtime_instance, "id", "") or ""),
            "app_slug": str(getattr(runtime_instance, "app_slug", "") or ""),
            "fqdn": str(getattr(runtime_instance, "fqdn", "") or ""),
            "status": str(getattr(runtime_instance, "status", "") or ""),
        }
        if runtime_instance
        else None,
        "runtime_target": runtime_target,
        "metadata": binding.metadata_json if isinstance(binding.metadata_json, dict) else {},
        "last_activation": binding.last_activation_json if isinstance(binding.last_activation_json, dict) else {},
        "created_at": binding.created_at,
        "updated_at": binding.updated_at,
    }


def _application_runtime_binding_payload(application: Application) -> Dict[str, Any]:
    selected_app_member, selected_policy_member = _solution_activation_memberships(application)
    binding = _application_runtime_binding(application)
    composition = _solution_runtime_binding_composition(selected_app_member, selected_policy_member)
    freshness = "unknown"
    freshness_reason = ""
    if binding:
        freshness, freshness_reason = _solution_runtime_binding_freshness(
            application=application,
            binding=binding,
            composition=composition,
        )
    return {
        "application_id": str(application.id),
        "workspace_id": str(application.workspace_id),
        "composition": composition,
        "runtime_binding": _serialize_solution_runtime_binding(
            binding,
            freshness=freshness,
            freshness_reason=freshness_reason,
        )
        if binding
        else None,
    }


def _record_solution_runtime_binding_from_activation(
    *,
    application: Application,
    selected_app_artifact: Artifact,
    activation_payload: Dict[str, Any],
) -> SolutionRuntimeBinding:
    status_value = str(activation_payload.get("status") or "").strip().lower()
    runtime_status = "active" if status_value == "reused" else "pending"
    activation_mode = "composed" if str(activation_payload.get("policy_source") or "") == "artifact" else "reconstructed"
    runtime_instance_payload = (
        activation_payload.get("runtime_instance")
        if isinstance(activation_payload.get("runtime_instance"), dict)
        else {}
    )
    runtime_instance_id = str(runtime_instance_payload.get("id") or "").strip()
    runtime_instance = None
    if runtime_instance_id:
        runtime_instance = WorkspaceAppInstance.objects.filter(
            id=runtime_instance_id,
            workspace_id=application.workspace_id,
        ).first()
    policy_artifact_ref = (
        activation_payload.get("policy_artifact_ref")
        if isinstance(activation_payload.get("policy_artifact_ref"), dict)
        else {}
    )
    policy_artifact = None
    policy_artifact_id = str(policy_artifact_ref.get("artifact_id") or "").strip()
    if policy_artifact_id:
        policy_artifact = Artifact.objects.filter(id=policy_artifact_id, workspace_id=application.workspace_id).first()
    runtime_target = activation_payload.get("runtime_target")
    if not isinstance(runtime_target, dict):
        runtime_target = {}
    runtime_target = _refresh_runtime_target_localhost_url(runtime_target)
    selected_app_member = ApplicationArtifactMembership(
        application=application,
        artifact=selected_app_artifact,
    )
    selected_policy_member = (
        ApplicationArtifactMembership(
            application=application,
            artifact=policy_artifact,
        )
        if policy_artifact
        else None
    )
    composition = _solution_runtime_binding_composition(selected_app_member, selected_policy_member)
    composition_fingerprint = _solution_runtime_binding_composition_fingerprint(composition)
    activation_metadata = {
        "policy_source": str(activation_payload.get("policy_source") or "reconstructed"),
        "policy_compatibility": str(activation_payload.get("policy_compatibility") or "unknown"),
        "policy_compatibility_reason": str(activation_payload.get("policy_compatibility_reason") or ""),
        "composition_fingerprint": composition_fingerprint,
        "primary_app_artifact_ref": composition.get("primary_app_artifact_ref"),
        "policy_artifact_ref": composition.get("policy_artifact_ref"),
        "runtime_health_snapshot": {
            "runtime_instance_present": bool(runtime_instance),
            "runtime_target_present": bool(runtime_target),
        },
    }
    if status_value == "reused":
        activation_metadata["last_successful_activation_at"] = timezone.now().isoformat()
    binding, _created = SolutionRuntimeBinding.objects.update_or_create(
        workspace_id=application.workspace_id,
        application=application,
        defaults={
            "runtime_instance": runtime_instance,
            "primary_app_artifact": selected_app_artifact,
            "policy_artifact": policy_artifact,
            "activation_mode": activation_mode,
            "status": runtime_status,
            "runtime_target_json": runtime_target,
            "last_activation_json": {
                "status": status_value,
                "activation": activation_payload.get("activation") if isinstance(activation_payload.get("activation"), dict) else {},
                "policy_source": str(activation_payload.get("policy_source") or "reconstructed"),
                "policy_compatibility": str(activation_payload.get("policy_compatibility") or "unknown"),
                "policy_compatibility_reason": str(activation_payload.get("policy_compatibility_reason") or ""),
            },
            "metadata_json": activation_metadata,
        },
    )
    return binding


def _composer_stage_for_context(
    *,
    application_plan: Optional[ApplicationPlan],
    application: Optional[Application],
    goal: Optional[Goal],
    thread: Optional[CoordinationThread],
) -> str:
    if thread is not None:
        return "thread_focus"
    if goal is not None:
        return "goal_focus"
    if application is not None and application_plan is not None:
        return "plan_applied"
    if application is not None:
        return "application_overview"
    if application_plan is not None:
        return "plan_review"
    return "factory_discovery"


def _serialize_composer_action(
    *,
    action_type: str,
    label: str,
    enabled: bool = True,
    target_kind: str = "",
    target_id: Optional[str] = None,
    params: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    payload: Dict[str, Any] = {
        "type": action_type,
        "label": label,
        "enabled": enabled,
    }
    if target_kind:
        payload["target_kind"] = target_kind
    if target_id is not None:
        payload["target_id"] = target_id
    if params:
        payload["params"] = params
    return payload


def _composer_breadcrumbs(
    *,
    selected_factory: Optional[ApplicationFactoryDefinition],
    application_plan: Optional[ApplicationPlan],
    application: Optional[Application],
    goal: Optional[Goal],
    thread: Optional[CoordinationThread],
) -> List[Dict[str, Any]]:
    breadcrumbs: List[Dict[str, Any]] = [{"kind": "composer", "label": "Composer"}]
    if selected_factory is not None:
        breadcrumbs.append({"kind": "factory", "label": selected_factory.name, "id": selected_factory.key})
    if application_plan is not None:
        breadcrumbs.append({"kind": "application_plan", "label": application_plan.name, "id": str(application_plan.id)})
    if application is not None:
        breadcrumbs.append({"kind": "application", "label": application.name, "id": str(application.id)})
    if goal is not None:
        breadcrumbs.append({"kind": "goal", "label": goal.title, "id": str(goal.id)})
    if thread is not None:
        breadcrumbs.append({"kind": "thread", "label": thread.title, "id": str(thread.id)})
    return breadcrumbs


def _serialize_composer_state(
    *,
    workspace: Workspace,
    factory_key: str = "",
    application_plan: Optional[ApplicationPlan] = None,
    application: Optional[Application] = None,
    goal: Optional[Goal] = None,
    thread: Optional[CoordinationThread] = None,
    solution_change_session: Optional[SolutionChangeSession] = None,
) -> Dict[str, Any]:
    if thread is not None and goal is None and thread.goal_id:
        goal = thread.goal
    if goal is not None and application is None and goal.application_id:
        application = goal.application
    if application_plan is not None and application is None and application_plan.application_id:
        application = application_plan.application
    selected_factory = get_application_factory(factory_key) if factory_key else None
    stage = _composer_stage_for_context(
        application_plan=application_plan,
        application=application,
        goal=goal,
        thread=thread,
    )
    factory_catalog = [_serialize_application_factory_summary(definition) for definition in list_application_factories()]
    recent_plans = list(
        ApplicationPlan.objects.filter(workspace=workspace)
        .select_related("application", "requested_by")
        .order_by("-updated_at", "-created_at")[:10]
    )
    recent_applications = list(
        Application.objects.filter(workspace=workspace)
        .select_related("requested_by")
        .prefetch_related("goals")
        .order_by("-updated_at", "-created_at")[:10]
    )
    related_goals: List[Dict[str, Any]] = []
    related_threads: List[Dict[str, Any]] = []
    portfolio_context: Optional[Dict[str, Any]] = None
    if application is not None:
        application_detail = _serialize_application_detail(application)
        related_goals = application_detail.get("goals") if isinstance(application_detail.get("goals"), list) else []
        goal_objects = list(
            CoordinationThread.objects.filter(goal__application=application)
            .select_related("goal", "owner")
            .order_by("-updated_at", "-created_at")[:50]
        )
        related_threads = [_coordination_thread_summary(item) for item in goal_objects]
        portfolio_context = application_detail.get("portfolio_state") if isinstance(application_detail.get("portfolio_state"), dict) else None
    elif goal is not None:
        goal_detail = _serialize_goal_detail(goal)
        related_goals = [_serialize_goal_summary(goal)]
        related_threads = goal_detail.get("threads") if isinstance(goal_detail.get("threads"), list) else []
        portfolio_context = _build_goal_portfolio_payload([goal])
    elif thread is not None:
        related_threads = [_coordination_thread_summary(thread)]
        if goal is not None:
            related_goals = [_serialize_goal_summary(goal)]
            portfolio_context = _build_goal_portfolio_payload([goal])
    else:
        goal_objects = list(_active_goals_for_workspace(workspace).order_by("-updated_at", "-created_at")[:20])
        related_goals = [_serialize_goal_summary(item) for item in goal_objects]
        portfolio_context = _build_goal_portfolio_payload(goal_objects)
        if goal_objects:
            related_threads = [
                _coordination_thread_summary(item)
                for item in CoordinationThread.objects.filter(goal__in=goal_objects)
                .select_related("goal", "owner")
                .order_by("-updated_at", "-created_at")[:20]
            ]
    available_actions: List[Dict[str, Any]] = []
    if selected_factory is not None and application_plan is None and application is None:
        available_actions.append(
            _serialize_composer_action(
                action_type="generate_plan",
                label="Generate Plan",
                target_kind="factory",
                target_id=selected_factory.key,
            )
        )
    if application_plan is not None and stage in {"plan_review", "plan_applied"}:
        available_actions.append(
            _serialize_composer_action(
                action_type="apply_plan",
                label="Apply Plan",
                enabled=application is None,
                target_kind="application_plan",
                target_id=str(application_plan.id),
            )
        )
    if application is not None:
        available_actions.append(
            _serialize_composer_action(
                action_type="open_application",
                label="Open Application",
                target_kind="application",
                target_id=str(application.id),
            )
        )
        available_actions.append(
            _serialize_composer_action(
                action_type="open_solution_change_sessions",
                label="Open Solution Change Sessions",
                target_kind="application",
                target_id=str(application.id),
            )
        )
    if solution_change_session is not None:
        session_execution_status = str(solution_change_session.execution_status or "not_started")
        available_actions.append(
            _serialize_composer_action(
                action_type="stage_solution_change",
                label="Stage Coordinated Change",
                enabled=bool(solution_change_session.plan_json),
                target_kind="solution_change_session",
                target_id=str(solution_change_session.id),
            )
        )
        available_actions.append(
            _serialize_composer_action(
                action_type="prepare_solution_preview",
                label="Prepare Preview Handoff",
                enabled=session_execution_status
                in {"staged", "preview_preparing", "preview_ready", "validating", "ready_for_promotion", "committed", "promoted"},
                target_kind="solution_change_session",
                target_id=str(solution_change_session.id),
            )
        )
        available_actions.append(
            _serialize_composer_action(
                action_type="validate_solution_change",
                label="Validate Staged Change",
                enabled=session_execution_status in {"preview_ready", "validating", "ready_for_promotion", "committed", "promoted"},
                target_kind="solution_change_session",
                target_id=str(solution_change_session.id),
            )
        )
    if goal is not None and isinstance((_serialize_goal_detail(goal).get("recommendation") or {}), dict):
        goal_detail = _serialize_goal_detail(goal)
        recommendation = goal_detail.get("recommendation") if isinstance(goal_detail.get("recommendation"), dict) else {}
        recommendation_id = str(recommendation.get("recommendation_id") or "").strip() or None
        available_actions.append(
            _serialize_composer_action(
                action_type="approve_next_slice",
                label="Approve Next Slice",
                enabled=bool(recommendation),
                target_kind="goal",
                target_id=str(goal.id),
                params={"recommendation_id": recommendation_id} if recommendation_id else None,
            )
        )
    if thread is not None:
        available_actions.extend(
            [
                _serialize_composer_action(action_type="review_thread", label="Review Thread", target_kind="thread", target_id=str(thread.id)),
                _serialize_composer_action(action_type="resume_thread", label="Resume Thread", target_kind="thread", target_id=str(thread.id)),
                _serialize_composer_action(action_type="queue_next_slice", label="Queue Next Slice", target_kind="thread", target_id=str(thread.id)),
                _serialize_composer_action(action_type="mark_thread_completed", label="Mark Thread Completed", target_kind="thread", target_id=str(thread.id)),
            ]
        )
    return {
        "workspace_id": str(workspace.id),
        "stage": stage,
        "context": {
            "factory_key": selected_factory.key if selected_factory else None,
            "application_plan_id": str(application_plan.id) if application_plan else None,
            "application_id": str(application.id) if application else None,
            "goal_id": str(goal.id) if goal else None,
            "thread_id": str(thread.id) if thread else None,
            "solution_change_session_id": str(solution_change_session.id) if solution_change_session else None,
        },
        "factory_catalog": factory_catalog,
        "selected_factory": _serialize_application_factory_summary(selected_factory) if selected_factory else None,
        "application_plans": [_serialize_application_plan_summary(plan) for plan in recent_plans],
        "applications": [_serialize_application_summary(app) for app in recent_applications],
        "application_plan": _serialize_application_plan_detail(application_plan) if application_plan else None,
        "application": _serialize_application_detail(application) if application else None,
        "solution_change_sessions": [
            _serialize_solution_change_session(
                item,
                memberships_by_artifact_id={
                    str(member.artifact_id): member
                    for member in ApplicationArtifactMembership.objects.filter(application=item.application)
                    .select_related("artifact", "artifact__type")
                    .all()
                },
            )
            for item in (
                SolutionChangeSession.objects.filter(application=application).order_by("-updated_at", "-created_at")[:10]
                if application is not None
                else []
            )
        ],
        "solution_change_session": _serialize_solution_change_session(
            solution_change_session,
            memberships_by_artifact_id={
                str(member.artifact_id): member
                for member in ApplicationArtifactMembership.objects.filter(application=solution_change_session.application)
                .select_related("artifact", "artifact__type")
                .all()
            },
        )
        if solution_change_session is not None
        else None,
        "goal": _serialize_goal_detail(goal) if goal else None,
        "thread": _coordination_thread_detail(thread) if thread else None,
        "related_goals": related_goals,
        "related_threads": related_threads,
        "portfolio_context": portfolio_context,
        "breadcrumbs": _composer_breadcrumbs(
            selected_factory=selected_factory,
            application_plan=application_plan,
            application=application,
            goal=goal,
            thread=thread,
        ),
        "available_actions": available_actions,
    }


def _build_goal_portfolio_payload(goals: List[Goal]) -> Dict[str, Any]:
    portfolio_rows = build_goal_portfolio_state(goals, runtime_detail_lookup=_project_runtime_status_to_task)
    portfolio_insights = compute_portfolio_insights(goals, runtime_detail_lookup=_project_runtime_status_to_task)
    portfolio_recommendation = recommend_portfolio_goal(goals, runtime_detail_lookup=_project_runtime_status_to_task)
    return {
        "goals": [
            {
                "goal_id": row.goal_id,
                "title": row.title,
                "planning_status": row.planning_status,
                "goal_progress_status": row.goal_progress_status,
                "progress_percent": row.progress_percent,
                "health_status": row.health_status,
                "active_threads": row.active_threads,
                "blocked_threads": row.blocked_threads,
                "recent_execution_count": row.recent_execution_count,
                "coordination_priority": {
                    "value": row.coordination_priority.value,
                    "reasons": row.coordination_priority.reasons,
                },
            }
            for row in portfolio_rows
        ],
        "insights": [
            {
                "key": insight.key,
                "summary": insight.summary,
                "evidence": insight.evidence,
                "goal_ids": insight.goal_ids,
            }
            for insight in portfolio_insights
        ],
        "recommended_goal": (
            {
                "goal_id": portfolio_recommendation.goal_id,
                "title": portfolio_recommendation.title,
                "coordination_priority": portfolio_recommendation.coordination_priority,
                "summary": portfolio_recommendation.summary,
                "reasoning": portfolio_recommendation.reasoning,
                "thread_id": portfolio_recommendation.thread_id,
                "work_item_id": portfolio_recommendation.work_item_id,
                "queue_action_type": portfolio_recommendation.queue_action_type,
            }
            if portfolio_recommendation
            else None
        ),
    }


def _goal_progress_summary_text(goal_detail: Dict[str, Any]) -> str:
    progress = goal_detail.get("goal_progress") if isinstance(goal_detail.get("goal_progress"), dict) else {}
    status = str(progress.get("goal_progress_status") or "not_started").replace("_", " ")
    completed = int(progress.get("completed_work_items") or 0)
    active = int(progress.get("active_work_items") or 0)
    blocked = int(progress.get("blocked_work_items") or 0)
    title = str(goal_detail.get("title") or "This goal")
    loop_summary = goal_detail.get("development_loop_summary") if isinstance(goal_detail.get("development_loop_summary"), dict) else {}
    recent_results = loop_summary.get("recent_work_results") if isinstance(loop_summary.get("recent_work_results"), list) else []
    latest = recent_results[0] if recent_results and isinstance(recent_results[0], dict) else {}
    next_slice = loop_summary.get("recommended_next_slice") if isinstance(loop_summary.get("recommended_next_slice"), dict) else {}
    parts = [f"{title} is {status}. Completed {completed} work item(s), active {active}, blocked {blocked}."]
    if latest:
        artifact_count = int(latest.get("artifact_count") or 0)
        parts.append(
            f"Latest result: {str(latest.get('title') or 'Work item')} is {str(latest.get('status') or 'updated')} with {artifact_count} artifact(s)."
        )
    next_summary = str(next_slice.get("summary") or "").strip()
    if next_summary:
        parts.append(f"Next slice: {next_summary}")
    return " ".join(parts)


def _thread_progress_summary_text(thread_detail: Dict[str, Any]) -> str:
    status = str(thread_detail.get("thread_progress_status") or thread_detail.get("status") or "not_started").replace("_", " ")
    completed = int(thread_detail.get("work_items_completed") or 0)
    ready = int(thread_detail.get("work_items_ready") or 0)
    blocked = int(thread_detail.get("work_items_blocked") or 0)
    title = str(thread_detail.get("title") or "This thread")
    recent_runs = thread_detail.get("recent_runs") if isinstance(thread_detail.get("recent_runs"), list) else []
    latest_run = recent_runs[0] if recent_runs and isinstance(recent_runs[0], dict) else {}
    recent_artifacts = thread_detail.get("recent_artifacts") if isinstance(thread_detail.get("recent_artifacts"), list) else []
    parts = [f"{title} is {status}. Completed {completed} work item(s), ready {ready}, blocked {blocked}."]
    if latest_run:
        parts.append(
            f"Latest run {str(latest_run.get('id') or 'run')} is {str(latest_run.get('status') or 'unknown')}."
        )
    if recent_artifacts:
        parts.append(f"{len(recent_artifacts)} artifact(s) are available for review.")
    return " ".join(parts)


def _thread_diagnostic_summary_text(thread_detail: Dict[str, Any]) -> str:
    diagnostic = thread_detail.get("thread_diagnostic") if isinstance(thread_detail.get("thread_diagnostic"), dict) else {}
    title = str(thread_detail.get("title") or "This thread")
    status = str(diagnostic.get("status") or thread_detail.get("thread_progress_status") or thread_detail.get("status") or "unknown").replace("_", " ")
    observations = diagnostic.get("observations") if isinstance(diagnostic.get("observations"), list) else []
    evidence = diagnostic.get("evidence") if isinstance(diagnostic.get("evidence"), list) else []
    parts = [f"{title} diagnostic status is {status}."]
    if observations:
        parts.append(str(observations[0]))
    if evidence:
        parts.append(f"Evidence: {str(evidence[0])}")
    provenance = diagnostic.get("provenance") if isinstance(diagnostic.get("provenance"), dict) else {}
    provenance_summary = str(provenance.get("summary") or "").strip()
    if provenance_summary:
        parts.append(provenance_summary)
    return " ".join(parts)


def _goal_diagnostic_summary_text(goal_detail: Dict[str, Any]) -> str:
    diagnostic = goal_detail.get("goal_diagnostic") if isinstance(goal_detail.get("goal_diagnostic"), dict) else {}
    title = str(goal_detail.get("title") or "This goal")
    status = str(diagnostic.get("status") or ((goal_detail.get("goal_progress") or {}) if isinstance(goal_detail.get("goal_progress"), dict) else {}).get("goal_progress_status") or "unknown").replace("_", " ")
    observations = diagnostic.get("observations") if isinstance(diagnostic.get("observations"), list) else []
    evidence = diagnostic.get("evidence") if isinstance(diagnostic.get("evidence"), list) else []
    parts = [f"{title} diagnostic status is {status}."]
    if observations:
        parts.append(str(observations[0]))
    if evidence:
        parts.append(f"Evidence: {str(evidence[0])}")
    return " ".join(parts)


def _goal_insight_summary_text(goal_detail: Dict[str, Any]) -> str:
    insights = goal_detail.get("development_insights") if isinstance(goal_detail.get("development_insights"), list) else []
    title = str(goal_detail.get("title") or "This goal")
    if not insights:
        return f"{title} has no recent development insight beyond the current durable progress state."
    first = insights[0] if isinstance(insights[0], dict) else {}
    summary = str(first.get("summary") or "").strip()
    evidence = first.get("evidence") if isinstance(first.get("evidence"), list) else []
    parts = [summary or f"{title} has a recent development insight available."]
    if evidence:
        parts.append(f"Evidence: {str(evidence[0])}")
    return " ".join(parts)


def _artifact_analysis_summary_text(artifact_detail: Dict[str, Any]) -> str:
    analysis = artifact_detail.get("analysis") if isinstance(artifact_detail.get("analysis"), dict) else {}
    label = str(artifact_detail.get("label") or artifact_detail.get("artifact_id") or "artifact")
    status = str(analysis.get("status") or "unknown").replace("_", " ")
    observations = analysis.get("observations") if isinstance(analysis.get("observations"), list) else []
    evidence = analysis.get("evidence") if isinstance(analysis.get("evidence"), list) else []
    parts = [f"{label} analysis status is {status}."]
    if observations:
        parts.append(str(observations[0]))
    if evidence:
        parts.append(f"Evidence: {str(evidence[0])}")
    provenance = analysis.get("provenance") if isinstance(analysis.get("provenance"), dict) else {}
    provenance_summary = str(provenance.get("summary") or "").strip()
    if provenance_summary:
        parts.append(provenance_summary)
    return " ".join(parts)


def _runtime_run_artifact_detail_for_conversation(
    *,
    workspace: Workspace,
    run_id: str,
    artifact_id: str,
) -> Dict[str, Any]:
    try:
        parsed_run_id = uuid.UUID(str(run_id))
        parsed_artifact_id = uuid.UUID(str(artifact_id))
    except (TypeError, ValueError) as exc:
        raise RuntimeError("runtime artifact reference is invalid") from exc
    try:
        run_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{parsed_run_id}", timeout=20)
        artifact_response = _seed_api_request(method="GET", path=f"/api/v1/runs/{parsed_run_id}/artifacts/{parsed_artifact_id}", timeout=20)
    except requests.RequestException as exc:
        raise RuntimeError("failed to reach xyn-core") from exc
    if run_response.status_code == 404:
        raise RuntimeError("runtime run not found")
    if run_response.status_code >= 400:
        raise RuntimeError("runtime run unavailable")
    if artifact_response.status_code == 404:
        raise RuntimeError("runtime artifact not found")
    if artifact_response.status_code >= 400:
        raise RuntimeError("runtime artifact unavailable")
    try:
        run_payload = run_response.json() if run_response.content else {}
        artifact_payload = artifact_response.json() if artifact_response.content else {}
    except ValueError as exc:
        raise RuntimeError("invalid runtime artifact response") from exc
    if not isinstance(run_payload, dict) or not _runtime_run_belongs_to_workspace(run_payload, workspace):
        raise RuntimeError("runtime run not found")
    if not isinstance(artifact_payload, dict):
        raise RuntimeError("runtime artifact unavailable")
    return _runtime_run_artifact_detail_payload_for_workspace(
        workspace=workspace,
        run_id=parsed_run_id,
        artifact_id=parsed_artifact_id,
        artifact_payload=artifact_payload,
    )


def _serialize_work_item_detail(task: DevTask) -> Dict[str, Any]:
    execution_payload = _resolve_dev_task_execution_payload(task)
    runtime_detail = execution_payload["runtime_detail"]
    run_payload = execution_payload["run_payload"]
    artifacts_payload = execution_payload["artifacts_payload"]
    commands_payload = execution_payload["commands_payload"]
    change_set = resolve_dev_task_change_set(task, execution_payload=execution_payload, include_diff=True)
    normalized_status = _canonical_work_item_status(str((runtime_detail or {}).get("status") or task.status), execution_policy=task.execution_policy)
    return {
        **_serialize_work_item_summary(task, runtime_detail=runtime_detail),
        "execution_queue": _serialize_selected_work_item_queue_state(task, normalized_status=normalized_status),
        "input_artifact_key": task.input_artifact_key,
        "last_error": str((runtime_detail or {}).get("failure_reason") or (runtime_detail or {}).get("escalation_reason") or task.last_error or ""),
        "context_packs": [
            {
                "id": str(pack.id),
                "name": pack.name,
                "purpose": pack.purpose,
                "scope": pack.scope,
                "version": pack.version,
            }
            for pack in task.context_packs.all()
        ],
        "thread_detail": _coordination_thread_summary(task.coordination_thread) if task.coordination_thread_id else None,
        "goal_detail": _serialize_goal_summary(task.goal) if task.goal_id else None,
        "execution_brief": task.execution_brief if isinstance(task.execution_brief, dict) else None,
        "execution_brief_history": task.execution_brief_history if isinstance(task.execution_brief_history, list) else [],
        "change_set": change_set,
        "result_run_detail": run_payload,
        "result_run_artifacts": artifacts_payload,
        "result_run_commands": commands_payload,
    }


def _requeue_dev_task(
    task: DevTask,
    *,
    user,
    execution_summary: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    recovery = evaluate_dev_task_recovery_state(task, execution_summary=execution_summary)
    if not recovery.requeueable:
        raise ValueError(recovery.message)
    record_execution_failure_snapshot(
        task,
        execution_summary=execution_summary,
        action="requeue",
        recorded_at=timezone.now().isoformat(),
    )
    task.runtime_run_id = None
    task.result_run = None
    task.status = "queued"
    task.updated_by = user
    task.save(update_fields=["execution_policy", "runtime_run_id", "result_run", "status", "updated_by", "updated_at"])
    return {"status": "queued"}


def _execute_conversation_action(
    *,
    identity: UserIdentity,
    user,
    workspace: Workspace,
    action: Dict[str, Any],
    prompt: str,
    request_id: str,
    intent_payload: Dict[str, Any],
    prompt_interpretation: Dict[str, Any],
) -> JsonResponse:
    action_type = str(action.get("action_type") or "").strip()
    target = action.get("target_object") if isinstance(action.get("target_object"), dict) else {}

    if action_type in {
        ConversationActionType.CREATE_WORK_ITEM.value,
        ConversationActionType.CONTINUE_WORK_ITEM.value,
        ConversationActionType.DISPATCH_RUN.value,
    }:
        task = _ensure_conversation_dev_task(workspace=workspace, action=action, prompt=prompt, user=user)
        detail = _serialize_dev_task_summary(task)
        if action_type == ConversationActionType.DISPATCH_RUN.value:
            task_thread_id = getattr(task, "coordination_thread_id", None)
            if task_thread_id:
                result = _dispatch_next_queue_item(workspace=workspace, user=user, identity=identity)
                task.refresh_from_db()
                detail = _serialize_dev_task_summary(task, runtime_detail=_project_runtime_status_to_task(task))
                return JsonResponse(
                    {
                        "status": "DraftReady",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": f"Queued runtime run {result.get('run_id')} for work item {result.get('work_item_id')} through XCO scheduling.",
                        "intent": intent_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": action,
                        "operation_result": True,
                        "result": {
                            "thread_id": result.get("thread_id"),
                            "work_item": detail,
                            "run_id": result.get("run_id"),
                            "work_item_id": result.get("work_item_id"),
                        },
                        "next_actions": [
                            {
                                "action": "OpenPanel",
                                "panel_key": "thread_detail",
                                "label": "Open Thread",
                                "params": {"thread_id": str(task_thread_id)},
                            },
                            {
                                "action": "OpenPanel",
                                "panel_key": "run_detail",
                                "label": "Open Run",
                                "params": {"run_id": str(result.get("run_id") or "")},
                            },
                        ],
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    }
                )
            result = _submit_conversation_runtime_run(task=task, workspace=workspace, action=action, prompt=prompt, user=user)
            detail = _serialize_dev_task_summary(task, runtime_detail=_project_runtime_status_to_task(task))
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": f"Queued runtime run {result.get('run_id')} for work item {result.get('work_item_id')}.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {
                        "work_item": detail,
                        "run_id": result.get("run_id"),
                        "work_item_id": result.get("work_item_id"),
                    },
                    "next_actions": [
                        {
                            "action": "OpenPanel",
                            "panel_key": "work_item_detail",
                            "label": "Open Work Item",
                            "params": {"work_item_id": str(task.id)},
                        },
                        {
                            "action": "OpenPanel",
                            "panel_key": "run_detail",
                            "label": "Open Run",
                            "params": {"run_id": str(result.get("run_id") or "")},
                        },
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        return JsonResponse(
            {
                "status": "DraftReady",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": (
                    f"Continuing work item {detail.get('work_item_id') or detail.get('title')}."
                    if action_type == ConversationActionType.CONTINUE_WORK_ITEM.value
                    else f"Created work item {detail.get('work_item_id') or detail.get('title')}."
                ),
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": True,
                "result": {"work_item": detail},
                "next_actions": [
                    {
                        "action": "OpenPanel",
                        "panel_key": "work_item_detail",
                        "label": "Open Work Item",
                        "params": {"work_item_id": str(task.id)},
                    }
                ],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
        )

    if action_type in {
        ConversationActionType.CREATE_THREAD.value,
        ConversationActionType.LIST_THREADS.value,
        ConversationActionType.SHOW_THREAD.value,
        ConversationActionType.SHOW_THREAD_REVIEW.value,
        ConversationActionType.PAUSE_THREAD.value,
        ConversationActionType.RESUME_THREAD.value,
        ConversationActionType.PRIORITIZE_THREAD.value,
    }:
        action_payload = ((action.get("payload") or {}) if isinstance(action.get("payload"), dict) else {}).get("action_payload")
        action_payload = action_payload if isinstance(action_payload, dict) else {}
        summary_mode = str(action_payload.get("summary_mode") or "").strip()
        thread_id = str(target.get("id") or "").strip()
        thread: Optional[CoordinationThread] = None
        if thread_id:
            thread = CoordinationThread.objects.filter(id=thread_id, workspace=workspace).first()
        if action_type == ConversationActionType.CREATE_THREAD.value:
            title = str(action_payload.get("title") or target.get("reference") or prompt).strip() or "XCO thread"
            thread = CoordinationThread.objects.create(
                workspace=workspace,
                title=title[:240],
                description=str(prompt or "").strip(),
                owner=identity,
                priority=str(action_payload.get("priority") or "normal").strip() or "normal",
                status="active",
                domain=str(action_payload.get("domain") or "development").strip(),
                work_in_progress_limit=max(1, int(action_payload.get("max_concurrent_runs") or 1)),
                execution_policy={
                    "max_concurrent_runs": max(1, int(action_payload.get("max_concurrent_runs") or 1)),
                    "pause_on_failure": bool(action_payload.get("pause_on_failure")),
                    "auto_resume": bool(action_payload.get("auto_resume")),
                    "review_required": bool(action_payload.get("review_required")),
                },
                source_conversation_id=str(action.get("thread_id") or "").strip(),
            )
            record_thread_event(thread=thread, event_type="thread_created", payload={"priority": thread.priority, "status": thread.status})
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": f"Created XCO thread {thread.title}.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"thread": _coordination_thread_summary(thread)},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id), "thread_id": str(thread.id)}}
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        if action_type == ConversationActionType.LIST_THREADS.value:
            rows = [
                _coordination_thread_summary(item)
                for item in _active_coordination_threads_for_workspace(workspace).order_by("-updated_at", "-created_at")[:100]
            ]
            return _direct_panel_intent_response(
                request_id=request_id,
                summary=f"Found {len(rows)} XCO thread(s).",
                panel_key="thread_list",
                params={"workspace_id": str(workspace.id)},
                prompt_interpretation=prompt_interpretation,
                extra_payload={
                    "intent": intent_payload,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"threads": rows},
                },
            )
        if thread is None:
            return JsonResponse(
                {
                    "status": "IntentClarificationRequired",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": "No XCO thread could be resolved from the conversation context.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": False,
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                },
                status=409,
            )
        if action_type == ConversationActionType.PAUSE_THREAD.value:
            transition_thread_status(thread, "paused")
        elif action_type == ConversationActionType.RESUME_THREAD.value:
            response_payload, status_code = _review_coordination_thread(thread=thread, identity=identity, review_action="resume_thread")
            if status_code >= 400:
                return JsonResponse(
                    {
                        "status": response_payload.get("status") or "ValidationError",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": response_payload.get("summary") or f"{thread.title} could not be resumed.",
                        "intent": intent_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": action,
                        "operation_result": False,
                        "result": {"thread": response_payload.get("thread")},
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    },
                    status=status_code,
                )
            detail = response_payload.get("thread") if isinstance(response_payload.get("thread"), dict) else _coordination_thread_detail(thread)
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": response_payload.get("summary") or f"Resumed XCO thread {thread.title}.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"thread": detail},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id), "thread_id": str(thread.id)}}
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        elif action_type == ConversationActionType.PRIORITIZE_THREAD.value:
            next_priority = str(action_payload.get("priority") or "high").strip().lower() or "high"
            if next_priority not in THREAD_PRIORITY_ORDER:
                return JsonResponse({"status": "ValidationError", "summary": "Priority must be critical, high, normal, or low."}, status=400)
            previous_priority = thread.priority
            thread.priority = next_priority
            thread.save(update_fields=["priority", "updated_at"])
            if previous_priority != next_priority:
                record_thread_event(thread=thread, event_type="thread_priority_changed", payload={"previous_priority": previous_priority, "priority": next_priority})
        detail = _coordination_thread_detail(thread)
        summary = (
            f"Paused XCO thread {thread.title}."
            if action_type == ConversationActionType.PAUSE_THREAD.value
            else f"Reviewing XCO thread {thread.title}."
            if action_type == ConversationActionType.SHOW_THREAD_REVIEW.value
            else f"Updated XCO thread {thread.title}."
            if action_type == ConversationActionType.PRIORITIZE_THREAD.value
            else _thread_diagnostic_summary_text(detail)
            if summary_mode == "thread_diagnostic_summary"
            else _thread_progress_summary_text(detail)
            if summary_mode == "thread_progress_summary"
            else f"Showing XCO thread {thread.title}."
        )
        direct_thread_target = _direct_panel_target_for_conversation_action(
            action_type=action_type,
            workspace_id=str(workspace.id),
            action_payload=action_payload,
            target={"id": str(thread.id)},
        )
        if direct_thread_target:
            panel_key, params = direct_thread_target
            return _direct_panel_intent_response(
                request_id=request_id,
                summary=summary,
                panel_key=panel_key,
                params=params,
                prompt_interpretation=prompt_interpretation,
                extra_payload={
                    "summary_type": (
                        "thread_diagnostic_summary"
                        if summary_mode == "thread_diagnostic_summary"
                        else "thread_progress_summary"
                        if summary_mode == "thread_progress_summary"
                        else None
                    ),
                    "intent": intent_payload,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"thread": detail},
                },
            )
        return JsonResponse(
            {
                "status": "DraftReady",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": summary,
                "summary_type": (
                    "thread_diagnostic_summary"
                    if summary_mode == "thread_diagnostic_summary"
                    else "thread_progress_summary"
                    if summary_mode == "thread_progress_summary"
                    else None
                ),
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": True,
                "result": {"thread": detail},
                "next_actions": [
                    {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id), "thread_id": str(thread.id)}}
                ],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
        )

    if action_type in {
        ConversationActionType.CREATE_GOAL.value,
        ConversationActionType.DECOMPOSE_GOAL.value,
        ConversationActionType.SUMMARIZE_PLAN.value,
        ConversationActionType.QUEUE_FIRST_SLICE.value,
        ConversationActionType.LIST_GOALS.value,
        ConversationActionType.SHOW_GOAL.value,
        ConversationActionType.CREATE_CAMPAIGN.value,
        ConversationActionType.LIST_CAMPAIGNS.value,
        ConversationActionType.SHOW_CAMPAIGN.value,
        ConversationActionType.LIST_APPLICATION_FACTORIES.value,
        ConversationActionType.OPEN_COMPOSER.value,
        ConversationActionType.GENERATE_APPLICATION_PLAN.value,
        ConversationActionType.APPLY_APPLICATION_PLAN.value,
        ConversationActionType.SHOW_APPLICATION.value,
        ConversationActionType.APPROVE_PLAN.value,
        ConversationActionType.APPROVE_RECOMMENDATION.value,
        ConversationActionType.DEFER_EXECUTION.value,
        ConversationActionType.ADJUST_PLAN.value,
        ConversationActionType.RECOMMEND_NEXT_SLICE.value,
        ConversationActionType.QUEUE_NEXT_SLICE.value,
    }:
        action_payload = ((action.get("payload") or {}) if isinstance(action.get("payload"), dict) else {}).get("action_payload")
        action_payload = action_payload if isinstance(action_payload, dict) else {}
        summary_mode = str(action_payload.get("summary_mode") or "").strip()
        target_kind = str(target.get("kind") or "").strip()
        target_id = str(target.get("id") or "").strip()
        application_id = target_id if target_kind == "application" else ""
        application_plan_id = target_id if target_kind == "application_plan" else ""
        goal_id = target_id if target_kind == "goal" else ""
        campaign_id = target_id if target_kind == "campaign" else ""
        goal: Optional[Goal] = None
        if goal_id:
            goal = Goal.objects.filter(id=goal_id, workspace=workspace).first()
        campaign: Optional[Campaign] = None
        if campaign_id:
            campaign = Campaign.objects.filter(id=campaign_id, workspace=workspace).first()
        application: Optional[Application] = None
        if application_id:
            application = Application.objects.filter(id=application_id, workspace=workspace).first()
        application_plan: Optional[ApplicationPlan] = None
        if application_plan_id:
            application_plan = ApplicationPlan.objects.filter(id=application_plan_id, workspace=workspace).first()
        if action_type == ConversationActionType.LIST_APPLICATION_FACTORIES.value:
            rows = [_serialize_application_factory_summary(definition) for definition in list_application_factories()]
            summary = f"Found {len(rows)} application factor{'ies' if len(rows) != 1 else 'y'}."
            return _direct_panel_intent_response(
                request_id=request_id,
                summary=summary,
                panel_key="composer_detail",
                params={"workspace_id": str(workspace.id)},
                prompt_interpretation=prompt_interpretation,
                extra_payload={
                    "intent": intent_payload,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"factories": rows},
                },
            )
        if action_type == ConversationActionType.OPEN_COMPOSER.value:
            params = {
                "workspace_id": str(workspace.id),
            }
            if action_payload.get("factory_key"):
                params["factory_key"] = str(action_payload.get("factory_key"))
            if action_payload.get("application_plan_id"):
                params["application_plan_id"] = str(action_payload.get("application_plan_id"))
            if action_payload.get("application_id"):
                params["application_id"] = str(action_payload.get("application_id"))
            if action_payload.get("goal_id"):
                params["goal_id"] = str(action_payload.get("goal_id"))
            if action_payload.get("thread_id"):
                params["thread_id"] = str(action_payload.get("thread_id"))
            return _direct_panel_intent_response(
                request_id=request_id,
                summary="Opening the unified composer.",
                panel_key="composer_detail",
                params=params,
                prompt_interpretation=prompt_interpretation,
                extra_payload={
                    "intent": intent_payload,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"workspace_id": str(workspace.id)},
                },
            )
        if action_type == ConversationActionType.LIST_CAMPAIGNS.value:
            rows = [
                _serialize_campaign_summary(item)
                for item in Campaign.objects.filter(workspace=workspace, archived=False).order_by("-updated_at", "-created_at")[:200]
            ]
            return _direct_panel_intent_response(
                request_id=request_id,
                summary=f"Found {len(rows)} campaign(s).",
                panel_key="campaign_list",
                params={"workspace_id": str(workspace.id)},
                prompt_interpretation=prompt_interpretation,
                extra_payload={
                    "intent": intent_payload,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"campaigns": rows},
                },
            )
        if action_type == ConversationActionType.CREATE_CAMPAIGN.value:
            name = str(action_payload.get("name") or action_payload.get("title") or prompt).strip() or "New Campaign"
            campaign_type = str(action_payload.get("campaign_type") or "generic").strip() or "generic"
            allowed_types = {
                str(item.get("key") or "").strip()
                for item in _campaign_type_definitions_for_workspace(workspace)
                if isinstance(item, dict)
            }
            if campaign_type not in allowed_types:
                campaign_type = "generic"
            campaign = Campaign.objects.create(
                workspace=workspace,
                slug=_next_available_campaign_slug(str(workspace.id), name),
                name=name[:240],
                campaign_type=campaign_type,
                status="draft",
                description=str(action_payload.get("description") or "").strip(),
                created_by=identity,
            )
            detail = _serialize_campaign_detail(campaign, workspace=workspace)
            action = {
                **action,
                "target_object": {
                    "kind": "campaign",
                    "id": str(campaign.id),
                    "label": campaign.name,
                    "workspace_id": str(workspace.id),
                },
            }
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": f"Created campaign {campaign.name}.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"campaign": detail},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "campaign_detail", "label": "Open Campaign", "params": {"workspace_id": str(workspace.id), "campaign_id": str(campaign.id)}}
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        if action_type == ConversationActionType.SHOW_CAMPAIGN.value:
            if campaign is None:
                return JsonResponse(
                    {
                        "status": "IntentClarificationRequired",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": "No campaign could be resolved from the conversation context.",
                        "intent": intent_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": action,
                        "operation_result": False,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    },
                    status=409,
                )
            detail = _serialize_campaign_detail(campaign, workspace=workspace)
            direct_campaign_target = _direct_panel_target_for_conversation_action(
                action_type=action_type,
                workspace_id=str(workspace.id),
                action_payload=action_payload,
                target={"id": str(campaign.id)},
            )
            if direct_campaign_target:
                panel_key, params = direct_campaign_target
                return _direct_panel_intent_response(
                    request_id=request_id,
                    summary=f"Showing campaign {campaign.name}.",
                    panel_key=panel_key,
                    params=params,
                    prompt_interpretation=prompt_interpretation,
                    extra_payload={
                        "intent": intent_payload,
                        "conversation_action": action,
                        "operation_result": True,
                        "result": {"campaign": detail},
                    },
                )
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": f"Showing campaign {campaign.name}.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"campaign": detail},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "campaign_detail", "label": "Open Campaign", "params": {"workspace_id": str(workspace.id), "campaign_id": str(campaign.id)}}
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        if action_type == ConversationActionType.GENERATE_APPLICATION_PLAN.value:
            objective = str(action_payload.get("objective") or action_payload.get("reference") or prompt).strip()
            plan, factory_definition, generated_plan, created = create_or_get_application_plan(
                workspace=workspace,
                objective=objective,
                requested_by=identity,
                source_conversation_id=str(action.get("thread_id") or "").strip(),
                factory_key=str(action_payload.get("factory_key") or "").strip(),
                application_name=str(action_payload.get("application_name") or "").strip(),
            )
            detail = _serialize_application_plan_detail(plan)
            action = {
                **action,
                "target_object": {
                    **target,
                    "id": str(plan.id),
                    "label": plan.name,
                    "workspace_id": str(workspace.id),
                },
            }
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": f"Generated a reviewable application plan for {plan.name}.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {
                        "application_plan": detail,
                        "factory": _serialize_application_factory_summary(factory_definition),
                        "generated_plan": generated_plan.model_dump(mode="json"),
                        "created": created,
                    },
                    "application_plan_id": str(plan.id),
                    "next_actions": [
                        {
                            "action": "OpenPanel",
                            "panel_key": "composer_detail",
                            "label": "Open Composer",
                            "params": {
                                "workspace_id": str(workspace.id),
                                "factory_key": str(plan.source_factory_key or action_payload.get("factory_key") or ""),
                                "application_plan_id": str(plan.id),
                            },
                        }
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        if action_type == ConversationActionType.APPLY_APPLICATION_PLAN.value:
            if application_plan is None and context.active_application_plan_id:
                application_plan = ApplicationPlan.objects.filter(id=context.active_application_plan_id, workspace=workspace).first()
            if application_plan is None:
                return JsonResponse(
                    {
                        "status": "IntentClarificationRequired",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": "No application plan could be resolved from the conversation context.",
                        "intent": intent_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": action,
                        "operation_result": False,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    },
                    status=409,
                )
            application, created = apply_application_plan(application_plan=application_plan, user=user)
            application.refresh_from_db()
            application_plan.refresh_from_db()
            action = {
                **action,
                "target_object": {
                    "kind": "application",
                    "id": str(application.id),
                    "label": application.name,
                    "workspace_id": str(workspace.id),
                },
            }
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": (
                        f"Applied application plan for {application.name} into durable goals, threads, and work items."
                        if created
                        else f"Application plan for {application.name} was already applied."
                    ),
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {
                        "application": _serialize_application_detail(application),
                        "application_plan": _serialize_application_plan_detail(application_plan),
                    },
                    "application_id": str(application.id),
                    "application_plan_id": str(application_plan.id),
                    "next_actions": [
                        {
                            "action": "OpenPanel",
                            "panel_key": "composer_detail",
                            "label": "Open Composer",
                            "params": {
                                "workspace_id": str(workspace.id),
                                "application_id": str(application.id),
                                "application_plan_id": str(application_plan.id),
                            },
                        }
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        if action_type == ConversationActionType.SHOW_APPLICATION.value:
            if application is None and context.active_application_id:
                application = Application.objects.filter(id=context.active_application_id, workspace=workspace).first()
            if application is None:
                return JsonResponse(
                    {
                        "status": "IntentClarificationRequired",
                        "artifact_type": "Workspace",
                        "artifact_id": None,
                        "summary": "No application could be resolved from the conversation context.",
                        "intent": intent_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": action,
                        "operation_result": False,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    },
                    status=409,
                )
            detail = _serialize_application_detail(application)
            return _direct_panel_intent_response(
                request_id=request_id,
                summary=f"Showing application {application.name}.",
                panel_key="composer_detail",
                params={"workspace_id": str(workspace.id), "application_id": str(application.id)},
                prompt_interpretation=prompt_interpretation,
                extra_payload={
                    "intent": intent_payload,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"application": detail},
                    "application_id": str(application.id),
                },
            )
        if action_type == ConversationActionType.LIST_GOALS.value:
            goal_objects = list(_active_goals_for_workspace(workspace).order_by("-updated_at", "-created_at")[:100])
            goals = [_serialize_goal_summary(item) for item in goal_objects]
            portfolio_state = _build_goal_portfolio_payload(goal_objects)
            recommended_goal = portfolio_state.get("recommended_goal") if isinstance(portfolio_state, dict) else None
            portfolio_insights = portfolio_state.get("insights") if isinstance(portfolio_state, dict) else []
            if summary_mode == "portfolio_health_summary":
                active_goals = sum(1 for item in (portfolio_state.get("goals") or []) if item.get("health_status") == "active")
                blocked_goals = sum(1 for item in (portfolio_state.get("goals") or []) if item.get("health_status") == "blocked")
                summary = (
                    f"Portfolio health: {active_goals} active goal(s), {blocked_goals} blocked goal(s), "
                    f"and {len(goals)} total goal(s)."
                )
            elif summary_mode == "portfolio_recommendation_summary":
                if isinstance(recommended_goal, dict) and recommended_goal.get("title"):
                    summary = (
                        f"{recommended_goal['title']} is the strongest current portfolio candidate. "
                        f"{recommended_goal.get('summary') or recommended_goal.get('reasoning') or ''}"
                    ).strip()
                else:
                    summary = "No portfolio-level goal recommendation is currently actionable."
            elif summary_mode == "portfolio_insight_summary":
                first_insight = portfolio_insights[0] if portfolio_insights else None
                if isinstance(first_insight, dict) and first_insight.get("summary"):
                    summary = str(first_insight["summary"])
                else:
                    summary = f"Found {len(goals)} goal(s) with no dominant portfolio issue right now."
            else:
                summary = f"Found {len(goals)} goal(s)."
            if not summary_mode:
                return _direct_panel_intent_response(
                    request_id=request_id,
                    summary=summary,
                    panel_key="composer_detail",
                    params={"workspace_id": str(workspace.id)},
                    prompt_interpretation=prompt_interpretation,
                    extra_payload={
                        "intent": intent_payload,
                        "conversation_action": action,
                        "operation_result": True,
                        "result": {"goals": goals, "portfolio_state": portfolio_state},
                    },
                )
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": summary,
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"goals": goals, "portfolio_state": portfolio_state},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id)}}
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        if action_type == ConversationActionType.CREATE_GOAL.value:
            title = str(action_payload.get("title") or target.get("label") or prompt).strip() or "New Goal"
            description = str(action_payload.get("description") or prompt).strip()
            goal = Goal.objects.create(
                workspace=workspace,
                title=title[:240],
                description=description,
                source_conversation_id=str(action.get("thread_id") or "").strip(),
                requested_by=identity,
                goal_type=str(action_payload.get("goal_type") or infer_goal_type(title, description)).strip() or "build_system",
                planning_status="proposed",
                priority=str(action_payload.get("priority") or "high").strip() or "high",
            )
            plan = decompose_goal(goal)
            persist_goal_plan(goal, plan, user=user)
            goal.refresh_from_db()
            detail = _serialize_goal_detail(goal)
            action = {
                **action,
                "target_object": {
                    **target,
                    "id": str(goal.id),
                    "label": goal.title,
                    "workspace_id": str(workspace.id),
                },
            }
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": f"Created goal {goal.title} and decomposed it into reviewable threads and work items.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"goal": detail},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id), "goal_id": str(goal.id)}}
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        if goal is None:
            return JsonResponse(
                {
                    "status": "IntentClarificationRequired",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": "No goal could be resolved from the conversation context.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": False,
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                },
                status=409,
            )
        if action_type == ConversationActionType.DECOMPOSE_GOAL.value:
            plan = decompose_goal(goal)
            persist_goal_plan(goal, plan, user=user)
            goal.refresh_from_db()
            summary = f"Decomposed goal {goal.title} into reviewable threads and work items."
        elif action_type == ConversationActionType.SUMMARIZE_PLAN.value:
            detail = _serialize_goal_detail(goal)
            loop_summary = detail.get("development_loop_summary") if isinstance(detail.get("development_loop_summary"), dict) else {}
            next_slice = loop_summary.get("recommended_next_slice") if isinstance(loop_summary, dict) else {}
            summary = str((next_slice or {}).get("summary") or "").strip() or serialize_goal_summary(goal).get("planning_summary") or f"Showing plan summary for {goal.title}."
        elif action_type == ConversationActionType.APPROVE_PLAN.value:
            if not valid_goal_transition(goal.planning_status, "in_progress"):
                return JsonResponse({"status": "ValidationError", "summary": f"Goal {goal.title} cannot transition to in_progress from {goal.planning_status}."}, status=409)
            goal.planning_status = "in_progress"
            goal.save(update_fields=["planning_status", "updated_at"])
            summary = f"Approved plan for {goal.title}."
        elif action_type in {ConversationActionType.APPROVE_RECOMMENDATION.value, ConversationActionType.QUEUE_NEXT_SLICE.value}:
            requested_action = (
                "approve_and_queue"
                if action_type == ConversationActionType.APPROVE_RECOMMENDATION.value
                else "queue_next_slice"
            )
            submitted_recommendation_id = str((((action.get("payload") or {}).get("action_payload") or {}).get("recommendation_id")) or "").strip() or None
            approval = _approve_goal_recommendation(
                goal=goal,
                identity=identity,
                requested_action_type=requested_action,
                submitted_recommendation_id=submitted_recommendation_id,
            )
            if approval["status"] in {"rejected", "not_ready", "invalid_thread_state", "no_recommendation", "stale_recommendation"}:
                return JsonResponse(
                    {
                        "status": approval["status"],
                        "summary": approval["summary"],
                        "intent": intent_payload,
                        "prompt_interpretation": prompt_interpretation,
                        "conversation_action": action,
                        "operation_result": False,
                        "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                    },
                    status=409,
                )
            goal.refresh_from_db()
            detail = _serialize_goal_detail(goal)
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": approval["summary"],
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"goal": detail, "queue_seed": approval.get("queue_seed")},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id), "goal_id": str(goal.id)}}
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        elif action_type == ConversationActionType.DEFER_EXECUTION.value:
            summary = f"Deferred execution for {goal.title}."
        elif action_type == ConversationActionType.ADJUST_PLAN.value:
            if not valid_goal_transition(goal.planning_status, "proposed"):
                return JsonResponse({"status": "ValidationError", "summary": f"Goal {goal.title} cannot transition to proposed from {goal.planning_status}."}, status=409)
            goal.planning_status = "proposed"
            goal.save(update_fields=["planning_status", "updated_at"])
            summary = f"Marked {goal.title} for plan adjustment."
        elif action_type == ConversationActionType.QUEUE_FIRST_SLICE.value:
            seeded = _activate_goal_first_slice(goal)
            goal.refresh_from_db()
            detail = _serialize_goal_detail(goal)
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": f"Queued the first executable slice for {goal.title}.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"goal": detail, "queue_seed": seeded},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id), "goal_id": str(goal.id), "thread_id": str(seeded.get("thread_id") or "")}},
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        elif action_type == ConversationActionType.RECOMMEND_NEXT_SLICE.value:
            recommendation = recommend_next_slice(goal)
            detail = _serialize_goal_detail(goal)
            recommendation_payload = {
                "recommendation_id": recommendation.recommendation_id,
                "goal_id": recommendation.goal_id,
                "thread_id": recommendation.thread_id,
                "thread_title": recommendation.thread_title,
                "work_item_id": recommendation.work_item_id,
                "work_item_title": recommendation.work_item_title,
                "recommended_work_items": [
                    {
                        "id": item.id,
                        "title": item.title,
                        "thread_id": item.thread_id,
                        "thread_title": item.thread_title,
                    }
                    for item in recommendation.recommended_work_items
                ],
                "queue_suggestion": {
                    "action_type": recommendation.queue_suggestion.action_type,
                    "thread_id": recommendation.queue_suggestion.thread_id,
                    "work_item_id": recommendation.queue_suggestion.work_item_id,
                    "reason": recommendation.queue_suggestion.reason,
                    "summary": recommendation.queue_suggestion.summary,
                }
                if recommendation.queue_suggestion
                else None,
                "reasoning_summary": recommendation.reasoning_summary,
                "summary": recommendation.summary,
            }
            return JsonResponse(
                {
                    "status": "DraftReady",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": recommendation.summary,
                    "summary_type": "next_slice_recommendation",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"goal": detail, "recommendation": recommendation_payload},
                    "next_actions": [
                        {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id), "goal_id": str(goal.id)}}
                    ],
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                }
            )
        else:
            detail = _serialize_goal_detail(goal)
            loop_summary = detail.get("development_loop_summary") if isinstance(detail.get("development_loop_summary"), dict) else {}
            summary = (
                _goal_progress_summary_text(detail)
                if summary_mode == "goal_progress_summary"
                else _goal_diagnostic_summary_text(detail)
                if summary_mode == "goal_diagnostic_summary"
                else _goal_insight_summary_text(detail)
                if summary_mode == "goal_insight_summary"
                else str(((loop_summary.get("recommended_next_slice") or {}) if isinstance(loop_summary, dict) else {}).get("summary") or "").strip() or f"Showing goal {goal.title}."
            )
        detail = locals().get("detail") if isinstance(locals().get("detail"), dict) else _serialize_goal_detail(goal)
        direct_goal_target = _direct_panel_target_for_conversation_action(
            action_type=action_type,
            workspace_id=str(workspace.id),
            action_payload=action_payload,
            target={"id": str(goal.id)},
        )
        if direct_goal_target:
            panel_key, params = direct_goal_target
            return _direct_panel_intent_response(
                request_id=request_id,
                summary=summary,
                panel_key=panel_key,
                params=params,
                prompt_interpretation=prompt_interpretation,
                extra_payload={
                    "summary_type": (
                        "goal_progress_summary"
                        if summary_mode == "goal_progress_summary"
                        else "goal_diagnostic_summary"
                        if summary_mode == "goal_diagnostic_summary"
                        else "goal_insight_summary"
                        if summary_mode == "goal_insight_summary"
                        else None
                    ),
                    "intent": intent_payload,
                    "conversation_action": action,
                    "operation_result": True,
                    "result": {"goal": detail},
                },
            )
        return JsonResponse(
            {
                "status": "DraftReady",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": summary,
                "summary_type": (
                    "goal_progress_summary"
                    if summary_mode == "goal_progress_summary"
                    else "goal_diagnostic_summary"
                    if summary_mode == "goal_diagnostic_summary"
                    else "goal_insight_summary"
                    if summary_mode == "goal_insight_summary"
                    else None
                ),
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": True,
                "result": {"goal": detail},
                "next_actions": [
                    {"action": "OpenPanel", "panel_key": "composer_detail", "label": "Open Composer", "params": {"workspace_id": str(workspace.id), "goal_id": str(goal.id)}}
                ],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
        )

    if action_type == ConversationActionType.SHOW_ARTIFACT_ANALYSIS.value:
        action_payload = ((action.get("payload") or {}) if isinstance(action.get("payload"), dict) else {}).get("action_payload")
        action_payload = action_payload if isinstance(action_payload, dict) else {}
        artifact_id = str(action_payload.get("artifact_id") or target.get("id") or "").strip()
        run_id = str(action_payload.get("run_id") or "").strip()
        if not artifact_id or not run_id:
            return JsonResponse(
                {
                    "status": "IntentClarificationRequired",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": "No artifact could be resolved from the conversation context.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": False,
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                },
                status=409,
            )
        try:
            detail = _runtime_run_artifact_detail_for_conversation(workspace=workspace, run_id=run_id, artifact_id=artifact_id)
        except RuntimeError as exc:
            return JsonResponse(
                {
                    "status": "ValidationError",
                    "artifact_type": "Workspace",
                    "artifact_id": None,
                    "summary": str(exc) or "Artifact analysis is unavailable.",
                    "intent": intent_payload,
                    "prompt_interpretation": prompt_interpretation,
                    "conversation_action": action,
                    "operation_result": False,
                    "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
                },
                status=409,
            )
        return JsonResponse(
            {
                "status": "DraftReady",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": _artifact_analysis_summary_text(detail),
                "summary_type": "artifact_analysis_summary",
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": True,
                "result": {"artifact": detail},
                "next_actions": [
                    {
                        "action": "OpenPanel",
                        "panel_key": "artifact_detail",
                        "label": "Open Artifact",
                        "params": {"runtime_run_id": run_id, "runtime_artifact_id": artifact_id},
                    }
                ],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
        )

    run_id = str(target.get("id") or "").strip()
    if not run_id:
        return JsonResponse(
            {
                "status": "IntentClarificationRequired",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": "No run could be resolved from the conversation context.",
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": False,
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            },
            status=409,
        )

    if action_type == ConversationActionType.PAUSE_RUN.value:
        runtime = _runtime_run_control("POST", f"/api/v1/runs/{run_id}/pause")
        return JsonResponse(
            {
                "status": "DraftReady",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": f"Pause requested for run {run_id}.",
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": True,
                "result": {"run": runtime},
                "next_actions": [
                    {
                        "action": "OpenPanel",
                        "panel_key": "run_detail",
                        "label": "Open Run",
                        "params": {"run_id": run_id},
                    }
                ],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
        )
    if action_type == ConversationActionType.CONTINUE_RUN.value:
        runtime = _runtime_run_control("POST", f"/api/v1/runs/{run_id}/continue")
        return JsonResponse(
            {
                "status": "DraftReady",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": f"Re-queued run {run_id}.",
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": True,
                "result": {"run": runtime},
                "next_actions": [
                    {
                        "action": "OpenPanel",
                        "panel_key": "run_detail",
                        "label": "Open Run",
                        "params": {"run_id": run_id},
                    }
                ],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
        )
    if action_type == ConversationActionType.RETRY_RUN.value:
        base_run = _fetch_runtime_run_payload(uuid.UUID(run_id))
        if not base_run:
            raise RuntimeError("runtime run not found")
        payload = base_run.get("prompt_payload") if isinstance(base_run.get("prompt_payload"), dict) else {}
        if not payload:
            raise RuntimeError("runtime prompt payload unavailable")
        policy = payload.get("policy") if isinstance(payload.get("policy"), dict) else {}
        action_policy = (
            ((action.get("payload") or {}) if isinstance(action.get("payload"), dict) else {}).get("policy")
            if isinstance((action.get("payload") or {}), dict)
            else {}
        )
        if isinstance(action_policy, dict):
            policy.update(
                {
                    "auto_continue": bool(action_policy.get("auto_continue", policy.get("auto_continue"))),
                    "require_human_review_on_failure": bool(
                        action_policy.get("require_human_review_on_failure", policy.get("require_human_review_on_failure", True))
                    ),
                }
            )
        payload["policy"] = policy
        payload["run_id"] = str(uuid.uuid4())
        runtime = _seed_api_request(method="POST", path="/api/v1/runtime/runs", payload=payload, timeout=30)
        body = runtime.json() if runtime.content else {}
        if runtime.status_code >= 400:
            raise RuntimeError(str((body or {}).get("detail") or "runtime retry failed"))
        return JsonResponse(
            {
                "status": "DraftReady",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": f"Queued retry run {str((body or {}).get('id') or payload['run_id'])}.",
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": True,
                "result": {"run": body},
                "next_actions": [
                    {
                        "action": "OpenPanel",
                        "panel_key": "run_detail",
                        "label": "Open Run",
                        "params": {"run_id": str((body or {}).get("id") or payload["run_id"])},
                    }
                ],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
        )
    if action_type in {ConversationActionType.SHOW_STATUS.value, ConversationActionType.SUMMARIZE_RUN.value, ConversationActionType.REQUEST_REVIEW.value}:
        detail = _fetch_runtime_run_detail_payload(uuid.UUID(run_id))
        if not detail:
            raise RuntimeError("runtime run detail unavailable")
        action_payload = ((action.get("payload") or {}) if isinstance(action.get("payload"), dict) else {}).get("action_payload")
        action_payload = action_payload if isinstance(action_payload, dict) else {}
        detail_view = str(action_payload.get("detail_view") or "").strip().lower()
        result: Dict[str, Any] = {"run": detail}
        summary = str(detail.get("summary") or f"Run {run_id} is {detail.get('status') or 'unknown'}.")
        if detail_view == "logs":
            artifacts = detail.get("artifacts") if isinstance(detail.get("artifacts"), list) else []
            result["logs"] = [row for row in artifacts if isinstance(row, dict) and str(row.get("artifact_type") or "") == "log"]
            summary = f"Found {len(result['logs'])} log artifact(s) for run {run_id}."
        elif detail_view == "artifacts":
            result["artifacts"] = detail.get("artifacts") if isinstance(detail.get("artifacts"), list) else []
            summary = f"Found {len(result['artifacts'])} artifact(s) for run {run_id}."
        elif action_type == ConversationActionType.REQUEST_REVIEW.value:
            summary = f"Run {run_id} is ready for review."
        return JsonResponse(
            {
                "status": "DraftReady",
                "artifact_type": "Workspace",
                "artifact_id": None,
                "summary": summary,
                "intent": intent_payload,
                "prompt_interpretation": prompt_interpretation,
                "conversation_action": action,
                "operation_result": True,
                "result": result,
                "next_actions": [
                    {
                        "action": "OpenPanel",
                        "panel_key": "run_detail",
                        "label": "Open Run",
                        "params": {"run_id": run_id},
                    }
                ],
                "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
            }
        )

    return JsonResponse(
        {
            "status": "UnsupportedIntent",
            "artifact_type": "Workspace",
            "artifact_id": None,
            "summary": "Conversation action is not supported.",
            "intent": intent_payload,
            "prompt_interpretation": prompt_interpretation,
            "conversation_action": action,
            "operation_result": False,
            "audit": {"request_id": request_id, "timestamp": timezone.now().isoformat()},
        },
        status=400,
    )


def _submit_dev_task_runtime_run(
    task: DevTask,
    *,
    workspace: Workspace,
    user,
    agent_override_id: Optional[str] = None,
) -> Dict[str, Any]:
    source = _load_dev_task_runtime_source(task)
    ensure_execution_brief_ready(task, work_item=source["work_item"])
    agent_selection = _resolve_dev_task_agent_selection(task, agent_override_id=agent_override_id)
    payload = _build_dev_task_runtime_payload(task, workspace, agent_selection=agent_selection)
    response = _seed_api_request(method="POST", path="/api/v1/runtime/runs", payload=payload, timeout=30)
    content_type = str(response.headers.get("content-type") or "").lower()
    if "application/json" not in content_type:
        raise RuntimeError("unexpected xyn-core response")
    body = response.json() if response.content else {}
    if response.status_code >= 400:
        message = body.get("detail") if isinstance(body, dict) else None
        raise RuntimeError(str(message or "runtime submission failed"))
    runtime_run_id = body.get("id") if isinstance(body, dict) else None
    task.runtime_run_id = runtime_run_id or payload["run_id"]
    task.runtime_workspace_id = workspace.id
    task.status = "queued"
    task.last_error = ""
    task.target_repo = str(((payload.get("target") or {}) if isinstance(payload.get("target"), dict) else {}).get("repo") or task.target_repo or "")
    task.target_branch = str(((payload.get("target") or {}) if isinstance(payload.get("target"), dict) else {}).get("branch") or task.target_branch or "")
    next_policy = (payload.get("policy") if isinstance(payload.get("policy"), dict) else {}) or {}
    current_policy = task.execution_policy if isinstance(task.execution_policy, dict) else {}
    task.execution_policy = {**current_policy, **next_policy} if current_policy else (next_policy or {})
    task.locked_by = ""
    task.locked_at = None
    task.updated_by = user
    task.save(
        update_fields=[
            "runtime_run_id",
            "runtime_workspace_id",
            "status",
            "last_error",
            "target_repo",
            "target_branch",
            "execution_policy",
            "locked_by",
            "locked_at",
            "updated_by",
            "updated_at",
        ]
    )
    return {"run_id": str(task.runtime_run_id), "status": task.status, "agent_selection": agent_selection}


def _conversation_default_repo(prompt: str) -> str:
    text = str(prompt or "").strip().lower()
    if "xyn-platform" in text:
        return "xyn-platform"
    if re.search(r"\bxyn[- ]core\b|\bcore repo\b", text):
        return "xyn"
    return str(os.environ.get("XYN_CONVERSATION_DEFAULT_RUNTIME_REPO") or "xyn-platform").strip() or "xyn-platform"


def _conversation_default_branch() -> str:
    return str(os.environ.get("XYN_CONVERSATION_DEFAULT_RUNTIME_BRANCH") or "develop").strip() or "develop"


def _conversation_work_item_id(reference: str) -> str:
    token = slugify(str(reference or "").strip())[:60]
    if token:
        return token
    return f"conversation-{uuid.uuid4().hex[:10]}"


def _find_conversation_dev_task(workspace: Workspace, action: Dict[str, Any]) -> Optional[DevTask]:
    target = action.get("target_object") if isinstance(action.get("target_object"), dict) else {}
    payload = action.get("payload") if isinstance(action.get("payload"), dict) else {}
    reference = str(target.get("reference") or "") or str(((payload.get("action_payload") or {}) if isinstance(payload.get("action_payload"), dict) else {}).get("reference") or "")
    task_id = str(target.get("id") or "").strip()
    if task_id:
        task = DevTask.objects.filter(id=task_id).first()
        if task:
            return task
    work_item_id = _conversation_work_item_id(reference) if reference else ""
    if work_item_id:
        task = DevTask.objects.filter(runtime_workspace_id=workspace.id, work_item_id=work_item_id).order_by("-updated_at", "-created_at").first()
        if task:
            return task
    return None


def _ensure_conversation_dev_task(*, workspace: Workspace, action: Dict[str, Any], prompt: str, user) -> DevTask:
    existing = _find_conversation_dev_task(workspace, action)
    if existing:
        return existing
    target = action.get("target_object") if isinstance(action.get("target_object"), dict) else {}
    payload = action.get("payload") if isinstance(action.get("payload"), dict) else {}
    action_payload = payload.get("action_payload") if isinstance(payload.get("action_payload"), dict) else {}
    policy = payload.get("policy") if isinstance(payload.get("policy"), dict) else {}
    conversation_thread_id = str(action.get("thread_id") or "").strip()
    coordination_thread = None
    coordination_thread_id = str(action_payload.get("coordination_thread_id") or action_payload.get("thread_id") or "").strip()
    if coordination_thread_id:
        coordination_thread = CoordinationThread.objects.filter(id=coordination_thread_id, workspace=workspace).first()
    elif conversation_thread_id:
        candidates = list(
            CoordinationThread.objects.filter(
                workspace=workspace,
                source_conversation_id=conversation_thread_id,
                status__in=["active", "queued", "paused"],
            ).order_by("-updated_at", "-created_at")[:2]
        )
        if len(candidates) == 1:
            coordination_thread = candidates[0]
    reference = str(target.get("reference") or action_payload.get("reference") or prompt).strip()
    title = str(target.get("label") or reference or prompt).strip() or "Conversation work item"
    target_resolution = resolve_development_target(goal=coordination_thread.goal if coordination_thread and coordination_thread.goal_id else None)
    resolved_repo = str(target_resolution.repository_slug or "").strip()
    resolved_branch = str(target_resolution.branch or "").strip()
    return DevTask.objects.create(
        title=title[:240],
        description=str(prompt or "").strip(),
        task_type="codegen",
        status="queued",
        max_attempts=2,
        source_entity_type="conversation",
        source_entity_id=uuid.uuid4(),
        source_conversation_id=conversation_thread_id,
        intent_type=str(action.get("intent_type") or "").strip(),
        target_repo=str(action_payload.get("target_repo") or resolved_repo or _conversation_default_repo(prompt)).strip(),
        target_branch=str(action_payload.get("target_branch") or resolved_branch or _conversation_default_branch()).strip(),
        execution_policy=policy or {},
        coordination_thread=coordination_thread,
        work_item_id=_conversation_work_item_id(reference),
        context_purpose="conversation",
        runtime_workspace_id=workspace.id,
        created_by=user,
        updated_by=user,
    )


def _conversation_runtime_payload(*, task: DevTask, workspace: Workspace, action: Dict[str, Any], prompt: str) -> Dict[str, Any]:
    payload = action.get("payload") if isinstance(action.get("payload"), dict) else {}
    policy = payload.get("policy") if isinstance(payload.get("policy"), dict) else {}
    action_payload = payload.get("action_payload") if isinstance(payload.get("action_payload"), dict) else {}
    thread_id = str(action.get("thread_id") or "").strip()
    requested_outputs = ["patch", "log", "summary"]
    if bool(policy.get("run_tests")) and "report" not in requested_outputs:
        requested_outputs.append("report")
    try:
        timeout_seconds = int(os.environ.get("XYN_CONVERSATION_RUNTIME_TIMEOUT_SECONDS", "1800") or "1800")
    except ValueError:
        timeout_seconds = 1800
    prompt_title = str(task.title or "Conversation run").strip() or "Conversation run"
    prompt_body = str(prompt or prompt_title).strip() or prompt_title
    return {
        "schema_version": "v1",
        "run_id": str(uuid.uuid4()),
        "work_item_id": str(task.work_item_id or f"conversation:{task.id}"),
        "worker_type": str(action_payload.get("worker_type") or "codex_local"),
        "target": {
            "repo": str(action_payload.get("target_repo") or _conversation_default_repo(prompt)),
            "branch": str(action_payload.get("target_branch") or _conversation_default_branch()),
            "workspace_id": str(workspace.id),
            "artifact_id": None,
        },
        "prompt": {
            "title": prompt_title,
            "body": prompt_body,
        },
        "context": {
            "epic_id": (
                str(re.sub(r"[^a-z0-9]+", "_", (re.search(r"\bEpic\s+([A-Z0-9-]+)\b", prompt, flags=re.IGNORECASE) or [None, ""]).group(1)).lower()).strip("_")
                if re.search(r"\bEpic\s+([A-Z0-9-]+)\b", prompt, flags=re.IGNORECASE)
                else None
            ),
            "attachments": [],
            "metadata": {
                "source": "conversation",
                "dev_task_id": str(task.id),
                "task_type": str(task.task_type or ""),
                "thread_id": thread_id or None,
            },
        },
        "policy": {
            "auto_continue": bool(policy.get("auto_continue")),
            "max_retries": 1,
            "require_human_review_on_failure": bool(policy.get("require_human_review_on_failure", True)),
            "timeout_seconds": timeout_seconds,
        },
        "requested_outputs": requested_outputs,
    }


def _submit_conversation_runtime_run(*, task: DevTask, workspace: Workspace, action: Dict[str, Any], prompt: str, user) -> Dict[str, Any]:
    payload = _conversation_runtime_payload(task=task, workspace=workspace, action=action, prompt=prompt)
    response = _seed_api_request(method="POST", path="/api/v1/runtime/runs", payload=payload, timeout=30)
    body = response.json() if response.content else {}
    if response.status_code >= 400:
        message = body.get("detail") if isinstance(body, dict) else None
        raise RuntimeError(str(message or "runtime submission failed"))
    runtime_run_id = body.get("id") if isinstance(body, dict) else None
    task.runtime_run_id = runtime_run_id or payload["run_id"]
    task.runtime_workspace_id = workspace.id
    task.status = "queued"
    task.last_error = ""
    task.target_repo = str(((payload.get("target") or {}) if isinstance(payload.get("target"), dict) else {}).get("repo") or task.target_repo or "")
    task.target_branch = str(((payload.get("target") or {}) if isinstance(payload.get("target"), dict) else {}).get("branch") or task.target_branch or "")
    task.execution_policy = (payload.get("policy") if isinstance(payload.get("policy"), dict) else {}) or task.execution_policy or {}
    task.updated_by = user
    task.save(update_fields=["runtime_run_id", "runtime_workspace_id", "status", "last_error", "target_repo", "target_branch", "execution_policy", "updated_by", "updated_at"])
    return {"run_id": str(task.runtime_run_id), "work_item_id": str(task.work_item_id), "status": task.status}


def _runtime_run_control(method: str, path: str, *, payload: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    response = _seed_api_request(method=method, path=path, payload=payload or None, timeout=30)
    body = response.json() if response.content else {}
    if response.status_code >= 400:
        message = body.get("detail") if isinstance(body, dict) else None
        raise RuntimeError(str(message or "runtime control request failed"))
    return body if isinstance(body, dict) else {}


@csrf_exempt
@login_required
def dev_tasks_collection(request: HttpRequest) -> JsonResponse:
    if staff_error := _require_staff(request):
        return staff_error
    if request.method == "POST":
        payload = _parse_json(request)
        title = payload.get("title")
        task_type = payload.get("task_type")
        if not title or not task_type:
            return JsonResponse({"error": "title and task_type required"}, status=400)
        if task_type == "deploy_release_plan" and not payload.get("target_instance_id"):
            return JsonResponse({"error": "target_instance_id required for deploy_release_plan"}, status=400)
        release = None
        if payload.get("release_id"):
            release = get_object_or_404(Release, id=payload["release_id"])
        target_instance = None
        if payload.get("target_instance_id"):
            target_instance = get_object_or_404(ProvisionedInstance, id=payload["target_instance_id"])
            if release:
                target_instance.desired_release = release
                target_instance.save(update_fields=["desired_release", "updated_at"])
        coordination_thread = None
        if payload.get("thread_id"):
            coordination_thread = get_object_or_404(CoordinationThread, id=payload["thread_id"])
        target_resolution = resolve_development_target(goal=coordination_thread.goal if coordination_thread and coordination_thread.goal_id else None)
        dev_task = DevTask.objects.create(
            title=title,
            description=payload.get("description", ""),
            task_type=task_type,
            status=payload.get("status", "queued"),
            priority=payload.get("priority", 0),
            max_attempts=payload.get("max_attempts", 3),
            source_entity_type=payload.get("source_entity_type", "manual"),
            source_entity_id=payload.get("source_entity_id") or uuid.uuid4(),
            source_conversation_id=payload.get("source_conversation_id", ""),
            intent_type=payload.get("intent_type", ""),
            target_repo=payload.get("target_repo") or target_resolution.repository_slug or "",
            target_branch=payload.get("target_branch") or target_resolution.branch or "",
            execution_brief=payload.get("execution_brief") if isinstance(payload.get("execution_brief"), dict) else None,
            execution_brief_history=[],
            execution_brief_review_state=(
                normalize_execution_brief_review_state(payload.get("execution_brief_review_state"))
                if isinstance(payload.get("execution_brief"), dict)
                else "draft"
            ),
            execution_brief_review_notes=str(payload.get("execution_brief_review_notes") or ""),
            execution_policy=payload.get("execution_policy") if isinstance(payload.get("execution_policy"), dict) else None,
            coordination_thread=coordination_thread,
            dependency_work_item_ids=payload.get("dependency_work_item_ids") if isinstance(payload.get("dependency_work_item_ids"), list) else [],
            source_run_id=payload.get("source_run_id") or None,
            input_artifact_key=payload.get("input_artifact_key", ""),
            work_item_id=payload.get("work_item_id", ""),
            context_purpose=payload.get("context_purpose", "any"),
            target_instance=target_instance,
            force=bool(payload.get("force")),
            created_by=request.user,
            updated_by=request.user,
        )
        if pack_ids := payload.get("context_pack_ids"):
            packs = ContextPack.objects.filter(id__in=pack_ids)
            dev_task.context_packs.add(*packs)
        return JsonResponse({"id": str(dev_task.id)})
    qs = DevTask.objects.all()
    status_filter = str(request.GET.get("status") or "").strip().lower()
    if task_type := request.GET.get("task_type"):
        qs = qs.filter(task_type=task_type)
    if source_entity_type := request.GET.get("source_entity_type"):
        qs = qs.filter(source_entity_type=source_entity_type)
    if source_entity_id := request.GET.get("source_entity_id"):
        qs = qs.filter(source_entity_id=source_entity_id)
    if runtime_workspace_id := request.GET.get("workspace_id"):
        qs = qs.filter(runtime_workspace_id=runtime_workspace_id)
    if coordination_thread_id := request.GET.get("thread_id"):
        qs = qs.filter(coordination_thread_id=coordination_thread_id)
    if target_instance_id := request.GET.get("target_instance_id"):
        qs = qs.filter(target_instance_id=target_instance_id)
    if query := request.GET.get("q"):
        qs = qs.filter(
            models.Q(title__icontains=query)
            | models.Q(task_type__icontains=query)
            | models.Q(work_item_id__icontains=query)
            | models.Q(last_error__icontains=query)
        )
    data = []
    for task in qs.order_by("-created_at"):
        row = _serialize_dev_task_summary(task)
        if status_filter and str(row.get("status") or "").strip().lower() != status_filter:
            continue
        data.append(row)
    return _paginate(request, data, "dev_tasks")


