def _active_goals_for_workspace(workspace: Workspace):
    qs = Goal.objects.filter(workspace=workspace)
    if hasattr(qs, "filter"):
        qs = qs.filter(Q(application__isnull=True) | ~Q(application__status="archived"))
    if hasattr(qs, "select_related"):
        qs = qs.select_related("requested_by")
    if hasattr(qs, "prefetch_related"):
        qs = qs.prefetch_related("threads__work_items", "work_items")
    return qs


def _active_coordination_threads_for_workspace(workspace: Workspace):
    qs = CoordinationThread.objects.filter(workspace=workspace)
    if hasattr(qs, "filter"):
        qs = qs.filter(Q(goal__application__isnull=True) | ~Q(goal__application__status="archived"))
    if hasattr(qs, "select_related"):
        qs = qs.select_related("owner")
    if hasattr(qs, "prefetch_related"):
        qs = qs.prefetch_related("work_items", "events")
    return qs


def _activate_goal_first_slice(goal: Goal) -> Dict[str, Optional[str]]:
    threads = list(goal.threads.all().order_by("created_at", "id"))
    if not threads:
        raise RuntimeError("goal has no planned threads")
    work_item_id_to_task = {str(task.work_item_id or task.id): task for task in goal.work_items.all().select_related("coordination_thread")}
    queue = derive_work_queue(
        threads=threads,
        status_lookup=lambda task: _thread_status_for_task(task),
        task_lookup=lambda work_item_id: work_item_id_to_task.get(str(work_item_id)),
    )
    selected_task: Optional[DevTask] = None
    if queue:
        selected_task = work_item_id_to_task.get(str(queue[0].work_item_id)) or DevTask.objects.filter(id=queue[0].task_id).first()
    if selected_task is None:
        selected_task = goal.work_items.filter(status="queued").select_related("coordination_thread").order_by("priority", "created_at", "id").first()
    if selected_task is None or selected_task.coordination_thread is None:
        raise RuntimeError("goal has no queue-ready work item")
    selected_thread = selected_task.coordination_thread
    for thread in threads:
        if thread.id == selected_thread.id:
            if thread.status != "active":
                transition_thread_status(thread, "active", work_item=selected_task, payload={"reason": "goal_queue_first_slice"})
        elif thread.status not in {"completed", "archived"}:
            if thread.status != "queued":
                thread.status = "queued"
                thread.save(update_fields=["status", "updated_at"])
    if goal.planning_status != "in_progress":
        goal.planning_status = "in_progress"
        goal.save(update_fields=["planning_status", "updated_at"])
    return {
        "thread_id": str(selected_thread.id),
        "work_item_id": str(selected_task.id),
        "work_item_reference": str(selected_task.work_item_id or selected_task.id),
    }


def _approve_goal_recommendation(
    *,
    goal: Goal,
    identity: UserIdentity,
    requested_action_type: str,
    submitted_recommendation_id: Optional[str] = None,
) -> Dict[str, Any]:
    original_requested_action_type = str(requested_action_type or "approve_and_queue").strip() or "approve_and_queue"
    recommendation = recommend_next_slice(goal)
    queue_suggestion = recommendation.queue_suggestion
    submitted_identity = parse_recommendation_id(submitted_recommendation_id)
    thread_for_blocked_state = (
        goal.threads.filter(id=recommendation.thread_id).prefetch_related("work_items").first()
        if recommendation.thread_id
        else None
    )
    if not queue_suggestion or not recommendation.actions:
        if thread_for_blocked_state and compute_thread_progress(thread_for_blocked_state).thread_status == "blocked":
            return {
                "status": "not_ready",
                "summary": f"{thread_for_blocked_state.title} is blocked and cannot be queued until its current blockers are cleared.",
                "queue_seed": None,
            }
        return {
            "status": "no_recommendation",
            "summary": f"No queueable recommendation is available for {goal.title}.",
            "queue_seed": None,
        }
    allowed_actions = {
        action.type: action for action in recommendation.actions if getattr(action, "queueable", False)
    }
    if not allowed_actions:
        if thread_for_blocked_state and compute_thread_progress(thread_for_blocked_state).thread_status == "blocked":
            return {
                "status": "not_ready",
                "summary": f"{thread_for_blocked_state.title} is blocked and cannot be queued until its current blockers are cleared.",
                "queue_seed": None,
            }
        return {
            "status": "no_recommendation",
            "summary": f"No queueable recommendation is available for {goal.title}.",
            "queue_seed": None,
        }
    action_type = original_requested_action_type
    if action_type == "approve_and_queue":
        action_type = str(queue_suggestion.action_type or "").strip()
    if action_type not in allowed_actions:
        if str(requested_action_type or "").strip() == "approve_and_queue":
            return {
                "status": "no_recommendation",
                "summary": f"No queueable recommendation is available for {goal.title}.",
                "queue_seed": None,
            }
        return {
            "status": "rejected",
            "summary": f"{action_type or 'This action'} is not queueable for the current recommendation.",
            "queue_seed": None,
        }

    thread = (
        goal.threads.filter(id=recommendation.thread_id).prefetch_related("work_items").first()
        if recommendation.thread_id
        else None
    )
    task = (
        goal.work_items.filter(id=recommendation.work_item_id).select_related("coordination_thread").first()
        if recommendation.work_item_id
        else None
    )
    if submitted_recommendation_id and recommendation.recommendation_id != submitted_recommendation_id:
        current_thread_id = str(thread.id) if thread else None
        current_work_item_id = str(task.id) if task else None
        if (
            submitted_identity.get("goal_id") == str(goal.id)
            and submitted_identity.get("thread_id") == current_thread_id
            and submitted_identity.get("work_item_id") == current_work_item_id
            and thread is not None
            and task is not None
        ):
            task_lookup = {str(item.work_item_id or item.id): item for item in goal.work_items.all()}
            queue = derive_work_queue(
                threads=goal.threads.all(),
                status_lookup=lambda candidate: _thread_status_for_task(candidate),
                task_lookup=lambda work_item_id: task_lookup.get(str(work_item_id)),
            )
            if queue and str(queue[0].task_id) == str(task.id) and thread.status == "active":
                return {
                    "status": "already_queued",
                    "summary": f"{task.title} is already the next eligible XCO queue item.",
                    "queue_seed": {
                        "thread_id": str(thread.id),
                        "work_item_id": str(task.id),
                        "work_item_reference": str(task.work_item_id or task.id),
                    },
                }
        return {
            "status": "stale_recommendation",
            "summary": f"The recommendation for {goal.title} is no longer current. Refresh the goal and review the latest next slice.",
            "queue_seed": None,
        }
    if thread is None or task is None or task.coordination_thread_id != thread.id:
        return {
            "status": "rejected",
            "summary": "The recommended work item could not be resolved from durable coordination state.",
            "queue_seed": None,
        }
    if thread.status not in {"active", "queued"}:
        return {
            "status": "invalid_thread_state",
            "summary": f"Thread {thread.title} is {thread.status} and cannot be queued from the current recommendation.",
            "queue_seed": None,
        }
    task_lookup = {str(item.work_item_id or item.id): item for item in goal.work_items.all()}
    activated_from_queue = False
    if thread.status == "queued" and action_type == "queue_first_slice":
        transition_thread_status(
            thread,
            "active",
            work_item=task,
            payload={"reason": "goal_queue_first_slice", "goal_id": str(goal.id)},
        )
        thread.refresh_from_db()
        activated_from_queue = True
    task_status = _thread_status_for_task(task)
    dependency_ids = task.dependency_work_item_ids if isinstance(task.dependency_work_item_ids, list) else []
    blocked_by_dependency = False
    for reference in dependency_ids:
        dep = task_lookup.get(str(reference))
        dep_status = _thread_status_for_task(dep) if dep is not None else ""
        if dep is None or dep_status not in {"completed", "succeeded"}:
            blocked_by_dependency = True
            break
    if task_status != "queued" or blocked_by_dependency:
        return {
            "status": "not_ready",
            "summary": f"{task.title} is not ready to enter the XCO queue.",
            "queue_seed": None,
        }
    queue = derive_work_queue(
        threads=goal.threads.all(),
        status_lookup=lambda candidate: _thread_status_for_task(candidate),
        task_lookup=lambda work_item_id: task_lookup.get(str(work_item_id)),
    )
    if queue and str(queue[0].task_id) == str(task.id) and thread.status == "active" and not activated_from_queue:
        return {
            "status": "already_queued",
            "summary": f"{task.title} is already the next eligible XCO queue item.",
            "queue_seed": {
                "thread_id": str(thread.id),
                "work_item_id": str(task.id),
                "work_item_reference": str(task.work_item_id or task.id),
            },
        }

    if thread.status != "active":
        transition_thread_status(
            thread,
            "active",
            work_item=task,
            payload={"reason": "recommendation_approved", "goal_id": str(goal.id)},
        )
    if goal.planning_status != "in_progress" and valid_goal_transition(goal.planning_status, "in_progress"):
        goal.planning_status = "in_progress"
        goal.save(update_fields=["planning_status", "updated_at"])
    if original_requested_action_type == "queue_first_slice":
        approval_event_type = "approval_queue_first_slice"
    elif original_requested_action_type == "queue_next_slice":
        approval_event_type = "approval_queue_next_slice"
    else:
        approval_event_type = "approval_recommendation"
    record_thread_event(
        thread=thread,
        event_type=approval_event_type,
        work_item=task,
        payload={
            "goal_id": str(goal.id),
            "user_id": str(getattr(identity, "id", "") or ""),
            "requested_action_type": original_requested_action_type,
            "resolved_action_type": action_type,
            "work_item_id": str(task.work_item_id or task.id),
        },
    )
    return {
        "status": "approved",
        "summary": f"Approved and queued {task.title} through XCO scheduling.",
        "queue_seed": {
            "thread_id": str(thread.id),
            "work_item_id": str(task.id),
            "work_item_reference": str(task.work_item_id or task.id),
        },
    }


def _coordination_task_lookup_factory(workspace_id: str):
    cache: Dict[str, Optional[DevTask]] = {}

    def _lookup(reference: str) -> Optional[DevTask]:
        key = str(reference or "").strip()
        if not key:
            return None
        if key not in cache:
            try:
                key_uuid = uuid.UUID(key)
            except (TypeError, ValueError, AttributeError):
                key_uuid = None
            query = DevTask.objects.filter(
                Q(runtime_workspace_id=workspace_id)
                | Q(coordination_thread__workspace_id=workspace_id)
                | Q(goal__workspace_id=workspace_id)
            )
            if key_uuid is not None:
                query = query.filter(Q(id=key_uuid) | Q(work_item_id=key))
            else:
                query = query.filter(work_item_id=key)
            cache[key] = query.order_by("-updated_at", "-created_at").first()
        return cache[key]

    return _lookup


def _xco_status_lookup(task: DevTask) -> str:
    return _thread_status_for_task(task)


def _update_thread_status_from_tasks(thread: CoordinationThread) -> None:
    policy = effective_thread_policy(thread)
    statuses = [_thread_status_for_task(task) for task in thread.work_items.all()]
    if thread.status == "archived":
        return
    if policy.get("pause_on_failure") and any(status in {"awaiting_review", "failed"} for status in statuses):
        if thread.status != "paused":
            transition_thread_status(thread, "paused", payload={"reason": "pause_on_failure"})
        return
    if statuses and all(status in {"completed", "succeeded", "canceled"} for status in statuses):
        if thread.status not in {"completed", "archived"}:
            transition_thread_status(thread, "completed", payload={"reason": "all_work_items_terminal"})
        return
    if thread.status == "queued" and policy.get("auto_resume") and any(status == "queued" for status in statuses):
        transition_thread_status(thread, "active", payload={"reason": "auto_resume"})
        return
    if thread.status == "paused" and policy.get("auto_resume") and not any(status == "awaiting_review" for status in statuses):
        transition_thread_status(thread, "active", payload={"reason": "auto_resume"})


@csrf_exempt
@login_required
def goals_collection(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method == "POST":
        payload = _parse_json(request)
        workspace_id = str(payload.get("workspace_id") or "").strip()
        title = str(payload.get("title") or "").strip()
        if not workspace_id or not title:
            return JsonResponse({"error": "workspace_id and title are required"}, status=400)
        workspace, _ = _goal_queryset(identity, workspace_id)
        goal = Goal.objects.create(
            workspace=workspace,
            title=title[:240],
            description=str(payload.get("description") or "").strip(),
            source_conversation_id=str(payload.get("source_conversation_id") or "").strip(),
            requested_by=identity,
            goal_type=str(payload.get("goal_type") or infer_goal_type(title, str(payload.get("description") or ""))).strip() or "build_system",
            planning_status=str(payload.get("planning_status") or "proposed").strip() or "proposed",
            priority=str(payload.get("priority") or "normal").strip() or "normal",
            planning_summary=str(payload.get("planning_summary") or "").strip(),
            resolution_notes_json=payload.get("resolution_notes") if isinstance(payload.get("resolution_notes"), list) else [],
        )
        return JsonResponse(_serialize_goal_detail(goal), status=201)
    workspace_id = str(request.GET.get("workspace_id") or "").strip()
    if not workspace_id:
        return JsonResponse({"error": "workspace_id is required"}, status=400)
    _, qs = _goal_queryset(identity, workspace_id)
    planning_status = str(request.GET.get("planning_status") or "").strip().lower()
    if planning_status:
        qs = qs.filter(planning_status=planning_status)
    goal_type = str(request.GET.get("goal_type") or "").strip().lower()
    if goal_type:
        qs = qs.filter(goal_type=goal_type)
    ordered_goals = list(qs.order_by("-updated_at", "-created_at"))
    portfolio_rows = build_goal_portfolio_state(ordered_goals, runtime_detail_lookup=_project_runtime_status_to_task)
    portfolio_by_goal_id = {row.goal_id: row for row in portfolio_rows}
    rows: List[Dict[str, Any]] = []
    for goal in ordered_goals:
        payload = _serialize_goal_summary(goal)
        portfolio_row = portfolio_by_goal_id.get(str(goal.id))
        if portfolio_row:
            payload["goal_progress"] = {
                "goal_progress_status": portfolio_row.goal_progress_status,
                "progress_percent": portfolio_row.progress_percent,
            }
            payload["coordination_priority"] = {
                "value": portfolio_row.coordination_priority.value,
                "reasons": portfolio_row.coordination_priority.reasons,
                "recent_execution_count": portfolio_row.recent_execution_count,
                "health_status": portfolio_row.health_status,
                "active_threads": portfolio_row.active_threads,
                "blocked_threads": portfolio_row.blocked_threads,
            }
        rows.append(payload)
    response = _paginate(request, rows, "goals")
    if not isinstance(response, JsonResponse):
        return response
    payload = json.loads(response.content)
    payload["portfolio_state"] = _build_goal_portfolio_payload(ordered_goals)
    return JsonResponse(payload, status=response.status_code)


@csrf_exempt
@login_required
def goal_detail(request: HttpRequest, goal_id: str) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    goal = get_object_or_404(Goal.objects.select_related("workspace", "requested_by").prefetch_related("threads__work_items", "work_items"), id=goal_id)
    if not _workspace_membership(identity, str(goal.workspace_id)):
        return JsonResponse({"error": "forbidden"}, status=403)
    if request.method == "GET":
        return JsonResponse(_serialize_goal_detail(goal))
    if request.method not in {"PATCH", "POST"}:
        return JsonResponse({"error": "method not allowed"}, status=405)
    payload = _parse_json(request)
    update_fields: List[str] = []
    if "title" in payload:
        goal.title = str(payload.get("title") or "").strip()[:240]
        update_fields.append("title")
    if "description" in payload:
        goal.description = str(payload.get("description") or "").strip()
        update_fields.append("description")
    if "priority" in payload:
        goal.priority = str(payload.get("priority") or "normal").strip().lower() or "normal"
        update_fields.append("priority")
    if "planning_status" in payload:
        next_status = str(payload.get("planning_status") or "").strip().lower()
        if not valid_goal_transition(goal.planning_status, next_status):
            return JsonResponse({"error": f"invalid goal planning_status transition: {goal.planning_status} -> {next_status}"}, status=409)
        goal.planning_status = next_status
        update_fields.append("planning_status")
    if "planning_summary" in payload:
        goal.planning_summary = str(payload.get("planning_summary") or "").strip()
        update_fields.append("planning_summary")
    if "resolution_notes" in payload:
        notes = payload.get("resolution_notes")
        if notes is not None and not isinstance(notes, list):
            return JsonResponse({"error": "resolution_notes must be a list"}, status=400)
        goal.resolution_notes_json = notes or []
        update_fields.append("resolution_notes_json")
    if update_fields:
        goal.save(update_fields=[*update_fields, "updated_at"])
    return JsonResponse(_serialize_goal_detail(goal))


@csrf_exempt
@login_required
def goal_decompose(request: HttpRequest, goal_id: str) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    goal = get_object_or_404(Goal.objects.select_related("workspace", "requested_by").prefetch_related("threads__work_items", "work_items"), id=goal_id)
    if not _workspace_membership(identity, str(goal.workspace_id)):
        return JsonResponse({"error": "forbidden"}, status=403)
    plan = decompose_goal(goal)
    persisted = persist_goal_plan(goal, plan, user=request.user)
    goal.refresh_from_db()
    return JsonResponse(
        {
            "goal": _serialize_goal_detail(goal),
            "threads": [_coordination_thread_summary(thread) for thread in persisted.get("threads", [])],
            "work_items": [_serialize_work_item_summary(task) for task in persisted.get("work_items", [])],
            "planning_output": plan.model_dump(mode="json"),
        }
    )


@csrf_exempt
@login_required
def goal_review(request: HttpRequest, goal_id: str) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    goal = get_object_or_404(Goal.objects.select_related("workspace", "requested_by").prefetch_related("threads__work_items", "work_items"), id=goal_id)
    if not _workspace_membership(identity, str(goal.workspace_id)):
        return JsonResponse({"error": "forbidden"}, status=403)
    payload = _parse_json(request)
    review_action = str(payload.get("review_action") or "").strip().lower()
    if review_action == "approve_plan":
        if not valid_goal_transition(goal.planning_status, "in_progress"):
            return JsonResponse({"error": f"invalid goal planning_status transition: {goal.planning_status} -> in_progress"}, status=409)
        goal.planning_status = "in_progress"
        goal.save(update_fields=["planning_status", "updated_at"])
        result = {"status": "approved", "goal": _serialize_goal_detail(goal)}
    elif review_action == "defer_execution":
        result = {"status": "deferred", "goal": _serialize_goal_detail(goal)}
    elif review_action == "adjust_plan":
        if not valid_goal_transition(goal.planning_status, "proposed"):
            return JsonResponse({"error": f"invalid goal planning_status transition: {goal.planning_status} -> proposed"}, status=409)
        goal.planning_status = "proposed"
        goal.save(update_fields=["planning_status", "updated_at"])
        result = {"status": "adjustment_requested", "goal": _serialize_goal_detail(goal)}
    elif review_action in {"queue_first_slice", "queue_next_slice", "approve_and_queue"}:
        approval = _approve_goal_recommendation(
            goal=goal,
            identity=identity,
            requested_action_type=review_action,
            submitted_recommendation_id=str(payload.get("recommendation_id") or "").strip() or None,
        )
        if approval["status"] in {"rejected", "not_ready", "invalid_thread_state", "stale_recommendation"}:
            return JsonResponse({"status": approval["status"], "summary": approval["summary"]}, status=409)
        goal.refresh_from_db()
        result = {"status": approval["status"], "goal": _serialize_goal_detail(goal), "queue_seed": approval.get("queue_seed"), "summary": approval["summary"]}
    else:
        return JsonResponse({"error": "review_action must be approve_plan, defer_execution, adjust_plan, approve_and_queue, queue_first_slice, or queue_next_slice"}, status=400)
    return JsonResponse(result)


