@login_required
def application_artifact_membership_detail(
    request: HttpRequest, application_id: str, membership_id: str
) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    application = get_object_or_404(Application.objects.select_related("workspace"), id=application_id)
    if not _workspace_membership(identity, str(application.workspace_id)):
        return JsonResponse({"error": "forbidden"}, status=403)
    membership = get_object_or_404(
        ApplicationArtifactMembership.objects.select_related("artifact", "artifact__type"),
        id=membership_id,
        application=application,
    )
    if request.method == "DELETE":
        if not _require_workspace_capabilities(identity, str(application.workspace_id), [CAP_ARTIFACTS_WRITE]):
            return JsonResponse({"error": "forbidden"}, status=403)
        payload = _serialize_application_artifact_membership(membership)
        membership.delete()
        return JsonResponse({"deleted": True, "membership": payload})
    if request.method != "PATCH":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if not _require_workspace_capabilities(identity, str(application.workspace_id), [CAP_ARTIFACTS_WRITE]):
        return JsonResponse({"error": "forbidden"}, status=403)
    payload = _parse_json(request)
    updates: Dict[str, Any] = {}
    if "role" in payload:
        allowed_roles = {choice for choice, _label in ApplicationArtifactMembership.ROLE_CHOICES}
        role = str(payload.get("role") or "").strip().lower()
        if role not in allowed_roles:
            return JsonResponse({"error": f"role must be one of {', '.join(sorted(allowed_roles))}"}, status=400)
        updates["role"] = role
    if "responsibility_summary" in payload:
        updates["responsibility_summary"] = str(payload.get("responsibility_summary") or "").strip()
    if "metadata" in payload:
        metadata = payload.get("metadata")
        if metadata is not None and not isinstance(metadata, dict):
            return JsonResponse({"error": "metadata must be an object"}, status=400)
        updates["metadata_json"] = metadata if isinstance(metadata, dict) else {}
    if "sort_order" in payload:
        try:
            updates["sort_order"] = int(payload.get("sort_order"))
        except (TypeError, ValueError):
            return JsonResponse({"error": "sort_order must be an integer"}, status=400)
    if updates:
        for key, value in updates.items():
            setattr(membership, key, value)
        membership.save()
        membership.refresh_from_db()
    return JsonResponse(_serialize_application_artifact_membership(membership))


@csrf_exempt
@login_required
def application_solution_change_sessions_collection(
    request: HttpRequest, application_id: str
) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    application = get_object_or_404(Application.objects.select_related("workspace"), id=application_id)
    if not _workspace_accessible_for_identity(identity, str(application.workspace_id)):
        return JsonResponse({"error": "forbidden"}, status=403)
    memberships = list(
        ApplicationArtifactMembership.objects.filter(application=application)
        .select_related("artifact", "artifact__type")
        .order_by("sort_order", "created_at")
    )
    memberships_by_artifact_id = {str(member.artifact_id): member for member in memberships}
    if request.method == "GET":
        sessions = list(
            SolutionChangeSession.objects.filter(application=application)
            .select_related("created_by")
            .order_by("-updated_at", "-created_at")
        )
        return JsonResponse(
            {
                "application_id": str(application.id),
                "workspace_id": str(application.workspace_id),
                "sessions": [
                    _serialize_solution_change_session(session, memberships_by_artifact_id=memberships_by_artifact_id)
                    for session in sessions
                ],
            }
        )
    if request.method != "POST":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if not _require_workspace_capabilities(identity, str(application.workspace_id), [CAP_ARTIFACTS_WRITE]):
        return JsonResponse({"error": "forbidden"}, status=403)
    payload = _parse_json(request)
    request_text = str(payload.get("request_text") or "").strip()
    if not request_text:
        return JsonResponse({"error": "request_text is required"}, status=400)
    title = str(payload.get("title") or "").strip() or f"Change Session {timezone.now().strftime('%Y-%m-%d %H:%M')}"
    metadata_payload = payload.get("metadata")
    if metadata_payload is None:
        metadata_payload = payload.get("metadata_json")
    if metadata_payload is not None and not isinstance(metadata_payload, dict):
        return JsonResponse({"error": "metadata must be an object"}, status=400)
    session_metadata = metadata_payload if isinstance(metadata_payload, dict) else {}
    analysis = _build_solution_impacted_analysis(
        application=application,
        request_text=request_text,
        memberships=memberships,
        session_metadata=session_metadata,
    )
    session = SolutionChangeSession.objects.create(
        workspace_id=application.workspace_id,
        application=application,
        title=title,
        request_text=request_text,
        created_by=identity,
        metadata_json=session_metadata,
        analysis_json=analysis,
        selected_artifact_ids_json=analysis.get("suggested_artifact_ids") if isinstance(analysis.get("suggested_artifact_ids"), list) else [],
    )
    _seed_solution_planning_state_on_create(session=session, memberships=memberships)
    session.refresh_from_db()
    return JsonResponse(
        {
            "created": True,
            "session": _serialize_solution_change_session(session, memberships_by_artifact_id=memberships_by_artifact_id),
        },
        status=201,
    )


@csrf_exempt
@login_required
def application_solution_change_session_detail(
    request: HttpRequest, application_id: str, session_id: str
) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    application = get_object_or_404(Application.objects.select_related("workspace"), id=application_id)
    if not _workspace_accessible_for_identity(identity, str(application.workspace_id)):
        return JsonResponse({"error": "forbidden"}, status=403)
    session = get_object_or_404(
        SolutionChangeSession.objects.select_related("created_by"),
        id=session_id,
        application=application,
    )
    memberships = list(
        ApplicationArtifactMembership.objects.filter(application=application)
        .select_related("artifact", "artifact__type")
        .order_by("sort_order", "created_at")
    )
    memberships_by_artifact_id = {str(member.artifact_id): member for member in memberships}
    if request.method == "GET":
        return JsonResponse(_serialize_solution_change_session(session, memberships_by_artifact_id=memberships_by_artifact_id))
    if request.method == "DELETE":
        if not _require_workspace_capabilities(identity, str(application.workspace_id), [CAP_ARTIFACTS_WRITE]):
            return JsonResponse({"error": "forbidden"}, status=403)
        execution_status = str(session.execution_status or "not_started").strip().lower() or "not_started"
        has_execution_records = bool(session.staged_changes_json) or bool(session.preview_json) or bool(session.validation_json)
        if execution_status != "not_started" or has_execution_records:
            return JsonResponse(
                {
                    "code": "DELETE_BLOCKED",
                    "message": "Change sessions can only be deleted before staged/preview/validation execution begins.",
                },
                status=409,
            )
        session.delete()
        return JsonResponse(
            {
                "deleted": True,
                "application_id": str(application.id),
                "session_id": str(session_id),
            }
        )
    if request.method != "PATCH":
        return JsonResponse({"error": "method not allowed"}, status=405)
    if not _require_workspace_capabilities(identity, str(application.workspace_id), [CAP_ARTIFACTS_WRITE]):
        return JsonResponse({"error": "forbidden"}, status=403)
    payload = _parse_json(request)
    if "title" in payload:
        session.title = str(payload.get("title") or "").strip() or session.title
    if "status" in payload:
        status_value = str(payload.get("status") or "").strip().lower()
        allowed_statuses = {choice for choice, _label in SolutionChangeSession.STATUS_CHOICES}
        if status_value not in allowed_statuses:
            return JsonResponse({"error": "invalid status"}, status=400)
        session.status = status_value
    if "selected_artifact_ids" in payload:
        raw = payload.get("selected_artifact_ids")
        if not isinstance(raw, list):
            return JsonResponse({"error": "selected_artifact_ids must be a list"}, status=400)
        allowed_ids = set(memberships_by_artifact_id.keys())
        selected_ids: List[str] = []
        for item in raw:
            token = str(item or "").strip()
            if token and token in allowed_ids and token not in selected_ids:
                selected_ids.append(token)
        constrained_ids, _widened, error_code = _apply_scope_lock_to_selection(
            session=session,
            selected_artifact_ids=selected_ids,
            scope_source=str(payload.get("scope_source") or "manual_override").strip() or "manual_override",
            widen_reason=str(payload.get("scope_widen_reason") or "").strip(),
            permit_planner_discovery=False,
        )
        if error_code == "scope_widen_reason_required":
            return JsonResponse(
                {
                    "error": "scope_widen_reason is required to expand decomposition scope",
                    "blocked_reason": "scope_lock_widen_reason_required",
                    "required_fields": ["scope_widen_reason"],
                    "allowed_actions": ["set_selected_artifact_ids_with_scope_widen_reason", "regenerate_options", "plan"],
                },
                status=409,
            )
        session.selected_artifact_ids_json = constrained_ids
    if "confirmed_workstreams" in payload:
        raw = payload.get("confirmed_workstreams")
        if not isinstance(raw, list):
            return JsonResponse({"error": "confirmed_workstreams must be a list"}, status=400)
        normalized: List[str] = []
        seen: set[str] = set()
        for item in raw:
            token = str(item or "").strip().lower()
            if not token or token in seen:
                continue
            if token not in _SOLUTION_WORKSTREAM_KEYS:
                return JsonResponse({"error": f"invalid confirmed_workstream: {token}"}, status=400)
            seen.add(token)
            normalized.append(token)
        analysis = session.analysis_json if isinstance(session.analysis_json, dict) else {}
        suggested = [
            str(item or "").strip().lower()
            for item in (analysis.get("suggested_workstreams") if isinstance(analysis.get("suggested_workstreams"), list) else [])
            if str(item or "").strip()
        ]
        if normalized and suggested:
            invalid = [item for item in normalized if item not in suggested]
            if invalid:
                return JsonResponse(
                    {"error": "confirmed_workstreams must be selected from suggested_workstreams"},
                    status=400,
                )
        if normalized and not suggested:
            return JsonResponse(
                {"error": "confirmed_workstreams cannot be set before suggested workstreams are available"},
                status=400,
            )
        metadata = session.metadata_json if isinstance(session.metadata_json, dict) else {}
        metadata = {**metadata, "confirmed_workstreams": normalized}
        session.metadata_json = metadata
    session.save()
    session.refresh_from_db()
    return JsonResponse(_serialize_solution_change_session(session, memberships_by_artifact_id=memberships_by_artifact_id))


@csrf_exempt
@login_required
def application_solution_change_session_control(
    request: HttpRequest, application_id: str, session_id: str
) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    application = get_object_or_404(Application.objects.select_related("workspace"), id=application_id)
    if not _workspace_accessible_for_identity(identity, str(application.workspace_id)):
        return JsonResponse({"error": "forbidden"}, status=403)
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)
    try:
        session = get_object_or_404(SolutionChangeSession, id=session_id, application=application)
    except Http404:
        raise
    except Exception as exc:
        logger.exception(
            "solution_change_session_control_resolution_failed application_id=%s session_id=%s",
            str(application_id or ""),
            str(session_id or ""),
        )
        return JsonResponse(
            {
                "error": "session_control_unavailable",
                "error_classification": "session_resolution_failed",
                "error_summary": f"{exc.__class__.__name__}: {str(exc)[:300]}",
                "application_id": str(application_id or ""),
                "session_id": str(session_id or ""),
                "safe_next_actions": ["get_application_change_session", "list_application_change_sessions"],
            },
            status=500,
        )
    return _solution_change_session_control_envelope(
        operation="inspect",
        session=session,
        application=application,
        operation_status="ready",
        operation_payload={"inspected": True},
        http_status=200,
    )


@csrf_exempt
@login_required
def application_solution_change_session_control_action(
    request: HttpRequest, application_id: str, session_id: str
) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    application = get_object_or_404(Application.objects.select_related("workspace"), id=application_id)
