@login_required
def draft_workflow(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method != "GET":
        return JsonResponse({"error": "method not allowed"}, status=405)

    draft_id = str(request.GET.get("draft_id") or "").strip()
    if not draft_id:
        return JsonResponse({"error": "draft_id is required"}, status=400)

    workspace = _resolve_workspace_for_identity(identity, str(request.GET.get("workspace_id") or ""))
    if workspace is None:
        return JsonResponse({"error": "workspace context is required"}, status=400)

    try:
        draft_response = _seed_api_request(
            method="GET",
            path=f"/api/v1/drafts/{draft_id}",
            workspace_slug=str(workspace.slug or ""),
            timeout=20,
        )
        jobs_response = _seed_api_request(
            method="GET",
            path="/api/v1/jobs",
            workspace_slug=str(workspace.slug or ""),
            timeout=20,
        )
    except requests.RequestException as exc:
        return JsonResponse({"error": "failed to load draft workflow", "details": exc.__class__.__name__}, status=502)

    if draft_response.status_code >= 300:
        return JsonResponse({"error": "failed to load draft", "status_code": draft_response.status_code}, status=502)
    if jobs_response.status_code >= 300:
        return JsonResponse({"error": "failed to load draft jobs", "status_code": jobs_response.status_code}, status=502)

    draft_payload = draft_response.json() if draft_response.content else {}
    jobs_payload = jobs_response.json() if jobs_response.content else []
    if not isinstance(draft_payload, dict):
        return JsonResponse({"error": "draft payload is invalid"}, status=502)
    if not isinstance(jobs_payload, list):
        jobs_payload = []

    return JsonResponse(get_draft_workflow(workspace=workspace, draft=draft_payload, jobs=jobs_payload))


def _review_coordination_thread(
    *,
    thread: CoordinationThread,
    identity: UserIdentity,
    review_action: str,
) -> Tuple[Dict[str, Any], int]:
    if review_action not in {"resume_thread", "queue_next_slice", "mark_thread_completed"}:
        return ({"error": "review_action must be resume_thread, queue_next_slice, or mark_thread_completed"}, 400)

    if review_action == "resume_thread":
        if thread.status == "active":
            blocked_brief_reviews = sum(
                1
                for task in thread.work_items.all()
                if evaluate_dev_task_queue_state(task, normalized_status=str(task.status or "")).reason == "brief_not_ready"
            )
            if blocked_brief_reviews:
                return (
                    {
                        "status": "already_active",
                        "thread": _coordination_thread_detail(thread),
                        "summary": (
                            f"{thread.title} is already active, but {blocked_brief_reviews} work item(s) still require "
                            "execution brief review before coding can be dispatched."
                        ),
                    },
                    200,
                )
            return ({"status": "already_active", "thread": _coordination_thread_detail(thread), "summary": f"{thread.title} is already active."}, 200)
        if not valid_thread_transition(thread.status, "active"):
            return (
                {
                    "status": "invalid_thread_state",
                    "thread": _coordination_thread_detail(thread),
                    "summary": f"{thread.title} cannot be resumed from {thread.status}.",
                },
                409,
            )
        transition_thread_status(thread, "active", payload={"reason": "thread_review_resume", "user_id": str(identity.id)})
        record_thread_event(
            thread=thread,
            event_type="approval_thread_resume",
            payload={"user_id": str(identity.id), "thread_id": str(thread.id)},
        )
        thread.refresh_from_db()
        return ({"status": "resumed", "thread": _coordination_thread_detail(thread), "summary": f"Resumed {thread.title}."}, 200)

    if review_action == "mark_thread_completed":
        unfinished = thread.work_items.exclude(status__in=["completed", "succeeded", "failed", "canceled"]).exists()
        if unfinished:
            return (
                {
                    "status": "unfinished_work",
                    "thread": _coordination_thread_detail(thread),
                    "summary": f"{thread.title} still has unfinished work items and cannot be marked completed.",
                },
                409,
            )
        if thread.status == "completed":
            return ({"status": "already_completed", "thread": _coordination_thread_detail(thread), "summary": f"{thread.title} is already completed."}, 200)
        if not valid_thread_transition(thread.status, "completed"):
            return (
                {
                    "status": "invalid_thread_state",
                    "thread": _coordination_thread_detail(thread),
                    "summary": f"{thread.title} cannot be completed from {thread.status}.",
                },
                409,
            )
        transition_thread_status(thread, "completed", payload={"reason": "thread_review_complete", "user_id": str(identity.id)})
        thread.refresh_from_db()
        return ({"status": "completed", "thread": _coordination_thread_detail(thread), "summary": f"Marked {thread.title} completed."}, 200)

    if thread.status != "active":
        return (
            {
                "status": "invalid_thread_state",
                "thread": _coordination_thread_detail(thread),
                "summary": f"{thread.title} must be active before queueing the next slice.",
            },
            409,
        )

    queue = derive_work_queue(
        threads=CoordinationThread.objects.filter(id=thread.id).select_related("workspace", "owner", "goal").prefetch_related("work_items"),
        status_lookup=_xco_status_lookup,
        task_lookup=_coordination_task_lookup_factory(str(thread.workspace_id)),
    )
    entry = next((candidate for candidate in queue if candidate.thread_id == str(thread.id)), None)
    if not entry:
        blocked_brief_reviews = sum(
            1
            for task in thread.work_items.all()
            if evaluate_dev_task_queue_state(task, normalized_status=str(task.status or "")).reason == "brief_not_ready"
        )
        if blocked_brief_reviews:
            return (
                {
                    "status": "brief_review_required",
                    "thread": _coordination_thread_detail(thread),
                    "summary": (
                        f"No queueable work is ready for {thread.title} because {blocked_brief_reviews} work item(s) "
                        "still require execution brief review."
                    ),
                },
                409,
            )
        return (
            {
                "status": "no_queueable_work",
                "thread": _coordination_thread_detail(thread),
                "summary": f"No queueable work is ready for {thread.title}.",
            },
            409,
        )
    task = thread.work_items.filter(id=entry.task_id).first()
    task_state = (
        evaluate_dev_task_queue_state(task, normalized_status=str(task.status or ""))
        if task is not None
        else None
    )
    if task is None or task_state is None or not task_state.dispatchable:
        if task_state is not None and task_state.reason == "brief_not_ready":
            return (
                {
                    "status": "brief_review_required",
                    "thread": _coordination_thread_detail(thread),
                    "summary": (
                        f"The next slice for {thread.title} still requires execution brief review before coding can be dispatched."
                    ),
                },
                409,
            )
        return (
            {
                "status": "no_queueable_work",
                "thread": _coordination_thread_detail(thread),
                "summary": f"No queueable work is ready for {thread.title}.",
            },
            409,
        )
    record_thread_event(
        thread=thread,
        event_type="approval_queue_next_slice",
        work_item=task,
        run_id=str(task.runtime_run_id) if task and task.runtime_run_id else None,
        payload={
            "user_id": str(identity.id),
            "work_item_id": str(task.work_item_id or task.id) if task else entry.work_item_id,
        },
    )
    thread.refresh_from_db()
    return (
        {
            "status": "approved",
            "thread": _coordination_thread_detail(thread),
            "queue_seed": {
                "thread_id": str(thread.id),
                "work_item_id": str(task.work_item_id or task.id) if task else entry.work_item_id,
            },
            "summary": f"Approved the next slice for {thread.title}.",
        },
        200,
    )


@csrf_exempt
@login_required
def threads_collection(request: HttpRequest) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    if request.method == "POST":
        payload = _parse_json(request)
        workspace_id = str(payload.get("workspace_id") or "").strip()
        title = str(payload.get("title") or "").strip()
        if not workspace_id or not title:
            return JsonResponse({"error": "workspace_id and title are required"}, status=400)
        workspace, _ = _coordination_thread_queryset(identity, workspace_id)
        thread = CoordinationThread.objects.create(
            workspace=workspace,
            title=title[:240],
            description=str(payload.get("description") or "").strip(),
            owner=identity,
            priority=str(payload.get("priority") or "normal").strip() or "normal",
            status=str(payload.get("status") or "active").strip() or "active",
            domain=str(payload.get("domain") or "").strip(),
            work_in_progress_limit=max(1, int(payload.get("work_in_progress_limit") or 1)),
            execution_policy=payload.get("execution_policy") if isinstance(payload.get("execution_policy"), dict) else {},
            source_conversation_id=str(payload.get("source_conversation_id") or "").strip(),
        )
        record_thread_event(thread=thread, event_type="thread_created", payload={"status": thread.status, "priority": thread.priority})
        return JsonResponse(_coordination_thread_detail(thread), status=201)
    workspace_id = str(request.GET.get("workspace_id") or "").strip()
    if not workspace_id:
        return JsonResponse({"error": "workspace_id is required"}, status=400)
    _, qs = _coordination_thread_queryset(identity, workspace_id)
    status_filter = str(request.GET.get("status") or "").strip().lower()
    if status_filter:
        qs = qs.filter(status=status_filter)
    priority_filter = str(request.GET.get("priority") or "").strip().lower()
    if priority_filter:
        qs = qs.filter(priority=priority_filter)
    rows = []
    for thread in qs.order_by("-updated_at", "-created_at"):
        _update_thread_status_from_tasks(thread)
        rows.append(_coordination_thread_summary(thread))
    return _paginate(request, rows, "threads")


@csrf_exempt
@login_required
def thread_detail(request: HttpRequest, thread_id: str) -> JsonResponse:
    identity = _require_authenticated(request)
    if not identity:
        return JsonResponse({"error": "not authenticated"}, status=401)
    thread = get_object_or_404(CoordinationThread.objects.select_related("workspace", "owner").prefetch_related("work_items", "events"), id=thread_id)
    if not _workspace_membership(identity, str(thread.workspace_id)):
        return JsonResponse({"error": "forbidden"}, status=403)
    if request.method == "GET":
        _update_thread_status_from_tasks(thread)
        return JsonResponse(_coordination_thread_detail(thread))
    if request.method not in {"PATCH", "POST"}:
        return JsonResponse({"error": "method not allowed"}, status=405)
    payload = _parse_json(request)
    previous_status = thread.status
    if "status" in payload:
        next_status = str(payload.get("status") or "").strip().lower()
        if not valid_thread_transition(thread.status, next_status):
            return JsonResponse({"error": f"invalid thread status transition: {thread.status} -> {next_status}"}, status=409)
        thread.status = next_status
    if "priority" in payload:
        next_priority = str(payload.get("priority") or "").strip().lower()
        if next_priority not in THREAD_PRIORITY_ORDER:
            return JsonResponse({"error": "invalid priority"}, status=400)
        if thread.priority != next_priority:
            record_thread_event(thread=thread, event_type="thread_priority_changed", payload={"previous_priority": thread.priority, "priority": next_priority})
        thread.priority = next_priority
    if "title" in payload:
        thread.title = str(payload.get("title") or "").strip()[:240]
    if "description" in payload:
        thread.description = str(payload.get("description") or "").strip()
    if "domain" in payload:
        thread.domain = str(payload.get("domain") or "").strip()
    if "work_in_progress_limit" in payload:
        thread.work_in_progress_limit = max(1, int(payload.get("work_in_progress_limit") or 1))
    if "execution_policy" in payload and isinstance(payload.get("execution_policy"), dict):
        thread.execution_policy = payload.get("execution_policy") or {}
    if "source_conversation_id" in payload:
        thread.source_conversation_id = str(payload.get("source_conversation_id") or "").strip()
    thread.save()
    if previous_status != thread.status:
        record_thread_event(thread=thread, event_type=f"thread_{thread.status}", payload={"previous_status": previous_status, "status": thread.status})
    return JsonResponse(_coordination_thread_detail(thread))


